class Login(APIView):
    def get(self, request):
        user_id = request.headers.get("X-User-Id")  # get from headers

        if user_id:
            try:
                user = User.objects.get(id=user_id)
                data = {
                    "user_id": str(user.id),  # Keep key as "user_id" but value from user.id
                    "username": user.username,
                    "email": user.email,
                    "is_admin": user.is_admin,
                    "is_customer": user.is_customer,
                    "is_rider": user.is_rider,
                    "is_moderator": user.is_moderator,
                    "registration_stage": user.registration_stage
                }
                return Response(data)
            except User.DoesNotExist:
                return Response({"error": "User not found"}, status=404)
    
    def post(self, request):
        """
        Logs in a user using email/username and password
        """
        username = request.data.get('username')
        password = request.data.get('password')
        
        if not username or not password:
            return Response(
                {"error": "Username and password are required"}, 
                status=status.HTTP_400_BAD_REQUEST
            )
        
        try:
            # Find user by username
            user = User.objects.get(username=username)
            
            # Check password using Django's check_password
            if not check_password(password, user.password):
                return Response(
                    {"error": "Invalid credentials"}, 
                    status=status.HTTP_401_UNAUTHORIZED
                )
                
        except User.DoesNotExist:
            return Response(
                {"error": "Invalid credentials"}, 
                status=status.HTTP_401_UNAUTHORIZED
            )
        
        # Login successful
        return Response({
            "message": "Login successful",
            "user_id": str(user.id),  # Keep key as "user_id" but value from user.id
            "username": user.username,
            "email": user.email,
            "is_admin": user.is_admin,
            "is_customer": user.is_customer,
            "is_rider": user.is_rider,
            "is_moderator": user.is_moderator,
            "registration_stage": user.registration_stage
        })
    
class Register(APIView):
    def get(self, request):
        user_id = request.headers.get("X-User-Id")

        if user_id:
            try:
                user = User.objects.get(id=user_id)
                data = {
                    "user_id": user.id,
                    "username": user.username,
                    "email": user.email,
                    "is_rider": getattr(user, "is_rider", False),
                    "registration_stage": getattr(user, "registration_stage", 1)
                }
                return Response(data)
            except User.DoesNotExist:
                return Response({"error": "User not found"}, status=404)

        users = [
            {
                "user_id": u.id,
                "username": u.username,
                "email": u.email,
            }
            for u in User.objects.all()
        ]
        return Response(users)

    def post(self, request):
        # Check if this is a rider completing registration
        rider_id = request.data.get('rider_id')
        
        if rider_id:
            # Rider completing existing rider application
            try:
                # Try to get rider by the user_id (since rider.rider is OneToOne to User)
                # First, check if a user exists with this ID
                try:
                    user = User.objects.get(id=rider_id)
                except User.DoesNotExist:
                    return Response({"error": f"User with ID {rider_id} not found"}, status=404)
                
                # Now find the rider associated with this user
                try:
                    rider = Rider.objects.get(rider=user)
                except Rider.DoesNotExist:
                    return Response({"error": "Rider application not found for this user"}, status=404)
                
                username = request.data.get('username')
                password = request.data.get('password')
                
                if not username or not password:
                    return Response({"error": "Username and password are required"}, status=400)
                
                # Check if username is taken by another user
                if User.objects.filter(username=username).exclude(id=user.id).exists():
                    return Response({"username": "Username already taken"}, status=400)
                
                # Update the existing user (NOT create a new one)
                user.username = username
                # Manually hash the password
                user.password = make_password(password)
                user.registration_stage = 2
                user.save()
                
                return Response({
                    "user_id": user.id,
                    "username": user.username,
                    "email": user.email,
                    "registration_stage": user.registration_stage,
                    "is_rider": True,
                    "message": "Rider account created successfully"
                }, status=200)
                
            except Exception as e:
                return Response({"error": str(e)}, status=500)
        
        else:
            # Regular customer registration (creates NEW user)
            serializer = UserSerializer(data=request.data)
            if serializer.is_valid(raise_exception=True):
                user = serializer.save()
                
                # Create customer for new user
                customer_data = {"customer": user.id}
                customer_serializer = CustomerSerializer(data=customer_data)
                if customer_serializer.is_valid(raise_exception=True):
                    customer = customer_serializer.save()
                    
                    # Check if wallet already exists before creating
                    wallet, created = UserWallet.objects.get_or_create(
                        user=user,
                        defaults={
                            'available_balance': Decimal('0.00'),
                            'pending_balance': Decimal('0.00')
                        }
                    )
                    
                    return Response({
                        "user_id": user.id,
                        "username": user.username,
                        "email": user.email,
                        "registration_stage": user.registration_stage,
                        "wallet_id": str(wallet.wallet_id),
                        "wallet_created": created,
                        "is_rider": False,
                        "message": "User registered successfully"
                    })
                
    def put(self, request):
        user_id = request.headers.get("X-User-Id")
        
        if not user_id:
            return Response({"error": "User ID is required"}, status=400)
        
        try:
            user = User.objects.get(id=user_id)
        except User.DoesNotExist:
            return Response({"error": "User not found"}, status=404)
            
        serializer = UserSerializer(user, data=request.data, partial=True)
        if serializer.is_valid(raise_exception=True):
            serializer.save()
            return Response(serializer.data)
        
class Profiling(APIView):
    
    def _get_coordinates_from_address(self, street, barangay, city, province, country="Philippines"):
        """
        Get latitude and longitude from address using Google Maps Geocoding API
        Returns (latitude, longitude) tuple
        """
        # Build full address string
        address_parts = []
        if street:
            address_parts.append(street)
        if barangay:
            address_parts.append(barangay)
        if city:
            address_parts.append(city)
        if province:
            address_parts.append(province)
        if country:
            address_parts.append(country)
        
        full_address = ", ".join(filter(None, address_parts))
        
        if not full_address:
            print(f"[GEOCODE] No address to geocode")
            return None, None
        
        GOOGLE_MAPS_API_KEY = getattr(settings, 'GOOGLE_MAPS_API_KEY', None)
        
        if not GOOGLE_MAPS_API_KEY:
            print(f"[GEOCODE] Google Maps API key not configured")
            return None, None
        
        try:
            url = "https://maps.googleapis.com/maps/api/geocode/json"
            params = {
                'address': full_address,
                'key': GOOGLE_MAPS_API_KEY
            }
            
            print(f"[GEOCODE] Geocoding address: {full_address}")
            
            response = requests.get(url, params=params, timeout=10)
            data = response.json()
            
            if data.get('status') == 'OK':
                location = data['results'][0]['geometry']['location']
                latitude = location['lat']
                longitude = location['lng']
                print(f"[GEOCODE] ✅ Got coordinates: ({latitude}, {longitude})")
                return Decimal(str(latitude)), Decimal(str(longitude))
            else:
                print(f"[GEOCODE] ❌ Geocoding failed: {data.get('status')}")
                return None, None
                
        except requests.exceptions.Timeout:
            print(f"[GEOCODE] ❌ Google Maps API timeout")
            return None, None
        except Exception as e:
            print(f"[GEOCODE] ❌ Error: {str(e)}")
            return None, None
    
    def get(self, request):
        user_id = request.headers.get('X-User-Id')
        
        if not user_id:
            return Response({"error": "User ID not provided"}, status=400)
        
        try:
            user = User.objects.get(id=user_id)
        except User.DoesNotExist:
            return Response({"error": "User not found"}, status=404)
        
        data = {
            "user_id": user.id,
            "registration_stage": user.registration_stage,
            "username": user.username,
            "first_name": user.first_name,
            "last_name": user.last_name,
            "middle_name": user.middle_name,
            "email": user.email,
            "contact_number": user.contact_number,
            "date_of_birth": user.date_of_birth,
            "age": user.age,
            "sex": user.sex,
            "street": user.street,
            "barangay": user.barangay,
            "city": user.city,
            "province": user.province,
            "zip_code": user.zip_code,
            "country": user.country,
            "latitude": float(user.latitude) if user.latitude else None,
            "longitude": float(user.longitude) if user.longitude else None,
        }
        return Response(data)
    
    def post(self, request):
        # Remove fields that shouldn't be in UserSerializer
        data = request.data.copy()
        data.pop('user_id', None)
        
        serializer = UserSerializer(data=data)
        if serializer.is_valid(raise_exception=True):
            saved_user = serializer.save()
            
            response_data = serializer.data.copy()
            response_data['user_id'] = saved_user.id
            
            return Response(response_data, status=status.HTTP_201_CREATED)
        
    def put(self, request):
        user_id = request.headers.get("X-User-Id")
        
        if not user_id:
            return Response({"error": "User ID is required"}, status=400)
        
        try:
            user = User.objects.get(id=user_id)
        except User.DoesNotExist:
            return Response({"error": "User not found"}, status=404)
        
        # Remove fields that shouldn't be in UserSerializer
        data = request.data.copy()
        data.pop('user_id', None)
        data.pop('registration_stage', None)
        
        serializer = UserSerializer(user, data=data, partial=True)
        
        if not serializer.is_valid():
            print(f"[PROFILE] Validation errors: {serializer.errors}")
            return Response(serializer.errors, status=status.HTTP_400_BAD_REQUEST)
        
        # Save the user and get the updated instance
        updated_user = serializer.save()
        
        # Check if any address field is being updated
        address_fields = ['street', 'barangay', 'city', 'province', 'zip_code', 'country']
        has_address_data = any(field in request.data for field in address_fields)
        
        latitude = None
        longitude = None
        
        # Get coordinates from the address if address fields are present
        if has_address_data:
            # Get coordinates from Google Maps API using the updated address
            latitude, longitude = self._get_coordinates_from_address(
                street=updated_user.street,
                barangay=updated_user.barangay,
                city=updated_user.city,
                province=updated_user.province,
                country=updated_user.country or "Philippines"
            )
            
            # Update user with coordinates if available
            if latitude and longitude:
                updated_user.latitude = latitude
                updated_user.longitude = longitude
                updated_user.save(update_fields=['latitude', 'longitude'])
                print(f"[PROFILE] Updated user {updated_user.id} with coordinates ({latitude}, {longitude})")
        
        # Create or update the default shipping address from user profile
        try:
            # Check if user already has a default shipping address
            existing_default = ShippingAddress.objects.filter(
                user=updated_user,
                is_default=True
            ).first()
            
            # Get recipient name from user profile
            recipient_name = f"{updated_user.first_name} {updated_user.last_name}".strip()
            if not recipient_name:
                recipient_name = updated_user.username or "Customer"
            
            if not existing_default:
                # Create default shipping address from user profile
                shipping_address = ShippingAddress(
                    user=updated_user,
                    recipient_name=recipient_name,
                    recipient_phone=updated_user.contact_number or "",
                    street=updated_user.street or "",
                    barangay=updated_user.barangay or "",
                    city=updated_user.city or "",
                    province=updated_user.province or "",
                    state=updated_user.state or "",
                    zip_code=updated_user.zip_code or "",
                    country=updated_user.country or "Philippines",
                    address_type="home",
                    is_default=True,
                    is_active=True,
                    latitude=latitude,
                    longitude=longitude
                )
                shipping_address.save()
                print(f"[PROFILE] Created default shipping address for user {updated_user.id}")
            else:
                # Update existing default address with new profile data
                existing_default.recipient_name = recipient_name
                existing_default.recipient_phone = updated_user.contact_number or ""
                existing_default.street = updated_user.street or ""
                existing_default.barangay = updated_user.barangay or ""
                existing_default.city = updated_user.city or ""
                existing_default.province = updated_user.province or ""
                existing_default.state = updated_user.state or ""
                existing_default.zip_code = updated_user.zip_code or ""
                existing_default.country = updated_user.country or "Philippines"
                
                # Update coordinates if available
                if latitude and longitude:
                    existing_default.latitude = latitude
                    existing_default.longitude = longitude
                
                existing_default.save()
                print(f"[PROFILE] Updated default shipping address for user {updated_user.id}")
                
        except Exception as e:
            # Log error but don't fail the profiling update
            print(f"[PROFILE] Error creating/updating shipping address: {str(e)}")
        
        # Transform response to maintain frontend compatibility
        response_data = serializer.data.copy()
        response_data['user_id'] = updated_user.id
        
        # Add coordinates to response if available
        if latitude and longitude:
            response_data['latitude'] = float(latitude)
            response_data['longitude'] = float(longitude)
        
        return Response(response_data, status=status.HTTP_200_OK)
    
class VerifyNumber(viewsets.ViewSet):
    @action(detail=False, methods=['get'])
    def user(self, request):
        user_id = request.headers.get('X-User-Id')

        if not user_id:
            return Response({"error": "User ID not provided"}, status=400)

        try:
            user = User.objects.get(id=user_id)
        except User.DoesNotExist:
            return Response({"error": "User not found"}, status=404)

        return Response({
            "user_id": user.id,
            "registration_stage": user.registration_stage,
        })

    def send_otp(self, contact_number):
        """
        Sends OTP using Twilio Verify API
        """
        try:
            # Validate phone number format
            # Remove any non-digit characters
            clean_number = ''.join(filter(str.isdigit, contact_number))
            
            # Ensure it starts with 9 and is 10 digits
            if len(clean_number) != 10 or not clean_number.startswith('9'):
                print(f"Invalid phone number format: {clean_number}")
                return None
            
            # Format as E.164: +63 followed by the 10-digit number
            formatted_number = f'+63{clean_number}'
            
            print(f"Sending OTP to: {formatted_number}")
            
            client = Client(settings.TWILIO_ACCOUNT_SID, settings.TWILIO_AUTH_TOKEN)
            
            # Try with 'sms' channel first
            verification = client.verify.v2.services(
                settings.TWILIO_SERVICE_ID
            ).verifications.create(
                to=formatted_number,
                channel='sms'
            )
            
            print(f"Twilio verification status: {verification.status}")
            return verification.status

        except TwilioRestException as e:
            print(f"Twilio error: {e}")
            print(f"Error code: {e.code}")
            print(f"Error message: {e.msg}")
            return None
        except Exception as e:
            print(f"Unexpected error in send_otp: {e}")
            return None

    @action(detail=False, methods=['post'], url_path='verify_number')
    def verify_number(self, request):
        """
        Single action to handle both contact number submission and OTP verification
        """
        user_id = request.headers.get('X-User-Id')
        action_type = request.data.get('action_type')
        contact_number = request.data.get('contact_number')
        otp_code = request.data.get('otp_code')

        if not user_id:
            return Response({"error": "User ID header is required!"}, status=400)

        try:
            user = User.objects.get(id=user_id)
        except User.DoesNotExist:
            return Response({"error": "User not found!"}, status=404)

        if action_type == 'send_otp':
            # Handle contact number submission and OTP sending
            if not contact_number:
                return Response({"error": "Contact number is required!"}, status=400)

            # Clean and validate phone number
            clean_number = ''.join(filter(str.isdigit, contact_number))
            
            # Remove leading '63' if present
            if clean_number.startswith('63'):
                clean_number = clean_number[2:]
            
            # Validate Philippine number format
            if len(clean_number) != 10 or not clean_number.startswith('9'):
                return Response({
                    "error": "Invalid Philippine number. Must be 10 digits starting with 9 (e.g., 9XXXXXXXXX)"
                }, status=400)
            
            # Save user's contact number
            user.contact_number = clean_number
            user.save()

            # Send OTP using Twilio Verify
            otp_status = self.send_otp(clean_number)
            
            if not otp_status:
                return Response({
                    "error": "Failed to send OTP. Please check your Twilio configuration or try again later."
                }, status=500)

            OTP.objects.update_or_create(
                user=user,
                defaults={
                    'otp': 'pending',
                    'sent_at': timezone.now(),
                    'expired_at': timezone.now() + timedelta(minutes=5)
                }
            )

            return Response({
                "message": f"OTP sent successfully to +63{clean_number}",
                "user_id": str(user.id),
                "contact_number": clean_number
            })

        elif action_type == 'verify_otp':
            # Handle OTP verification
            if not contact_number or not otp_code:
                return Response({"error": "Contact number and OTP code are required!"}, status=400)

            # Clean phone number for comparison
            clean_number = ''.join(filter(str.isdigit, contact_number))
            if clean_number.startswith('63'):
                clean_number = clean_number[2:]
            
            # Verify that the contact number matches the user's stored number
            if user.contact_number != clean_number:
                return Response({"error": "Contact number doesn't match user record!"}, status=400)

            try:
                formatted_number = f'+63{clean_number}'
                
                client = Client(settings.TWILIO_ACCOUNT_SID, settings.TWILIO_AUTH_TOKEN)
                verification_check = client.verify.v2.services(
                    settings.TWILIO_SERVICE_ID
                ).verification_checks.create(
                    to=formatted_number,
                    code=otp_code
                )

                print(f"Verification check status: {verification_check.status}")

                if verification_check.status == 'approved':
                    # FIX: Update registration stage to 4 (not 3)
                    user.registration_stage = 4
                    user.save()
                    
                    OTP.objects.filter(user=user).update(
                        otp=otp_code, 
                        expired_at=timezone.now()
                    )
                    
                    return Response({
                        "message": "Phone number verified successfully!",
                        "registration_stage": user.registration_stage
                    })
                else:
                    return Response({"error": "Invalid or expired OTP!"}, status=400)

            except TwilioRestException as e:
                print(f"Twilio error: {e}")
                return Response({"error": f"Verification failed: {e.msg}"}, status=500)
            except Exception as e:
                print(f"Unexpected error: {e}")
                return Response({"error": "Verification failed. Please try again later."}, status=500)

        else:
            return Response({"error": "Invalid action type"}, status=400)

            
class RiderRegistration(viewsets.ViewSet):
    @action(detail=False, methods=['post'], url_path='register')
    def register(self, request):
        """
        First step: Create rider application record with vehicle details.
        Creates a placeholder user with empty password (will be updated later)
        """
        try:
            # Create a placeholder user first (will be updated later with username/password)
            user_data = {
                'is_customer': False,
                'is_rider': True,
                'registration_stage': 1,
                'username': f"temp_rider_{uuid.uuid4().hex[:8]}",
                'password': ''  # Empty password, will be set later by register endpoint
            }
            
            user_serializer = UserSerializer(data=user_data)
            if not user_serializer.is_valid():
                return Response(user_serializer.errors, status=400)
                
            user = user_serializer.save()
            
            # Create rider record with comprehensive validation
            vehicle_type = request.data.get('vehicle_type', '').strip()
            plate_number = request.data.get('plate_number', '').strip()
            vehicle_brand = request.data.get('vehicle_brand', '').strip()
            vehicle_model = request.data.get('vehicle_model', '').strip()
            license_number = request.data.get('license_number', '').strip()
            
            # Get files from request
            vehicle_image = request.FILES.get('vehicle_image')
            license_image = request.FILES.get('license_image')
            
            errors = {}
            
            # Vehicle Type validation
            if not vehicle_type:
                errors['vehicle_type'] = "Vehicle type is required"
            elif vehicle_type not in ["car", "motorcycle", "bicycle", "scooter", "van", "truck"]:
                errors['vehicle_type'] = "Please select a valid vehicle type"
            
            # Plate Number validation
            if not plate_number:
                errors['plate_number'] = "Plate number is required"
            elif len(plate_number) > 20:
                errors['plate_number'] = "Plate number should be at most 20 characters"
            
            # Vehicle Brand validation
            if not vehicle_brand:
                errors['vehicle_brand'] = "Vehicle brand is required"
            elif len(vehicle_brand) > 50:
                errors['vehicle_brand'] = "Vehicle brand should be at most 50 characters"
            
            # Vehicle Model validation
            if not vehicle_model:
                errors['vehicle_model'] = "Vehicle model is required"
            elif len(vehicle_model) > 50:
                errors['vehicle_model'] = "Vehicle model should be at most 50 characters"
            
            # License Number validation
            if not license_number:
                errors['license_number'] = "License number is required"
            elif len(license_number) > 20:
                errors['license_number'] = "License number should be at most 20 characters"
            
            # Vehicle Image validation
            if not vehicle_image:
                errors['vehicle_image'] = "Vehicle image is required"
            elif vehicle_image.size > 5 * 1024 * 1024:
                errors['vehicle_image'] = "Vehicle image should be less than 5MB"
            elif not vehicle_image.content_type.startswith('image/'):
                errors['vehicle_image'] = "Please upload a valid image file"
            
            # License Image validation
            if not license_image:
                errors['license_image'] = "License image is required"
            elif license_image.size > 5 * 1024 * 1024:
                errors['license_image'] = "License image should be less than 5MB"
            elif not license_image.content_type.startswith('image/'):
                errors['license_image'] = "License image should be a valid image file"
            
            # Return validation errors if any
            if errors:
                user.delete()
                return Response({"errors": errors}, status=400)
            
            # Create rider instance
            rider = Rider(
                rider=user,
                vehicle_type=vehicle_type,
                plate_number=plate_number,
                vehicle_brand=vehicle_brand,
                vehicle_model=vehicle_model,
                license_number=license_number,
                verified=False
            )
            
            # Handle file uploads
            if vehicle_image:
                vehicle_image.seek(0)
                rider.vehicle_image.save(vehicle_image.name, vehicle_image, save=False)
            
            if license_image:
                license_image.seek(0)
                rider.license_image.save(license_image.name, license_image, save=False)
            
            rider.save()
            
            return Response({
                "message": "Rider application submitted successfully",
                "user_id": str(user.id),
                "rider_id": str(rider.rider_id),
                "registration_stage": user.registration_stage,
                "status": "pending_verification"
            }, status=status.HTTP_201_CREATED)
                
        except Exception as e:
            logger.error(f"Rider registration failed: {str(e)}", exc_info=True)
            if 'user' in locals():
                user.delete()
            return Response({"error": f"Registration failed: {str(e)}"}, status=500)
        
class AdminDashboard(viewsets.ViewSet):
    @action(detail=False, methods=['get'])
    def get_comprehensive_dashboard(self, request):
        try:
            start_date_str = request.query_params.get('start_date')
            end_date_str = request.query_params.get('end_date')
            date_range_type = request.query_params.get('range_type', 'weekly')
            valid_range_types = ['daily', 'weekly', 'monthly', 'yearly', 'custom']
            if date_range_type not in valid_range_types:
                date_range_type = 'weekly'
            
            start_date = None
            end_date = None
            
            if start_date_str and end_date_str:
                try:
                    start_date = datetime.strptime(start_date_str, '%Y-%m-%d').date()
                    end_date = datetime.strptime(end_date_str, '%Y-%m-%d').date()
                except ValueError as e:
                    return Response({
                        'success': False,
                        'error': f'Invalid date format. Use YYYY-MM-DD. Error: {str(e)}'
                    }, status=status.HTTP_400_BAD_REQUEST)
            else:
                end_date = timezone.now().date()
                start_date = end_date - timedelta(days=6)

            if start_date > end_date:
                start_date, end_date = end_date, start_date

            max_days = 365 * 2
            date_range_days = (end_date - start_date).days

            if date_range_days > max_days:
                return Response({
                    'success': False,
                    'error': f'Date range exceeds maximum allowed ({max_days} days)'
                }, status=status.HTTP_400_BAD_REQUEST)

            overview_data = self._get_overview_data(start_date, end_date)
            operational_data = self._get_operational_data(start_date, end_date)
            sales_data = self._get_sales_analytics_data(start_date, end_date, date_range_type)
            user_data = self._get_user_analytics_data(start_date, end_date, date_range_type)
            product_data = self._get_product_analytics_data(start_date, end_date)
            shop_data = self._get_shop_analytics_data(start_date, end_date)

            comprehensive_data = {
                'success': True,
                'date_range': {
                    'start_date': start_date.isoformat(),
                    'end_date': end_date.isoformat(),
                    'range_type': date_range_type,
                    'total_days': date_range_days,
                },
                'overview': overview_data,
                'operational': operational_data,
                'sales_analytics': sales_data,
                'user_analytics': user_data,
                'product_analytics': product_data,
                'shop_analytics': shop_data,
            }
            return Response(comprehensive_data, status=status.HTTP_200_OK)
        except Exception as e:
            print(f"Error in get_comprehensive_dashboard: {str(e)}")
            import traceback
            traceback.print_exc()
            return Response({
                'success': False,
                'error': str(e),
                'message': 'An error occurred while fetching dashboard data'
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
    
    def _get_overview_data(self, start_date, end_date):
        try:
            from decimal import Decimal
            
            date_range_days = (end_date - start_date).days + 1
            previous_start_date = start_date - timedelta(days=date_range_days)
            previous_end_date = start_date - timedelta(days=1)

            # Current period metrics
            current_orders = Order.objects.filter(
                created_at__date__gte=start_date,
                created_at__date__lte=end_date
            ).count()

            # Calculate revenue breakdown including pending orders
            current_completed_orders = Order.objects.filter(
                created_at__date__gte=start_date,
                created_at__date__lte=end_date,
                status='completed'
            )
            current_completed_revenue = current_completed_orders.aggregate(
                total_revenue=Sum('total_amount')
            )['total_revenue'] or Decimal('0')

            # Calculate incoming balance from ongoing transactions (pending/processing orders)
            current_pending_orders = Order.objects.filter(
                created_at__date__gte=start_date,
                created_at__date__lte=end_date,
                status__in=['pending', 'processing', 'shipped']
            )
            current_pending_revenue = current_pending_orders.aggregate(
                total_revenue=Sum('total_amount')
            )['total_revenue'] or Decimal('0')

            # Total revenue including pending
            current_revenue = current_completed_revenue + current_pending_revenue

            # Calculate shipping fees from completed orders
            current_shipping_fees = Delivery.objects.filter(
                order__in=current_completed_orders,
                status='delivered'
            ).aggregate(
                total_shipping=Sum('delivery_fee')
            )['total_shipping'] or Decimal('0')

            # Calculate platform fees (5% of order total for completed orders)
            current_platform_fees = current_completed_revenue * Decimal('0.05')

            # Calculate VAT collected from successful/completed orders
            # VAT is calculated as price * (vat_percentage / 100) for each variant in completed orders
            vat_collected = Decimal('0')
            
            # Get all checkouts from completed orders
            completed_checkouts = Checkout.objects.filter(
                order__in=current_completed_orders,
                order__status='completed'
            ).select_related('cart_item__variant', 'order')
            
            for checkout in completed_checkouts:
                if checkout.cart_item and checkout.cart_item.variant:
                    variant = checkout.cart_item.variant
                    # Get variant price and VAT percentage
                    price = variant.price or Decimal('0')
                    vat_percentage = variant.value_added_tax or Decimal('12.00')
                    # Calculate VAT amount: price * (vat_percentage / 100)
                    vat_amount = price * (vat_percentage / Decimal('100'))
                    vat_collected += vat_amount * checkout.quantity
                elif checkout.direct_variant_id:
                    # Handle direct checkout (product purchased directly without cart)
                    try:
                        variant = Variants.objects.get(id=checkout.direct_variant_id)
                        price = variant.price or Decimal('0')
                        vat_percentage = variant.value_added_tax or Decimal('12.00')
                        vat_amount = price * (vat_percentage / Decimal('100'))
                        vat_collected += vat_amount * checkout.quantity
                    except Variants.DoesNotExist:
                        pass

            # Previous period metrics
            previous_orders = Order.objects.filter(
                created_at__date__gte=previous_start_date,
                created_at__date__lte=previous_end_date
            ).count()

            previous_completed_orders = Order.objects.filter(
                created_at__date__gte=previous_start_date,
                created_at__date__lte=previous_end_date,
                status='completed'
            )
            previous_completed_revenue = previous_completed_orders.aggregate(
                total_revenue=Sum('total_amount')
            )['total_revenue'] or Decimal('0')

            previous_pending_orders = Order.objects.filter(
                created_at__date__gte=previous_start_date,
                created_at__date__lte=previous_end_date,
                status__in=['pending', 'processing', 'shipped']
            )
            previous_pending_revenue = previous_pending_orders.aggregate(
                total_revenue=Sum('total_amount')
            )['total_revenue'] or Decimal('0')

            previous_revenue = previous_completed_revenue + previous_pending_revenue

            # Previous period VAT collected
            previous_vat_collected = Decimal('0')
            previous_completed_checkouts = Checkout.objects.filter(
                order__in=previous_completed_orders,
                order__status='completed'
            ).select_related('cart_item__variant', 'order')
            
            for checkout in previous_completed_checkouts:
                if checkout.cart_item and checkout.cart_item.variant:
                    variant = checkout.cart_item.variant
                    price = variant.price or Decimal('0')
                    vat_percentage = variant.value_added_tax or Decimal('12.00')
                    vat_amount = price * (vat_percentage / Decimal('100'))
                    previous_vat_collected += vat_amount * checkout.quantity
                elif checkout.direct_variant_id:
                    try:
                        variant = Variants.objects.get(id=checkout.direct_variant_id)
                        price = variant.price or Decimal('0')
                        vat_percentage = variant.value_added_tax or Decimal('12.00')
                        vat_amount = price * (vat_percentage / Decimal('100'))
                        previous_vat_collected += vat_amount * checkout.quantity
                    except Variants.DoesNotExist:
                        pass

            # Growth calculations
            order_growth = 0
            revenue_growth = 0
            vat_growth = 0

            if previous_orders > 0:
                order_growth = ((current_orders - previous_orders) / previous_orders) * 100

            if float(previous_revenue) > 0:
                revenue_growth = ((float(current_revenue) - float(previous_revenue)) / float(previous_revenue)) * 100

            if float(previous_vat_collected) > 0:
                vat_growth = ((float(vat_collected) - float(previous_vat_collected)) / float(previous_vat_collected)) * 100

            # Active customers
            active_customers = User.objects.filter(
                is_customer=True,
                is_suspended=False,
                created_at__date__lte=end_date
            ).count()

            active_shops = Shop.objects.filter(
                status='Active',
                is_suspended=False,
                created_at__date__lte=end_date
            ).count()

            # Lifetime totals including all orders
            total_completed_revenue = Order.objects.filter(
                status='completed',
                created_at__date__lte=end_date
            ).aggregate(
                total_revenue=Sum('total_amount')
            )['total_revenue'] or Decimal('0')

            total_pending_revenue = Order.objects.filter(
                status__in=['pending', 'processing', 'shipped'],
                created_at__date__lte=end_date
            ).aggregate(
                total_revenue=Sum('total_amount')
            )['total_revenue'] or Decimal('0')

            total_revenue = total_completed_revenue + total_pending_revenue
            total_orders = Order.objects.filter(
                created_at__date__lte=end_date
            ).count()

            # Lifetime VAT collected
            lifetime_vat_collected = Decimal('0')
            all_completed_checkouts = Checkout.objects.filter(
                order__status='completed'
            ).select_related('cart_item__variant', 'order')
            
            for checkout in all_completed_checkouts:
                if checkout.cart_item and checkout.cart_item.variant:
                    variant = checkout.cart_item.variant
                    price = variant.price or Decimal('0')
                    vat_percentage = variant.value_added_tax or Decimal('12.00')
                    vat_amount = price * (vat_percentage / Decimal('100'))
                    lifetime_vat_collected += vat_amount * checkout.quantity
                elif checkout.direct_variant_id:
                    try:
                        variant = Variants.objects.get(id=checkout.direct_variant_id)
                        price = variant.price or Decimal('0')
                        vat_percentage = variant.value_added_tax or Decimal('12.00')
                        vat_amount = price * (vat_percentage / Decimal('100'))
                        lifetime_vat_collected += vat_amount * checkout.quantity
                    except Variants.DoesNotExist:
                        pass

            return {
                'total_revenue': float(total_revenue),
                'total_completed_revenue': float(total_completed_revenue),
                'total_pending_revenue': float(total_pending_revenue),
                'total_orders': total_orders,
                'total_vat_collected': float(lifetime_vat_collected),
                'active_customers': active_customers,
                'active_shops': active_shops,
                'current_period_orders': current_orders,
                'current_period_completed_revenue': float(current_completed_revenue),
                'current_period_pending_revenue': float(current_pending_revenue),
                'current_period_revenue': float(current_revenue),
                'current_period_shipping_fees': float(current_shipping_fees),
                'current_period_platform_fees': float(current_platform_fees),
                'current_period_vat_collected': float(vat_collected),
                'previous_period_orders': previous_orders,
                'previous_period_revenue': float(previous_revenue),
                'previous_period_vat_collected': float(previous_vat_collected),
                'order_growth': round(order_growth, 1),
                'revenue_growth': round(revenue_growth, 1),
                'vat_growth': round(vat_growth, 1),
                'date_range_days': date_range_days,
                'breakdown_note': 'Platform fees calculated as 5% of completed order total only. Pending revenue represents incoming balance from ongoing transactions. VAT is calculated as 12% of product prices (or variant-specific VAT rate) from completed orders.',
            }
        except Exception as e:
            print(f"Error in _get_overview_data: {str(e)}")
            import traceback
            traceback.print_exc()
            raise

    def _get_sales_analytics_data(self, start_date, end_date, range_type='weekly'):
        try:
            from decimal import Decimal
            
            sales_data = []
            date_range_days = (end_date - start_date).days + 1

            if range_type == 'daily' or date_range_days <= 7:
                current_date = start_date
                while current_date <= end_date:
                    day_orders = Order.objects.filter(
                        created_at__date=current_date
                    )
                    
                    day_completed = day_orders.filter(status='completed')
                    day_completed_revenue = day_completed.aggregate(
                        revenue=Sum('total_amount')
                    )['revenue'] or Decimal('0')
                    
                    day_pending = day_orders.filter(status__in=['pending', 'processing', 'shipped'])
                    day_pending_revenue = day_pending.aggregate(
                        revenue=Sum('total_amount')
                    )['revenue'] or Decimal('0')
                    
                    day_revenue = day_completed_revenue + day_pending_revenue
                    
                    day_shipping = Delivery.objects.filter(
                        order__in=day_completed,
                        status='delivered'
                    ).aggregate(shipping=Sum('delivery_fee'))['shipping'] or Decimal('0')
                    
                    day_platform_fees = day_completed_revenue * Decimal('0.05')
                    
                    # Calculate VAT collected for the day
                    day_vat_collected = Decimal('0')
                    day_checkouts = Checkout.objects.filter(
                        order__in=day_completed,
                        order__status='completed'
                    ).select_related('cart_item__variant')
                    
                    for checkout in day_checkouts:
                        if checkout.cart_item and checkout.cart_item.variant:
                            variant = checkout.cart_item.variant
                            price = variant.price or Decimal('0')
                            vat_percentage = variant.value_added_tax or Decimal('12.00')
                            vat_amount = price * (vat_percentage / Decimal('100'))
                            day_vat_collected += vat_amount * checkout.quantity
                        elif checkout.direct_variant_id:
                            try:
                                variant = Variants.objects.get(id=checkout.direct_variant_id)
                                price = variant.price or Decimal('0')
                                vat_percentage = variant.value_added_tax or Decimal('12.00')
                                vat_amount = price * (vat_percentage / Decimal('100'))
                                day_vat_collected += vat_amount * checkout.quantity
                            except Variants.DoesNotExist:
                                pass

                    sales_data.append({
                        'date': current_date.isoformat(),
                        'name': current_date.strftime('%a, %b %d'),
                        'revenue': float(day_revenue),
                        'completed_revenue': float(day_completed_revenue),
                        'pending_revenue': float(day_pending_revenue),
                        'orders': day_orders.count(),
                        'completed_orders': day_completed.count(),
                        'pending_orders': day_pending.count(),
                        'shipping_fees': float(day_shipping),
                        'platform_fees': float(day_platform_fees),
                        'vat_collected': float(day_vat_collected),
                    })

                    current_date += timedelta(days=1)
                grouping = 'daily'

            elif range_type == 'monthly' or date_range_days > 60:
                monthly_sales = Order.objects.filter(
                    created_at__date__gte=start_date,
                    created_at__date__lte=end_date
                ).annotate(
                    month=TruncMonth('created_at')
                ).values('month').annotate(
                    total_revenue=Sum('total_amount'),
                    orders=Count('order')
                ).order_by('month')

                for month_data in monthly_sales:
                    if month_data['month']:
                        month_start = month_data['month'].date()
                        month_end = (month_start + timedelta(days=32)).replace(day=1) - timedelta(days=1)
                        
                        month_completed = Order.objects.filter(
                            created_at__date__gte=month_start,
                            created_at__date__lte=month_end,
                            status='completed'
                        )
                        month_completed_revenue = month_completed.aggregate(
                            revenue=Sum('total_amount')
                        )['revenue'] or Decimal('0')
                        
                        month_pending = Order.objects.filter(
                            created_at__date__gte=month_start,
                            created_at__date__lte=month_end,
                            status__in=['pending', 'processing', 'shipped']
                        )
                        month_pending_revenue = month_pending.aggregate(
                            revenue=Sum('total_amount')
                        )['revenue'] or Decimal('0')
                        
                        month_revenue = month_completed_revenue + month_pending_revenue
                        
                        month_shipping = Delivery.objects.filter(
                            order__in=month_completed,
                            status='delivered'
                        ).aggregate(shipping=Sum('delivery_fee'))['shipping'] or Decimal('0')
                        
                        month_platform_fees = month_completed_revenue * Decimal('0.05')
                        
                        # Calculate VAT collected for the month
                        month_vat_collected = Decimal('0')
                        month_checkouts = Checkout.objects.filter(
                            order__in=month_completed,
                            order__status='completed'
                        ).select_related('cart_item__variant')
                        
                        for checkout in month_checkouts:
                            if checkout.cart_item and checkout.cart_item.variant:
                                variant = checkout.cart_item.variant
                                price = variant.price or Decimal('0')
                                vat_percentage = variant.value_added_tax or Decimal('12.00')
                                vat_amount = price * (vat_percentage / Decimal('100'))
                                month_vat_collected += vat_amount * checkout.quantity
                            elif checkout.direct_variant_id:
                                try:
                                    variant = Variants.objects.get(id=checkout.direct_variant_id)
                                    price = variant.price or Decimal('0')
                                    vat_percentage = variant.value_added_tax or Decimal('12.00')
                                    vat_amount = price * (vat_percentage / Decimal('100'))
                                    month_vat_collected += vat_amount * checkout.quantity
                                except Variants.DoesNotExist:
                                    pass

                        sales_data.append({
                            'date': month_data['month'].strftime('%Y-%m-%d'),
                            'name': month_data['month'].strftime('%b %Y'),
                            'revenue': float(month_revenue),
                            'completed_revenue': float(month_completed_revenue),
                            'pending_revenue': float(month_pending_revenue),
                            'orders': month_data['orders'] or 0,
                            'completed_orders': month_completed.count(),
                            'pending_orders': month_pending.count(),
                            'shipping_fees': float(month_shipping),
                            'platform_fees': float(month_platform_fees),
                            'vat_collected': float(month_vat_collected),
                        })
                grouping = 'monthly'

            else:
                current_date = start_date
                week_num = 1
                while current_date <= end_date:
                    week_end = min(current_date + timedelta(days=6), end_date)
                    
                    week_orders = Order.objects.filter(
                        created_at__date__gte=current_date,
                        created_at__date__lte=week_end
                    )
                    
                    week_completed = week_orders.filter(status='completed')
                    week_completed_revenue = week_completed.aggregate(
                        revenue=Sum('total_amount')
                    )['revenue'] or Decimal('0')
                    
                    week_pending = week_orders.filter(status__in=['pending', 'processing', 'shipped'])
                    week_pending_revenue = week_pending.aggregate(
                        revenue=Sum('total_amount')
                    )['revenue'] or Decimal('0')
                    
                    week_revenue = week_completed_revenue + week_pending_revenue
                    
                    week_shipping = Delivery.objects.filter(
                        order__in=week_completed,
                        status='delivered'
                    ).aggregate(shipping=Sum('delivery_fee'))['shipping'] or Decimal('0')
                    
                    week_platform_fees = week_completed_revenue * Decimal('0.05')
                    
                    # Calculate VAT collected for the week
                    week_vat_collected = Decimal('0')
                    week_checkouts = Checkout.objects.filter(
                        order__in=week_completed,
                        order__status='completed'
                    ).select_related('cart_item__variant')
                    
                    for checkout in week_checkouts:
                        if checkout.cart_item and checkout.cart_item.variant:
                            variant = checkout.cart_item.variant
                            price = variant.price or Decimal('0')
                            vat_percentage = variant.value_added_tax or Decimal('12.00')
                            vat_amount = price * (vat_percentage / Decimal('100'))
                            week_vat_collected += vat_amount * checkout.quantity
                        elif checkout.direct_variant_id:
                            try:
                                variant = Variants.objects.get(id=checkout.direct_variant_id)
                                price = variant.price or Decimal('0')
                                vat_percentage = variant.value_added_tax or Decimal('12.00')
                                vat_amount = price * (vat_percentage / Decimal('100'))
                                week_vat_collected += vat_amount * checkout.quantity
                            except Variants.DoesNotExist:
                                pass

                    sales_data.append({
                        'date': current_date.isoformat(),
                        'name': f'Week {week_num}',
                        'revenue': float(week_revenue),
                        'completed_revenue': float(week_completed_revenue),
                        'pending_revenue': float(week_pending_revenue),
                        'orders': week_orders.count(),
                        'completed_orders': week_completed.count(),
                        'pending_orders': week_pending.count(),
                        'shipping_fees': float(week_shipping),
                        'platform_fees': float(week_platform_fees),
                        'vat_collected': float(week_vat_collected),
                    })

                    current_date = week_end + timedelta(days=1)
                    week_num += 1
                grouping = 'weekly'

            order_status_data = Order.objects.filter(
                created_at__date__gte=start_date,
                created_at__date__lte=end_date
            ).values('status').annotate(
                count=Count('order')
            ).order_by('-count')

            status_distribution = []
            for status_data in order_status_data:
                status_distribution.append({
                    'status': status_data['status'],
                    'count': status_data['count'],
                    'color': self._get_status_color(status_data['status'])
                })

            return {
                'sales_data': sales_data,
                'status_distribution': status_distribution,
                'grouping': grouping,
            }
        except Exception as e:
            print(f"Error in _get_sales_analytics_data: {str(e)}")
            import traceback
            traceback.print_exc()
            raise

    def _get_user_analytics_data(self, start_date, end_date, range_type='weekly'):
        try:
            user_growth_data = []
            date_range_days = (end_date - start_date).days + 1

            if range_type == 'monthly' or date_range_days > 60:
                monthly_users = User.objects.filter(
                    is_customer=True,
                    created_at__date__gte=start_date,
                    created_at__date__lte=end_date
                ).annotate(
                    month=TruncMonth('created_at')
                ).values('month').annotate(
                    new_users=Count('id')
                ).order_by('month')

                for month_data in monthly_users:
                    if month_data['month']:
                        month_start = month_data['month'].date()
                        month_end = (month_start + timedelta(days=32)).replace(day=1) - timedelta(days=1)

                        returning_users = User.objects.filter(
                            is_customer=True,
                            created_at__date__lt=month_start,
                            order__created_at__date__gte=month_start,
                            order__created_at__date__lte=month_end
                        ).distinct().count()

                        total_orders = Order.objects.filter(
                            user__is_customer=True,
                            created_at__date__gte=month_start,
                            created_at__date__lte=month_end
                        ).count()

                        user_growth_data.append({
                            'period': month_data['month'].strftime('%b %Y'),
                            'new_users': month_data['new_users'],
                            'returning_users': returning_users,
                            'total_orders': total_orders,
                            'calculation_note': 'New users = customers who registered in this period. Returning users = customers who registered before this period but made orders now.',
                        })
            else:
                current_date = start_date
                week_num = 1
                while current_date <= end_date:
                    week_end = min(current_date + timedelta(days=6), end_date)

                    weekly_new = User.objects.filter(
                        is_customer=True,
                        created_at__date__gte=current_date,
                        created_at__date__lte=week_end
                    ).count()

                    weekly_returning = User.objects.filter(
                        is_customer=True,
                        created_at__date__lt=current_date,
                        order__created_at__date__gte=current_date,
                        order__created_at__date__lte=week_end
                    ).distinct().count()

                    weekly_orders = Order.objects.filter(
                        user__is_customer=True,
                        created_at__date__gte=current_date,
                        created_at__date__lte=week_end
                    ).count()

                    user_growth_data.append({
                        'period': f'Week {week_num}',
                        'new_users': weekly_new,
                        'returning_users': weekly_returning,
                        'total_orders': weekly_orders,
                    })

                    current_date = week_end + timedelta(days=1)
                    week_num += 1

            return {
                'user_growth': user_growth_data,
            }
        except Exception as e:
            print(f"Error in _get_user_analytics_data: {str(e)}")
            import traceback
            traceback.print_exc()
            raise

    def _get_product_analytics_data(self, start_date, end_date):
        try:
            from decimal import Decimal
            
            product_stats = Checkout.objects.filter(
                created_at__gte=start_date,
                created_at__lte=end_date,
                cart_item__product__isnull=False
            ).values(
                'cart_item__product__id',
                'cart_item__product__name'
            ).annotate(
                order_count=Count('id', distinct=True),
                total_revenue=Sum('total_amount')
            ).order_by('-order_count')[:10]

            product_performance = []
            for stat in product_stats:
                product_id = stat['cart_item__product__id']
                product_name = stat['cart_item__product__name'] or 'Unknown Product'
                
                product_revenue = float(stat['total_revenue'] or 0)
                platform_fee = product_revenue * 0.05
                
                # Calculate VAT collected for this product
                product_vat_collected = Decimal('0')
                product_checkouts = Checkout.objects.filter(
                    created_at__gte=start_date,
                    created_at__lte=end_date,
                    cart_item__product__id=product_id,
                    order__status='completed'
                ).select_related('cart_item__variant')
                
                for checkout in product_checkouts:
                    if checkout.cart_item and checkout.cart_item.variant:
                        variant = checkout.cart_item.variant
                        price = variant.price or Decimal('0')
                        vat_percentage = variant.value_added_tax or Decimal('12.00')
                        vat_amount = price * (vat_percentage / Decimal('100'))
                        product_vat_collected += vat_amount * checkout.quantity

                product_performance.append({
                    'name': product_name[:30] + ('...' if len(product_name) > 30 else ''),
                    'full_name': product_name,
                    'product_id': str(product_id) if product_id else None,
                    'orders': stat['order_count'],
                    'revenue': product_revenue,
                    'platform_fee': round(platform_fee, 2),
                    'vat_collected': float(product_vat_collected),
                    'calculation_note': 'Platform fee = 5% of product revenue from orders in this period. VAT = 12% (or variant-specific rate) of product price from completed orders.',
                })

            return {
                'product_performance': product_performance,
            }
        except Exception as e:
            print(f"Error in _get_product_analytics_data: {str(e)}")
            import traceback
            traceback.print_exc()
            raise

    def _get_shop_analytics_data(self, start_date, end_date):
        try:
            from decimal import Decimal
            
            shop_stats = Checkout.objects.filter(
                created_at__gte=start_date,
                created_at__lte=end_date,
                cart_item__product__shop__isnull=False
            ).values(
                'cart_item__product__shop__id',
                'cart_item__product__shop__name'
            ).annotate(
                total_sales=Sum('total_amount'),
                order_count=Count('order', distinct=True)
            ).order_by('-total_sales')[:10]

            shop_performance = []
            for stat in shop_stats:
                shop_id = stat['cart_item__product__shop__id']
                shop_name = stat['cart_item__product__shop__name'] or 'Unknown Shop'
                shop_sales = float(stat['total_sales'] or 0)
                shop_orders = stat['order_count'] or 0

                try:
                    shop = Shop.objects.get(id=shop_id)
                    
                    platform_fee = shop_sales * 0.05
                    
                    # Calculate VAT collected for this shop
                    shop_vat_collected = Decimal('0')
                    shop_checkouts = Checkout.objects.filter(
                        created_at__gte=start_date,
                        created_at__lte=end_date,
                        cart_item__product__shop=shop,
                        order__status='completed'
                    ).select_related('cart_item__variant')
                    
                    for checkout in shop_checkouts:
                        if checkout.cart_item and checkout.cart_item.variant:
                            variant = checkout.cart_item.variant
                            price = variant.price or Decimal('0')
                            vat_percentage = variant.value_added_tax or Decimal('12.00')
                            vat_amount = price * (vat_percentage / Decimal('100'))
                            shop_vat_collected += vat_amount * checkout.quantity
                        elif checkout.direct_variant_id:
                            try:
                                variant = Variants.objects.get(id=checkout.direct_variant_id)
                                price = variant.price or Decimal('0')
                                vat_percentage = variant.value_added_tax or Decimal('12.00')
                                vat_amount = price * (vat_percentage / Decimal('100'))
                                shop_vat_collected += vat_amount * checkout.quantity
                            except Variants.DoesNotExist:
                                pass

                    avg_rating = Review.objects.filter(
                        shop=shop,
                        created_at__date__gte=start_date,
                        created_at__date__lte=end_date
                    ).aggregate(avg=Avg('average_rating'))['avg'] or 0

                    follower_count = ShopFollow.objects.filter(shop=shop).count()

                    product_count = Product.objects.filter(
                        shop=shop,
                        is_removed=False,
                        upload_status='published'
                    ).count()

                    shop_performance.append({
                        'name': shop_name,
                        'shop_id': str(shop.id),
                        'sales': shop_sales,
                        'orders': shop_orders,
                        'platform_fee': round(platform_fee, 2),
                        'vat_collected': float(shop_vat_collected),
                        'average_order_value': round(shop_sales / shop_orders, 2) if shop_orders > 0 else 0,
                        'rating': round(float(avg_rating), 1),
                        'followers': follower_count,
                        'products': product_count,
                        'calculation_note': 'Platform fee = 5% of total sales from this shop in the selected period. VAT = 12% (or variant-specific rate) of product prices from completed orders.',
                    })
                except Shop.DoesNotExist:
                    continue

            return {
                'shop_performance': shop_performance,
            }
        except Exception as e:
            print(f"Error in _get_shop_analytics_data: {str(e)}")
            import traceback
            traceback.print_exc()
            raise

    def _get_operational_data(self, start_date, end_date):
        try:
            from decimal import Decimal
            
            # Active Boosts (from products being boosted)
            active_boosts = Boost.objects.filter(
                start_date__date__lte=end_date,
                end_date__date__gte=start_date,
                status='active'
            ).count()
            
            # Calculate boost revenue (price of active boost plans)
            boost_revenue = Boost.objects.filter(
                start_date__date__lte=end_date,
                end_date__date__gte=start_date,
                status='active'
            ).aggregate(
                total_revenue=Sum('boost_plan__price')
            )['total_revenue'] or Decimal('0')

            # Pending Refunds
            pending_refunds = Refund.objects.filter(
                requested_at__date__gte=start_date,
                requested_at__date__lte=end_date,
                status='pending'
            ).count()
            
            # Calculate total refund amount pending
            pending_refund_amount = Refund.objects.filter(
                requested_at__date__gte=start_date,
                requested_at__date__lte=end_date,
                status='pending'
            ).aggregate(
                total_amount=Sum('total_refund_amount')
            )['total_amount'] or Decimal('0')

            # Completed Refunds in period
            completed_refunds = Refund.objects.filter(
                processed_at__date__gte=start_date,
                processed_at__date__lte=end_date,
                status='approved'
            ).count()
            
            completed_refund_amount = Refund.objects.filter(
                processed_at__date__gte=start_date,
                processed_at__date__lte=end_date,
                status='approved'
            ).aggregate(
                total_amount=Sum('approved_refund_amount')
            )['total_amount'] or Decimal('0')

            # Low Stock Products
            low_stock_variants = Variants.objects.filter(
                quantity__lt=5,
                is_active=True,
                product__is_removed=False,
                product__upload_status='published'
            ).values('product').distinct().count()

            # Average Rating
            avg_rating = Review.objects.filter(
                created_at__date__gte=start_date,
                created_at__date__lte=end_date
            ).aggregate(
                avg_rating=Avg('average_rating')
            )['avg_rating'] or 0
            
            total_reviews = Review.objects.filter(
                created_at__date__gte=start_date,
                created_at__date__lte=end_date
            ).count()

            # Pending Reports
            pending_reports = Report.objects.filter(
                created_at__date__gte=start_date,
                created_at__date__lte=end_date,
                status='pending'
            ).count()

            # Active Riders
            active_riders = Rider.objects.filter(
                verified=True,
                is_accepting_deliveries=True
            ).count()
            
            total_riders = Rider.objects.filter(verified=True).count()

            # Total deliveries completed in period
            completed_deliveries = Delivery.objects.filter(
                delivered_at__date__gte=start_date,
                delivered_at__date__lte=end_date,
                status='delivered'
            ).count()
            
            total_delivery_fees = Delivery.objects.filter(
                delivered_at__date__gte=start_date,
                delivered_at__date__lte=end_date,
                status='delivered'
            ).aggregate(
                total_fees=Sum('delivery_fee')
            )['total_fees'] or Decimal('0')

            # Active Vouchers
            active_vouchers = Voucher.objects.filter(
                is_active=True,
                start_date__lte=end_date,
                end_date__gte=start_date
            ).count()
            
            # Vouchers used in period
            vouchers_used = Checkout.objects.filter(
                created_at__gte=start_date,
                created_at__lte=end_date,
                voucher__isnull=False
            ).count()
            
            total_voucher_discount = Checkout.objects.filter(
                created_at__gte=start_date,
                created_at__lte=end_date,
                voucher__isnull=False
            ).aggregate(
                total_discount=Sum('voucher__value')
            )['total_discount'] or Decimal('0')

            # Calculate incoming balance from ongoing transactions
            pending_orders_value = Order.objects.filter(
                created_at__date__gte=start_date,
                created_at__date__lte=end_date,
                status__in=['pending', 'processing', 'shipped']
            ).aggregate(
                total=Sum('total_amount')
            )['total'] or Decimal('0')

            return {
                'active_boosts': active_boosts,
                'boost_revenue': float(boost_revenue),
                'pending_refunds': pending_refunds,
                'pending_refund_amount': float(pending_refund_amount),
                'completed_refunds': completed_refunds,
                'completed_refund_amount': float(completed_refund_amount),
                'low_stock_products': low_stock_variants,
                'avg_rating': round(float(avg_rating), 1),
                'total_reviews': total_reviews,
                'pending_reports': pending_reports,
                'active_riders': active_riders,
                'total_riders': total_riders,
                'completed_deliveries': completed_deliveries,
                'total_delivery_fees': float(total_delivery_fees),
                'active_vouchers': active_vouchers,
                'vouchers_used': vouchers_used,
                'total_voucher_discount': float(total_voucher_discount),
                'incoming_balance': float(pending_orders_value),
                'calculation_notes': {
                    'boost_revenue': 'Sum of boost_plan prices for active boosts in this period',
                    'pending_refund_amount': 'Sum of total_refund_amount for pending refunds',
                    'completed_refund_amount': 'Sum of approved_refund_amount for approved refunds',
                    'total_delivery_fees': 'Sum of delivery_fee from completed deliveries',
                    'total_voucher_discount': 'Sum of voucher values applied to checkouts',
                    'platform_fee': 'Calculated as 5% of total revenue from completed orders',
                    'incoming_balance': 'Sum of total_amount from pending/processing/shipped orders (ongoing transactions)',
                }
            }
        except Exception as e:
            print(f"Error in _get_operational_data: {str(e)}")
            import traceback
            traceback.print_exc()
            raise

    def _get_status_color(self, status):
        color_map = {
            'pending': '#f59e0b',
            'processing': '#3b82f6',
            'shipped': '#8b5cf6',
            'delivered': '#10b981',
            'completed': '#10b981',
            'cancelled': '#ef4444',
            'refunded': '#6b7280',
        }
        return color_map.get(status.lower(), '#6b7280')


class AdminAnalytics(viewsets.ViewSet):
    @action(detail=False, methods=['get'])
    def get_comprehensive_analytics(self, request):
        try:
            start_date_str = request.query_params.get('start_date')
            end_date_str = request.query_params.get('end_date')
            date_range_type = request.query_params.get('range_type', 'weekly')
            
            valid_range_types = ['daily', 'weekly', 'monthly', 'yearly', 'custom']
            if date_range_type not in valid_range_types:
                date_range_type = 'weekly'
            
            start_date = None
            end_date = None
            
            if start_date_str and end_date_str:
                try:
                    start_date = datetime.strptime(start_date_str, '%Y-%m-%d').date()
                    end_date = datetime.strptime(end_date_str, '%Y-%m-%d').date()
                except ValueError as e:
                    return Response({
                        'success': False,
                        'error': f'Invalid date format. Use YYYY-MM-DD. Error: {str(e)}'
                    }, status=status.HTTP_400_BAD_REQUEST)
            else:
                end_date = timezone.now().date()
                start_date = end_date - timedelta(days=6)
            
            if start_date > end_date:
                start_date, end_date = end_date, start_date
            
            max_days = 365 * 2
            date_range_days = (end_date - start_date).days
            if date_range_days > max_days:
                return Response({
                    'success': False,
                    'error': f'Date range exceeds maximum allowed ({max_days} days)'
                }, status=status.HTTP_400_BAD_REQUEST)
            
            order_sales_data = self._get_order_sales_analytics(start_date, end_date, date_range_type)
            user_customer_data = self._get_user_customer_analytics(start_date, end_date, date_range_type)
            product_inventory_data = self._get_product_inventory_analytics(start_date, end_date)
            shop_merchant_data = self._get_shop_merchant_analytics(start_date, end_date, date_range_type)
            boost_promotion_data = self._get_boost_promotion_analytics(start_date, end_date)
            rider_delivery_data = self._get_rider_delivery_analytics(start_date, end_date)
            voucher_discount_data = self._get_voucher_discount_analytics(start_date, end_date)
            refund_return_data = self._get_refund_return_analytics(start_date, end_date, date_range_type)
            report_moderation_data = self._get_report_moderation_analytics(start_date, end_date)
            
            comprehensive_data = {
                'success': True,
                'date_range': {
                    'start_date': start_date.isoformat(),
                    'end_date': end_date.isoformat(),
                    'range_type': date_range_type,
                    'total_days': date_range_days,
                },
                'order_sales_analytics': order_sales_data,
                'user_customer_analytics': user_customer_data,
                'product_inventory_analytics': product_inventory_data,
                'shop_merchant_analytics': shop_merchant_data,
                'boost_promotion_analytics': boost_promotion_data,
                'rider_delivery_analytics': rider_delivery_data,
                'voucher_discount_analytics': voucher_discount_data,
                'refund_return_analytics': refund_return_data,
                'report_moderation_analytics': report_moderation_data,
            }
            
            return Response(comprehensive_data, status=status.HTTP_200_OK)
            
        except Exception as e:
            print(f"Error in get_comprehensive_analytics: {str(e)}")
            import traceback
            traceback.print_exc()
            
            return Response({
                'success': False,
                'error': str(e),
                'message': 'An error occurred while fetching analytics data'
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
    
    def _get_order_sales_analytics(self, start_date, end_date, range_type='weekly'):
        try:
            date_range_days = (end_date - start_date).days + 1
            
            if range_type == 'daily' or date_range_days <= 7:
                current_date = start_date
                order_metrics_data = []
                
                while current_date <= end_date:
                    day_data = Order.objects.filter(
                        created_at__date=current_date
                    ).aggregate(
                        revenue=Sum('total_amount'),
                        orders=Count('order'),
                        avg_order_value=Avg('total_amount')
                    )
                    
                    refunds = Order.objects.filter(
                        created_at__date=current_date,
                        status='cancelled'
                    ).count()
                    
                    order_metrics_data.append({
                        'month': current_date.strftime('%a, %b %d'),
                        'revenue': float(day_data['revenue'] or 0),
                        'orders': day_data['orders'] or 0,
                        'avgOrderValue': float(day_data['avg_order_value'] or 0),
                        'refunds': refunds,
                    })
                    
                    current_date += timedelta(days=1)
                    
            elif range_type == 'monthly' or date_range_days > 60:
                monthly_orders = Order.objects.filter(
                    created_at__date__gte=start_date,
                    created_at__date__lte=end_date
                ).annotate(
                    month=TruncMonth('created_at')
                ).values('month').annotate(
                    revenue=Sum('total_amount'),
                    orders=Count('order'),
                    avg_order_value=Avg('total_amount')
                ).order_by('month')
                
                order_metrics_data = []
                for month_data in monthly_orders:
                    if month_data['month']:
                        month_start = month_data['month'].date()
                        month_end = (month_start + timedelta(days=32)).replace(day=1) - timedelta(days=1)
                        
                        refunds = Order.objects.filter(
                            created_at__date__gte=month_start,
                            created_at__date__lte=month_end,
                            status='cancelled'
                        ).count()
                        
                        order_metrics_data.append({
                            'month': month_data['month'].strftime('%b %Y'),
                            'revenue': float(month_data['revenue'] or 0),
                            'orders': month_data['orders'],
                            'avgOrderValue': float(month_data['avg_order_value'] or 0),
                            'refunds': refunds,
                        })
            else:
                current_date = start_date
                week_num = 1
                order_metrics_data = []
                
                while current_date <= end_date:
                    week_end = min(current_date + timedelta(days=6), end_date)
                    
                    week_data = Order.objects.filter(
                        created_at__date__gte=current_date,
                        created_at__date__lte=week_end
                    ).aggregate(
                        revenue=Sum('total_amount'),
                        orders=Count('order'),
                        avg_order_value=Avg('total_amount')
                    )
                    
                    refunds = Order.objects.filter(
                        created_at__date__gte=current_date,
                        created_at__date__lte=week_end,
                        status='cancelled'
                    ).count()
                    
                    order_metrics_data.append({
                        'month': f'Week {week_num}',
                        'revenue': float(week_data['revenue'] or 0),
                        'orders': week_data['orders'] or 0,
                        'avgOrderValue': float(week_data['avg_order_value'] or 0),
                        'refunds': refunds,
                    })
                    
                    current_date = week_end + timedelta(days=1)
                    week_num += 1
            
            order_status_data = Order.objects.filter(
                created_at__date__gte=start_date,
                created_at__date__lte=end_date
            ).values('status').annotate(
                count=Count('order')
            ).order_by('status')
            
            status_distribution = []
            for status_data in order_status_data:
                status_distribution.append({
                    'status': status_data['status'],
                    'count': status_data['count'],
                    'color': self._get_status_color(status_data['status'])
                })
            
            payment_methods = Order.objects.filter(
                created_at__date__gte=start_date,
                created_at__date__lte=end_date
            ).values('payment_method').annotate(
                count=Count('order')
            ).order_by('-count')
            
            payment_distribution = []
            total_orders = Order.objects.filter(
                created_at__date__gte=start_date,
                created_at__date__lte=end_date
            ).count()
            
            for payment_data in payment_methods:
                percentage = round((payment_data['count'] / total_orders * 100), 1) if total_orders > 0 else 0
                payment_distribution.append({
                    'method': payment_data['payment_method'],
                    'count': payment_data['count'],
                    'percentage': percentage
                })
            
            return {
                'order_metrics_data': order_metrics_data,
                'order_status_distribution': status_distribution,
                'payment_method_data': payment_distribution,
            }
        except Exception as e:
            print(f"Error in _get_order_sales_analytics: {str(e)}")
            import traceback
            traceback.print_exc()
            return {
                'order_metrics_data': [],
                'order_status_distribution': [],
                'payment_method_data': [],
            }
    
    def _get_user_customer_analytics(self, start_date, end_date, range_type='weekly'):
        try:
            date_range_days = (end_date - start_date).days + 1
            
            if range_type == 'monthly' or date_range_days > 60:
                monthly_users = User.objects.filter(
                    is_customer=True,
                    created_at__date__gte=start_date,
                    created_at__date__lte=end_date
                ).annotate(
                    month=TruncMonth('created_at')
                ).values('month').annotate(
                    new_users=Count('id')
                ).order_by('month')
                
                user_growth_data = []
                for month_data in monthly_users:
                    if month_data['month']:
                        month_start = month_data['month'].date()
                        month_end = (month_start + timedelta(days=32)).replace(day=1) - timedelta(days=1)
                        
                        returning_users = User.objects.filter(
                            is_customer=True,
                            created_at__date__lt=month_start,
                            order__created_at__date__gte=month_start,
                            order__created_at__date__lte=month_end
                        ).distinct().count()
                        
                        user_growth_data.append({
                            'month': month_data['month'].strftime('%b %Y'),
                            'new': month_data['new_users'],
                            'returning': returning_users,
                            'total': month_data['new_users'] + returning_users,
                        })
            else:
                current_date = start_date
                week_num = 1
                user_growth_data = []
                
                while current_date <= end_date:
                    week_end = min(current_date + timedelta(days=6), end_date)
                    
                    weekly_new = User.objects.filter(
                        is_customer=True,
                        created_at__date__gte=current_date,
                        created_at__date__lte=week_end
                    ).count()
                    
                    weekly_returning = User.objects.filter(
                        is_customer=True,
                        created_at__date__lt=current_date,
                        order__created_at__date__gte=current_date,
                        order__created_at__date__lte=week_end
                    ).distinct().count()
                    
                    user_growth_data.append({
                        'month': f'Week {week_num}',
                        'new': weekly_new,
                        'returning': weekly_returning,
                        'total': weekly_new + weekly_returning,
                    })
                    
                    current_date = week_end + timedelta(days=1)
                    week_num += 1
            
            total_users = User.objects.count()
            role_distribution = []
            
            if total_users > 0:
                role_distribution = [
                    {
                        'role': 'Customers',
                        'count': User.objects.filter(is_customer=True).count(),
                        'percentage': round((User.objects.filter(is_customer=True).count() / total_users * 100), 1)
                    },
                    {
                        'role': 'Riders',
                        'count': User.objects.filter(is_rider=True).count(),
                        'percentage': round((User.objects.filter(is_rider=True).count() / total_users * 100), 1)
                    },
                    {
                        'role': 'Admins',
                        'count': User.objects.filter(is_admin=True).count(),
                        'percentage': round((User.objects.filter(is_admin=True).count() / total_users * 100), 1)
                    },
                ]
            
            stage_distribution = User.objects.filter(
                registration_stage__isnull=False
            ).values('registration_stage').annotate(
                count=Count('id')
            ).order_by('registration_stage')
            
            registration_data = []
            for stage_data in stage_distribution:
                stage_label = self._get_stage_label(stage_data['registration_stage'])
                registration_data.append({
                    'stage': stage_label,
                    'count': stage_data['count']
                })
            
            return {
                'user_growth_data': user_growth_data,
                'user_role_distribution': role_distribution,
                'registration_stage_data': registration_data,
            }
        except Exception as e:
            print(f"Error in _get_user_customer_analytics: {str(e)}")
            import traceback
            traceback.print_exc()
            return {
                'user_growth_data': [],
                'user_role_distribution': [],
                'registration_stage_data': [],
            }
    
    def _get_product_inventory_analytics(self, start_date, end_date):
        try:
            product_stats = Checkout.objects.filter(
                created_at__gte=start_date,
                created_at__lte=end_date,
                cart_item__product__isnull=False
            ).values(
                'cart_item__product__id',
                'cart_item__product__name'
            ).annotate(
                order_count=Count('id', distinct=True),
                total_revenue=Sum('total_amount')
            ).order_by('-order_count')[:10]
            
            product_performance = []
            for stat in product_stats:
                product_id = stat['cart_item__product__id']
                product_name = stat['cart_item__product__name'] or 'Unknown Product'
                
                try:
                    product = Product.objects.get(id=product_id)
                    
                    views = CustomerActivity.objects.filter(
                        product=product,
                        activity_type='view',
                        created_at__date__gte=start_date,
                        created_at__date__lte=end_date
                    ).count()
                    
                    favorites = Favorites.objects.filter(product=product).count()
                    total_stock = product.total_stock
                    
                    product_performance.append({
                        'name': product_name[:30] + ('...' if len(product_name) > 30 else ''),
                        'orders': stat['order_count'],
                        'revenue': float(stat['total_revenue'] or 0),
                        'views': views,
                        'favorites': favorites,
                        'stock': total_stock,
                    })
                except Product.DoesNotExist:
                    continue
            
            category_stats = Checkout.objects.filter(
                created_at__gte=start_date,
                created_at__lte=end_date,
                cart_item__product__category__isnull=False
            ).values(
                'cart_item__product__category__id',
                'cart_item__product__category__name'
            ).annotate(
                total_revenue=Sum('total_amount'),
                product_count=Count('cart_item__product', distinct=True)
            ).order_by('-total_revenue')[:10]
            
            category_data = []
            for stat in category_stats:
                category_id = stat['cart_item__product__category__id']
                category_name = stat['cart_item__product__category__name'] or 'Unknown Category'
                
                try:
                    category = Category.objects.get(id=category_id)
                    
                    avg_rating = Review.objects.filter(
                        product__category=category,
                        created_at__date__gte=start_date,
                        created_at__date__lte=end_date
                    ).aggregate(avg=Avg('average_rating'))['avg'] or 0
                    
                    category_data.append({
                        'category': category_name,
                        'revenue': float(stat['total_revenue'] or 0),
                        'products': stat['product_count'],
                        'avgRating': round(float(avg_rating), 1)
                    })
                except Category.DoesNotExist:
                    continue
            
            products_with_low_stock = 0
            products_with_stock = 0
            products_out_of_stock = 0
            
            for product in Product.objects.filter(is_removed=False, upload_status='published'):
                total_stock = product.total_stock
                if total_stock >= 10:
                    products_with_stock += 1
                elif 1 <= total_stock < 10:
                    products_with_low_stock += 1
                elif total_stock == 0:
                    products_out_of_stock += 1
            
            inventory_status = [
                {'status': 'In Stock', 'count': products_with_stock, 'color': '#10b981'},
                {'status': 'Low Stock', 'count': products_with_low_stock, 'color': '#f59e0b'},
                {'status': 'Out of Stock', 'count': products_out_of_stock, 'color': '#ef4444'},
            ]
            
            engagement_data = [
                {
                    'activity': 'Product Views',
                    'count': CustomerActivity.objects.filter(
                        activity_type='view',
                        created_at__date__gte=start_date,
                        created_at__date__lte=end_date
                    ).count()
                },
                {
                    'activity': 'Add to Cart',
                    'count': CartItem.objects.filter(
                        added_at__date__gte=start_date,
                        added_at__date__lte=end_date
                    ).count()
                },
                {
                    'activity': 'Wishlist Adds',
                    'count': Favorites.objects.count()
                },
                {
                    'activity': 'Reviews Posted',
                    'count': Review.objects.filter(
                        created_at__date__gte=start_date,
                        created_at__date__lte=end_date
                    ).count()
                },
            ]
            
            return {
                'product_performance_data': product_performance,
                'category_performance_data': category_data,
                'inventory_status_data': inventory_status,
                'product_engagement_data': engagement_data,
            }
        except Exception as e:
            print(f"Error in _get_product_inventory_analytics: {str(e)}")
            import traceback
            traceback.print_exc()
            return {
                'product_performance_data': [],
                'category_performance_data': [],
                'inventory_status_data': [],
                'product_engagement_data': [],
            }
    
    def _get_shop_merchant_analytics(self, start_date, end_date, range_type='weekly'):
        try:
            shop_stats = Checkout.objects.filter(
                created_at__gte=start_date,
                created_at__lte=end_date,
                cart_item__product__shop__isnull=False
            ).values(
                'cart_item__product__shop__id',
                'cart_item__product__shop__name'
            ).annotate(
                total_sales=Sum('total_amount'),
                order_count=Count('order', distinct=True)
            ).order_by('-total_sales')[:10]
            
            shop_performance = []
            for stat in shop_stats:
                shop_id = stat['cart_item__product__shop__id']
                shop_name = stat['cart_item__product__shop__name'] or 'Unknown Shop'
                
                try:
                    shop = Shop.objects.get(id=shop_id)
                    
                    avg_rating = Review.objects.filter(
                        shop=shop,
                        created_at__date__gte=start_date,
                        created_at__date__lte=end_date
                    ).aggregate(avg=Avg('average_rating'))['avg'] or 0
                    
                    follower_count = ShopFollow.objects.filter(shop=shop).count()
                    product_count = Product.objects.filter(
                        shop=shop,
                        is_removed=False,
                        upload_status='published'
                    ).count()
                    
                    shop_performance.append({
                        'name': shop_name,
                        'sales': float(stat['total_sales'] or 0),
                        'orders': stat['order_count'] or 0,
                        'rating': round(float(avg_rating), 1),
                        'followers': follower_count,
                        'products': product_count
                    })
                except Shop.DoesNotExist:
                    continue
            
            date_range_days = (end_date - start_date).days + 1
            
            if range_type == 'monthly' or date_range_days > 60:
                monthly_shops = Shop.objects.filter(
                    created_at__date__gte=start_date,
                    created_at__date__lte=end_date
                ).annotate(
                    month=TruncMonth('created_at')
                ).values('month').annotate(
                    new_shops=Count('id')
                ).order_by('month')
                
                shop_growth_data = []
                for month_data in monthly_shops:
                    if month_data['month']:
                        month_start = month_data['month'].date()
                        month_end = (month_start + timedelta(days=32)).replace(day=1) - timedelta(days=1)
                        
                        total_shops = Shop.objects.filter(
                            created_at__date__lte=month_end
                        ).count()
                        
                        total_followers = ShopFollow.objects.filter(
                            shop__created_at__date__lte=month_end
                        ).count()
                        
                        shop_growth_data.append({
                            'month': month_data['month'].strftime('%b %Y'),
                            'newShops': month_data['new_shops'],
                            'totalShops': total_shops,
                            'followers': total_followers
                        })
            else:
                current_date = start_date
                week_num = 1
                shop_growth_data = []
                
                while current_date <= end_date:
                    week_end = min(current_date + timedelta(days=6), end_date)
                    
                    new_shops = Shop.objects.filter(
                        created_at__date__gte=current_date,
                        created_at__date__lte=week_end
                    ).count()
                    
                    total_shops = Shop.objects.filter(
                        created_at__date__lte=week_end
                    ).count()
                    
                    total_followers = ShopFollow.objects.filter(
                        shop__created_at__date__lte=week_end
                    ).count()
                    
                    shop_growth_data.append({
                        'month': f'Week {week_num}',
                        'newShops': new_shops,
                        'totalShops': total_shops,
                        'followers': total_followers
                    })
                    
                    current_date = week_end + timedelta(days=1)
                    week_num += 1
            
            shop_locations = Shop.objects.exclude(
                Q(city__isnull=True) | Q(city='')
            ).values('city').annotate(
                shop_count=Count('id')
            ).order_by('-shop_count')[:10]
            
            location_data = []
            for location in shop_locations:
                location_revenue = Checkout.objects.filter(
                    created_at__gte=start_date,
                    created_at__lte=end_date,
                    cart_item__product__shop__city=location['city']
                ).aggregate(total=Sum('total_amount'))['total'] or 0
                
                location_data.append({
                    'location': location['city'],
                    'shops': location['shop_count'],
                    'revenue': float(location_revenue)
                })
            
            return {
                'shop_performance_data': shop_performance,
                'shop_growth_data': shop_growth_data,
                'shop_location_data': location_data,
            }
        except Exception as e:
            print(f"Error in _get_shop_merchant_analytics: {str(e)}")
            import traceback
            traceback.print_exc()
            return {
                'shop_performance_data': [],
                'shop_growth_data': [],
                'shop_location_data': [],
            }
    
    def _get_boost_promotion_analytics(self, start_date, end_date):
        try:
            boost_performance = Boost.objects.filter(
                created_at__date__gte=start_date,
                created_at__date__lte=end_date
            ).values(
                'boost_plan__name'
            ).annotate(
                usage_count=Count('id'),
                active_boosts=Count('id', filter=Q(status='active'))
            ).order_by('-usage_count')
            
            boost_performance_data = []
            for boost in boost_performance:
                boost_plan_name = boost['boost_plan__name']
                if boost_plan_name:
                    try:
                        boost_plan = BoostPlan.objects.get(name=boost_plan_name)
                        total_revenue = float(boost_plan.price) * boost['usage_count']
                    except BoostPlan.DoesNotExist:
                        total_revenue = 0
                else:
                    total_revenue = 0
                
                boost_performance_data.append({
                    'plan': boost_plan_name or 'Unknown Plan',
                    'revenue': total_revenue,
                    'usage': boost['usage_count'],
                    'active_boosts': boost['active_boosts']
                })
            
            active_boost_status = [
                {'status': 'Active', 'count': Boost.objects.filter(status='active').count(), 'color': '#10b981'},
                {'status': 'Pending', 'count': Boost.objects.filter(status='pending').count(), 'color': '#f59e0b'},
                {'status': 'Expired', 'count': Boost.objects.filter(status='expired').count(), 'color': '#6b7280'},
            ]
            
            return {
                'boost_performance_data': boost_performance_data,
                'active_boost_status': active_boost_status,
            }
        except Exception as e:
            print(f"Error in _get_boost_promotion_analytics: {str(e)}")
            import traceback
            traceback.print_exc()
            return {
                'boost_performance_data': [],
                'active_boost_status': [],
            }
    
    def _get_rider_delivery_analytics(self, start_date, end_date):
        try:
            rider_performance = Rider.objects.annotate(
                delivery_count=Count(
                    'delivery',
                    filter=Q(
                        delivery__created_at__date__gte=start_date,
                        delivery__created_at__date__lte=end_date
                    )
                ),
                successful_deliveries=Count(
                    'delivery',
                    filter=Q(
                        delivery__status='delivered',
                        delivery__created_at__date__gte=start_date,
                        delivery__created_at__date__lte=end_date
                    )
                )
            ).filter(
                delivery_count__gt=0
            ).order_by('-delivery_count')[:10]
            
            rider_performance_data = []
            for rider in rider_performance:
                success_rate = (rider.successful_deliveries / rider.delivery_count * 100) if rider.delivery_count > 0 else 0
                rider_name = f"{rider.rider.first_name or ''} {rider.rider.last_name or ''}".strip() or str(rider.rider.id)
                rider_performance_data.append({
                    'name': rider_name,
                    'deliveries': rider.delivery_count,
                    'successRate': round(success_rate, 1)
                })
            
            delivery_status_data = Delivery.objects.filter(
                created_at__date__gte=start_date,
                created_at__date__lte=end_date
            ).values('status').annotate(
                count=Count('id')
            ).order_by('status')
            
            status_distribution = []
            color_map = {
                'pending': '#f59e0b', 'picked_up': '#3b82f6', 'in_progress': '#8b5cf6',
                'delivered': '#10b981', 'cancelled': '#ef4444', 'declined': '#6b7280', 'accepted': '#3b82f6',
            }
            for status_data in delivery_status_data:
                status_distribution.append({
                    'status': status_data['status'].replace('_', ' ').title(),
                    'count': status_data['count'],
                    'color': color_map.get(status_data['status'], '#6b7280')
                })
            
            rider_verification_data = [
                {'status': 'Verified', 'count': Rider.objects.filter(verified=True).count(), 'color': '#10b981'},
                {'status': 'Pending', 'count': Rider.objects.filter(verified=False).count(), 'color': '#f59e0b'},
            ]
            
            return {
                'rider_performance_data': rider_performance_data,
                'delivery_status_data': status_distribution,
                'rider_verification_data': rider_verification_data,
            }
        except Exception as e:
            print(f"Error in _get_rider_delivery_analytics: {str(e)}")
            import traceback
            traceback.print_exc()
            return {
                'rider_performance_data': [],
                'delivery_status_data': [],
                'rider_verification_data': [],
            }
    
