class SellerDashboard(viewsets.ViewSet):
    """
    Seller dashboard viewset with comprehensive metrics and data
    Uses CHECKOUT STATUS (not order status) for accurate per-shop sales tracking
    VAT is excluded from sales/earnings calculations but still available from variants
    """
    
    @action(detail=False, methods=['get'])
    def get_dashboard(self, request):
        """Get comprehensive dashboard data for seller"""
        try:
            # Get parameters with defaults
            shop_id = request.query_params.get('shop_id')
            start_date = request.query_params.get('start_date')
            end_date = request.query_params.get('end_date')
            range_type = request.query_params.get('range_type', 'monthly')
            
            if not shop_id:
                return Response(
                    {'error': 'shop_id is required', 'success': False},
                    status=status.HTTP_400_BAD_REQUEST
                )
            
            try:
                shop = Shop.objects.get(id=shop_id)
            except Shop.DoesNotExist:
                return Response(
                    {'error': 'Shop not found', 'success': False},
                    status=status.HTTP_404_NOT_FOUND
                )
            
            # Parse dates
            if start_date:
                try:
                    start_date = datetime.strptime(start_date, '%Y-%m-%d').date()
                except:
                    start_date = None
            else:
                start_date = None
            
            if end_date:
                try:
                    end_date = datetime.strptime(end_date, '%Y-%m-%d').date()
                except:
                    end_date = None
            else:
                end_date = None
            
            # Build response data
            data = {
                'success': True,
                'summary': self._get_summary_data(shop, start_date, end_date),
                'latest_orders': self._get_latest_orders(shop),
                'low_stock': self._get_low_stock_data(shop),
                'refunds': self._get_refund_data(shop),
                'shop_performance': self._get_shop_performance_data(shop),
                'reports': self._get_report_data(shop),
                'store_management_counts': self._get_store_management_counts(shop),
            }
            
            return Response(data, status=status.HTTP_200_OK)
            
        except Exception as e:
            print(f"Error in get_dashboard: {str(e)}")
            traceback.print_exc()
            return Response(
                {'error': str(e), 'success': False},
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )

    def _get_store_management_counts(self, shop):
        """Get counts for Store Management grid items - FILTERED BY SPECIFIC SHOP"""
        try:
            # Only count products for this specific shop
            product_count = Product.objects.filter(
                shop=shop,
                is_removed=False
            ).count()

            # Only count orders for this specific shop (using checkout status, not order status)
            orders_count = Checkout.objects.filter(
                Q(cart_item__product__shop=shop) | Q(direct_shop_id=str(shop.id))
            ).values('order').distinct().count()

            # Only count gifts for this specific shop
            gifts_count = AppliedGift.objects.filter(
                shop_id=shop,
                is_active=True
            ).count()

            # Only count return addresses for this specific shop
            address_count = ReturnAddress.objects.filter(
                shop=shop
            ).count()

            # Only count shop vouchers for this specific shop
            shop_voucher_count = Voucher.objects.filter(
                shop=shop,
                is_active=True,
                voucher_type='shop'
            ).count()

            # Only count product vouchers for this specific shop
            product_voucher_count = Voucher.objects.filter(
                shop=shop,
                is_active=True,
                voucher_type='product'
            ).count()

            return {
                'product_list': product_count,
                'orders': orders_count,
                'gifts': gifts_count,
                'address': address_count,
                'shop_voucher': shop_voucher_count,
                'product_voucher': product_voucher_count,
            }
        except Exception as e:
            print(f"Error in _get_store_management_counts: {str(e)}")
            return {
                'product_list': 0,
                'orders': 0,
                'gifts': 0,
                'address': 0,
                'shop_voucher': 0,
                'product_voucher': 0,
            }
    
    def _get_summary_data(self, shop, start_date=None, end_date=None):
        """
        Get summary statistics for the dashboard cards - using CHECKOUT STATUS
        
        Sales are counted when checkout.status = 'completed' (delivered)
        This accurately tracks per-shop sales regardless of global order status
        """
        
        # Base filter for this shop's checkouts
        base_filter = Q(cart_item__product__shop=shop) | Q(direct_shop_id=str(shop.id))
        
        # Get completed checkouts (delivered) for this shop
        completed_checkouts = Checkout.objects.filter(
            base_filter,
            status='completed'  # 👈 Use checkout status, not order status
        ).select_related('order')
        
        # Calculate total sales WITHOUT VAT using the actual product/variant prices
        total_sales = Decimal('0.00')
        total_earnings = Decimal('0.00')
        
        for checkout_item in completed_checkouts:
            if checkout_item.direct_product_price:
                # Direct checkout (no cart item)
                item_total = checkout_item.direct_product_price * checkout_item.quantity
                total_sales += item_total
                total_earnings += item_total
            elif checkout_item.cart_item and checkout_item.cart_item.variant:
                # Has variant - use variant price
                variant_price = checkout_item.cart_item.variant.price or Decimal('0.00')
                item_total = variant_price * checkout_item.quantity
                total_sales += item_total
                total_earnings += item_total
            elif checkout_item.cart_item and checkout_item.cart_item.product:
                # Legacy product without variant
                product_price = Decimal(str(checkout_item.cart_item.product.price)) if hasattr(checkout_item.cart_item.product, 'price') else Decimal('0.00')
                item_total = product_price * checkout_item.quantity
                total_sales += item_total
                total_earnings += item_total
        
        # Total unique orders that have at least one completed checkout from this shop
        total_orders = completed_checkouts.values('order').distinct().count()
        
        # Low stock variants count - only for this specific shop
        low_stock_variants = Variants.objects.filter(
            product__shop=shop,
            product__upload_status='published',
            product__is_removed=False,
            is_active=True,
            quantity__gt=0,
            quantity__lte=F('critical_trigger')
        ).filter(
            critical_trigger__isnull=False
        )
        
        low_stock_count = low_stock_variants.count()
        
        # Refund requests count - only for this specific shop
        refund_requests = Refund.objects.filter(
            order_id__checkout__cart_item__product__shop=shop,
            status__in=['pending', 'negotiation', 'dispute']
        ).distinct().count()
        
        # Draft products count - only for this specific shop
        draft_count = Product.objects.filter(
            shop=shop,
            upload_status='draft',
            is_removed=False
        ).count()
        
        # Calculate period sales if dates provided (for compatibility)
        period_sales = 0
        if start_date and end_date:
            start_datetime = timezone.make_aware(datetime.combine(start_date, time.min))
            end_datetime = timezone.make_aware(datetime.combine(end_date, time.max))
            
            period_checkouts = Checkout.objects.filter(
                base_filter,
                status='completed',
                created_at__range=[start_datetime, end_datetime]
            ).select_related('order')
            
            for checkout_item in period_checkouts:
                if checkout_item.direct_product_price:
                    period_sales += float(checkout_item.direct_product_price) * checkout_item.quantity
                elif checkout_item.cart_item and checkout_item.cart_item.variant:
                    variant_price = float(checkout_item.cart_item.variant.price or 0)
                    period_sales += variant_price * checkout_item.quantity
                elif checkout_item.cart_item and checkout_item.cart_item.product:
                    product_price = float(getattr(checkout_item.cart_item.product, 'price', 0))
                    period_sales += product_price * checkout_item.quantity
        
        # Optional: Get pending earnings (checkouts that are shipped but not yet completed)
        pending_checkouts = Checkout.objects.filter(
            base_filter,
            status='pending'  # 👈 Still pending/delivery in progress
        ).select_related('order')
        
        pending_earnings = Decimal('0.00')
        for checkout_item in pending_checkouts:
            if checkout_item.direct_product_price:
                pending_earnings += checkout_item.direct_product_price * checkout_item.quantity
            elif checkout_item.cart_item and checkout_item.cart_item.variant:
                variant_price = checkout_item.cart_item.variant.price or Decimal('0.00')
                pending_earnings += variant_price * checkout_item.quantity
            elif checkout_item.cart_item and checkout_item.cart_item.product:
                product_price = Decimal(str(checkout_item.cart_item.product.price)) if hasattr(checkout_item.cart_item.product, 'price') else Decimal('0.00')
                pending_earnings += product_price * checkout_item.quantity
        
        return {
            'total_sales': float(total_sales),
            'total_earnings': float(total_earnings),
            'total_orders': total_orders,
            'pending_earnings': float(pending_earnings),
            'pending_orders': pending_checkouts.values('order').distinct().count(),
            'low_stock_count': low_stock_count,
            'refund_requests': refund_requests,
            'draft_count': draft_count,
            'period_sales': period_sales if start_date and end_date else float(total_sales),
        }
    
    def _get_latest_orders(self, shop, limit=5):
        """Get latest 5 orders for the shop with per-shop status - FILTERED BY SPECIFIC SHOP"""
        try:
            # Get unique orders that have checkouts from this shop
            orders = Order.objects.filter(
                checkout__cart_item__product__shop=shop
            ).distinct().order_by('-created_at')[:limit]
            
            order_list = []
            for order in orders:
                # Get this shop's specific checkout status for this order
                shop_checkouts = Checkout.objects.filter(
                    Q(cart_item__product__shop=shop) | Q(direct_shop_id=str(shop.id)),
                    order=order
                )
                
                # Determine shop's status based on checkouts
                if shop_checkouts.filter(status='completed').exists():
                    shop_status = 'completed'
                elif shop_checkouts.filter(status='pending').exists():
                    shop_status = 'pending'
                else:
                    shop_status = 'processing'
                
                # Calculate shop's total from checkouts
                shop_total = Decimal('0.00')
                for checkout in shop_checkouts:
                    if checkout.direct_product_price:
                        shop_total += checkout.direct_product_price * checkout.quantity
                    elif checkout.cart_item and checkout.cart_item.variant:
                        shop_total += (checkout.cart_item.variant.price or Decimal('0.00')) * checkout.quantity
                    elif checkout.cart_item and checkout.cart_item.product:
                        shop_total += Decimal(str(getattr(checkout.cart_item.product, 'price', 0))) * checkout.quantity
                
                order_list.append({
                    'id': str(order.order),
                    'order_id': str(order.order),
                    'customer_name': order.shipping_address.recipient_name if order.shipping_address else 'Unknown',
                    'customer_email': order.shipping_address.user.email if order.shipping_address and order.shipping_address.user else 'N/A',
                    'status': shop_status,  # 👈 Per-shop status, not global order status
                    'total_amount': float(shop_total),
                    'created_at': order.created_at.isoformat(),
                })
            
            return order_list
        except Exception as e:
            print(f"Error in _get_latest_orders: {str(e)}")
            return []
    
    def _get_low_stock_data(self, shop, limit=5):
        """Get low stock variants - FILTERED BY SPECIFIC SHOP"""
        try:
            low_stock_variants = Variants.objects.filter(
                product__shop=shop,
                product__upload_status='published',
                product__is_removed=False,
                is_active=True,
                quantity__gt=0,
                quantity__lte=F('critical_trigger')
            ).filter(
                critical_trigger__isnull=False
            ).select_related('product').order_by('quantity')[:limit]
            
            low_stock_items = []
            for variant in low_stock_variants:
                low_stock_items.append({
                    'id': str(variant.id),
                    'product_id': str(variant.product.id),
                    'product_name': variant.product.name,
                    'quantity': variant.quantity,
                    'critical_stock': variant.critical_trigger,
                    'sku_code': variant.sku_code,
                    'variant_title': variant.title,
                    'price': float(variant.price) if variant.price else 0,
                    'value_added_tax': float(variant.value_added_tax) if variant.value_added_tax else 0,
                    'value_added_tax_amount': float(variant.value_added_tax_amount) if variant.value_added_tax_amount else 0,
                    'price_with_vat': float(variant.price_with_vat) if variant.price else 0,
                })
            
            return low_stock_items
        except Exception as e:
            print(f"Error in _get_low_stock_data: {str(e)}")
            return []
    
    def _get_refund_data(self, shop, limit=3):
        """Get refund and dispute data - FILTERED BY SPECIFIC SHOP"""
        try:
            refunds = Refund.objects.filter(
                order_id__checkout__cart_item__product__shop=shop
            ).select_related('order_id').distinct().order_by('-requested_at')[:limit]
            
            pending_count = Refund.objects.filter(
                order_id__checkout__cart_item__product__shop=shop,
                status='pending'
            ).distinct().count()
            
            disputes_count = Refund.objects.filter(
                order_id__checkout__cart_item__product__shop=shop,
                status='dispute'
            ).distinct().count()
            
            total_count = Refund.objects.filter(
                order_id__checkout__cart_item__product__shop=shop,
            ).distinct().count()
            
            latest_refunds = [
                {
                    'id': str(refund.refund_id),
                    'reason': refund.reason,
                    'requested_amount': float(refund.total_refund_amount or 0),
                    'status': refund.status,
                    'order_id': str(refund.order_id.order),
                    'customer_note': refund.customer_note,
                    'requested_at': refund.requested_at.isoformat(),
                }
                for refund in refunds
            ]
            
            return {
                'pending_count': pending_count,
                'disputes_count': disputes_count,
                'total_count': total_count,
                'latest': latest_refunds,
            }
        except Exception as e:
            print(f"Error in _get_refund_data: {str(e)}")
            return {
                'pending_count': 0,
                'disputes_count': 0,
                'total_count': 0,
                'latest': [],
            }
    
    def _get_shop_performance_data(self, shop):
        """Get shop performance metrics - FILTERED BY SPECIFIC SHOP"""
        try:
            # Only for this specific shop
            reviews = Review.objects.filter(shop=shop)
            average_rating = reviews.aggregate(avg_rating=Avg('average_rating'))['avg_rating'] or 0
            
            # Total followers - only for this shop
            total_followers = ShopFollow.objects.filter(shop=shop).count()
            
            # Product counts - only for this shop
            total_products = Product.objects.filter(shop=shop, is_removed=False).count()
            active_products = Product.objects.filter(
                shop=shop,
                upload_status='published',
                is_removed=False
            ).count()
            draft_products = Product.objects.filter(
                shop=shop,
                upload_status='draft',
                is_removed=False
            ).count()
            
            # Get total VAT collected from variants (for information purposes only)
            total_vat_collected = Variants.objects.filter(
                product__shop=shop,
                product__is_removed=False,
                is_active=True
            ).aggregate(
                total_vat=Sum('value_added_tax_amount')
            )['total_vat'] or Decimal('0.00')
            
            # Completed orders count for this shop
            completed_orders_count = Checkout.objects.filter(
                Q(cart_item__product__shop=shop) | Q(direct_shop_id=str(shop.id)),
                status='completed'
            ).values('order').distinct().count()
            
            return {
                'average_rating': round(float(average_rating), 1),
                'total_reviews': reviews.count(),
                'total_followers': total_followers,
                'total_products': total_products,
                'active_products': active_products,
                'draft_products': draft_products,
                'total_vat_collected': float(total_vat_collected),
                'completed_orders': completed_orders_count,
            }
        except Exception as e:
            print(f"Error in _get_shop_performance_data: {str(e)}")
            return {
                'average_rating': 0,
                'total_reviews': 0,
                'total_followers': 0,
                'total_products': 0,
                'active_products': 0,
                'draft_products': 0,
                'total_vat_collected': 0,
                'completed_orders': 0,
            }
    
    def _get_report_data(self, shop):
        """Get report and notification data - FILTERED BY SPECIFIC SHOP"""
        try:
            # Active reports against this specific shop
            active_reports = Report.objects.filter(
                reported_shop=shop,
                status__in=['pending', 'under_review']
            ).count()
            
            total_reports = Report.objects.filter(reported_shop=shop).count()
            
            # Latest notifications for the shop owner
            if shop.customer and shop.customer.customer:
                user = shop.customer.customer
                notifications = Notification.objects.filter(
                    user=user,
                    created_at__gte=timezone.now() - timedelta(days=7)
                ).order_by('-created_at')[:3]
                
                latest_notifications = [
                    {
                        'id': str(notification.id),
                        'title': notification.title,
                        'message': notification.message,
                        'type': notification.type,
                        'time': self._get_time_ago(notification.created_at),
                        'is_read': notification.is_read,
                    }
                    for notification in notifications
                ]
            else:
                latest_notifications = []
            
            return {
                'active_count': active_reports,
                'total_count': total_reports,
                'latest_notifications': latest_notifications,
            }
        except Exception as e:
            print(f"Error in _get_report_data: {str(e)}")
            return {
                'active_count': 0,
                'total_count': 0,
                'latest_notifications': [],
            }
    
    def _get_time_ago(self, date):
        """Convert datetime to human-readable time ago"""
        try:
            now = timezone.now()
            diff = now - date
            
            if diff.days > 365:
                years = diff.days // 365
                return f"{years} year{'s' if years > 1 else ''} ago"
            elif diff.days > 30:
                months = diff.days // 30
                return f"{months} month{'s' if months > 1 else ''} ago"
            elif diff.days > 0:
                return f"{diff.days} day{'s' if diff.days > 1 else ''} ago"
            elif diff.seconds > 3600:
                hours = diff.seconds // 3600
                return f"{hours} hour{'s' if hours > 1 else ''} ago"
            elif diff.seconds > 60:
                minutes = diff.seconds // 60
                return f"{minutes} minute{'s' if minutes > 1 else ''} ago"
            else:
                return "just now"
        except Exception:
            return "unknown"
    
