class CartSummaryView(APIView):
    """
    Returns a summary of the cart with total items, unique products, and total value
    """
    def get(self, request):
        user_id = request.GET.get("user_id")
        
        if not user_id:
            return Response({"error": "user_id is required"}, status=400)
        
        try:
            user = User.objects.get(pk=user_id)
        except User.DoesNotExist:
            return Response({"error": "User not found"}, status=404)
        
        try:
            cart_items = CartItem.objects.filter(user=user, is_ordered=False)\
                .select_related("product", "variant")
            
            total_items = 0
            total_value = 0
            unique_products = set()
            items_by_shop = {}
            
            for item in cart_items:
                total_items += item.quantity
                unique_products.add(item.product.id)
                
                # Calculate value based on variant price or use product min price as fallback
                if item.variant and item.variant.price:
                    item_value = item.variant.price * item.quantity
                    total_value += item_value
                elif item.product:
                    # Use min price as estimate if no variant selected
                    min_price = item.product.min_price or 0
                    item_value = min_price * item.quantity
                    total_value += item_value
                
                # Group by shop
                if item.product and item.product.shop:
                    shop_id = str(item.product.shop.id)
                    if shop_id not in items_by_shop:
                        items_by_shop[shop_id] = {
                            'shop_name': item.product.shop.name,
                            'item_count': 0,
                            'total_value': 0
                        }
                    
                    items_by_shop[shop_id]['item_count'] += item.quantity
                    if item.variant and item.variant.price:
                        items_by_shop[shop_id]['total_value'] += item.variant.price * item.quantity
                    elif item.product.min_price:
                        items_by_shop[shop_id]['total_value'] += item.product.min_price * item.quantity
            
            return Response({
                "success": True,
                "summary": {
                    "total_items": total_items,
                    "unique_products": len(unique_products),
                    "total_value": str(total_value),
                    "items_by_shop": items_by_shop
                }
            })
            
        except Exception as e:
            import traceback
            print("Error in CartSummaryView.get:", str(e))
            print(traceback.format_exc())
            return Response({
                "success": False,
                "error": "Failed to fetch cart summary",
                "details": str(e)
            }, status=500)


class BulkCartAddView(APIView):
    """
    Add multiple items to cart at once
    """
    def post(self, request):
        user_id = request.data.get("user_id")
        items = request.data.get("items", [])
        
        if not user_id:
            return Response({"error": "user_id is required"}, status=400)
        
        if not items or not isinstance(items, list):
            return Response({"error": "Items array is required"}, status=400)
        
        try:
            user = User.objects.get(pk=user_id)
        except User.DoesNotExist:
            return Response({"error": "User not found"}, status=404)
        
        results = {
            "success": [],
            "failed": []
        }
        
        for item_data in items:
            try:
                product_id = item_data.get("product_id")
                variant_id = item_data.get("variant_id")
                quantity = int(item_data.get("quantity", 1))
                
                if not product_id:
                    results["failed"].append({
                        "item": item_data,
                        "error": "Product ID is required"
                    })
                    continue
                
                # Find product
                try:
                    product = Product.objects.get(id=product_id)
                except Product.DoesNotExist:
                    results["failed"].append({
                        "item": item_data,
                        "error": "Product not found"
                    })
                    continue
                
                # Handle variant if provided
                variant = None
                if variant_id:
                    try:
                        variant = Variants.objects.get(id=variant_id, product=product, is_active=True)
                        if variant.quantity < quantity:
                            results["failed"].append({
                                "item": item_data,
                                "error": f"Only {variant.quantity} units available",
                                "available_quantity": variant.quantity
                            })
                            continue
                    except Variants.DoesNotExist:
                        results["failed"].append({
                            "item": item_data,
                            "error": "Variant not found or inactive"
                        })
                        continue
                else:
                    # Check if product has any active variants
                    if not product.variants.filter(is_active=True).exists():
                        results["failed"].append({
                            "item": item_data,
                            "error": "No active variants available for this product"
                        })
                        continue
                
                # Add to cart logic
                cart_item, created = CartItem.objects.get_or_create(
                    user=user,
                    product=product,
                    variant=variant,
                    defaults={"quantity": 0}
                )
                
                new_quantity = cart_item.quantity + quantity
                
                # Check availability
                if variant:
                    if new_quantity > variant.quantity:
                        results["failed"].append({
                            "item": item_data,
                            "error": f"Only {variant.quantity} units available",
                            "available_quantity": variant.quantity
                        })
                        continue
                else:
                    total_stock = product.total_stock
                    if new_quantity > total_stock:
                        results["failed"].append({
                            "item": item_data,
                            "error": f"Only {total_stock} units available across all variants",
                            "available_quantity": total_stock
                        })
                        continue
                
                cart_item.quantity = new_quantity
                cart_item.save()
                
                serializer = CartItemSerializer(cart_item, context={"request": request})
                results["success"].append(serializer.data)
                
            except Exception as e:
                results["failed"].append({
                    "item": item_data,
                    "error": str(e)
                })
        
        return Response({
            "success": True,
            "results": results
        })
    
class CheckoutView(viewsets.ViewSet):
    """
    Simplified Checkout ViewSet
    """
    @action(methods=["get"], detail=False)
    def getOrder(self, request):
        pass
        
    
    @action(methods=["post"], detail=False)
    def checkout(self, request):
        """
        Cart-based checkout
        Request body:
        {
            "user_id": "uuid",
            "payment_method": "cod | gcash | paymaya | paypal",
            "delivery_method": "pickup | standard",
            "delivery_address": "string"
        }
        """
        try:
            data = request.data

            user_id = data.get("user_id")
            payment_method = data.get("payment_method")
            delivery_method = data.get("delivery_method")
            delivery_address = data.get("delivery_address")

            # ---- VALIDATION ----
            if not user_id:
                return Response({"error": "user_id is required"}, status=400)

            if not payment_method:
                return Response({"error": "payment_method is required"}, status=400)

            if not delivery_address:
                return Response({"error": "delivery_address is required"}, status=400)

            try:
                user = User.objects.get(id=user_id)
            except User.DoesNotExist:
                return Response({"error": "User not found"}, status=404)

            cart_items = CartItem.objects.select_related("product").filter(user=user)

            if not cart_items.exists():
                return Response({"error": "Cart is empty"}, status=400)

            # ---- TRANSACTION ----
            with transaction.atomic():
                total_amount = Decimal("0.00")

                # Create order
                order = Order.objects.create(
                    user=user,
                    status="pending",
                    payment_method=payment_method,
                    delivery_method=delivery_method,
                    delivery_address=delivery_address,
                    total_amount=0  # temporary
                )

                for cart_item in cart_items:
                    product = cart_item.product

                    if not product:
                        continue

                    # Handle SKU-aware stock and pricing
                    if getattr(cart_item, 'sku', None) and cart_item.sku:
                        sku = cart_item.sku
                        if sku.quantity < cart_item.quantity:
                            raise Exception(f"Insufficient SKU stock for {product.name} - SKU {sku.sku_code}")
                        unit_price = sku.price if sku.price is not None else product.price
                        line_total = unit_price * cart_item.quantity
                        total_amount += line_total

                        # Deduct SKU stock
                        sku.quantity -= cart_item.quantity
                        sku.save(update_fields=['quantity'])

                        # Recalculate and sync product.quantity from SKU totals
                        try:
                            total = product.skus.filter(is_active=True).aggregate(total=Coalesce(Sum('quantity'), 0))['total']
                            product.quantity = int(total or 0)
                            product.save(update_fields=['quantity'])

                            # Debug: product state after SKU sync
                            try:
                                shop = product.shop
                                print(f"POST-CHECKOUT SKU SYNC: product={product.id} name={product.name} quantity={product.quantity} is_removed={product.is_removed} upload_status={product.upload_status} shop_verified={getattr(shop, 'verified', None)} shop_status={getattr(shop, 'status', None)}")
                            except Exception as _e:
                                print("POST-CHECKOUT SKU SYNC: failed to log product state", _e)
                        except Exception:
                            pass
                    else:
                        if product.quantity < cart_item.quantity:
                            raise Exception(f"Insufficient stock for {product.name}")

                        unit_price = product.price
                        line_total = unit_price * cart_item.quantity
                        total_amount += line_total

                        # Deduct stock
                        product.quantity -= cart_item.quantity
                        product.save(update_fields=["quantity"])

                        # Debug: product state after product stock decrement
                        try:
                            shop = product.shop
                            print(f"POST-CHECKOUT PROD DECR: product={product.id} name={product.name} quantity={product.quantity} is_removed={product.is_removed} upload_status={product.upload_status} shop_verified={getattr(shop, 'verified', None)} shop_status={getattr(shop, 'status', None)}")
                        except Exception as _e:
                            print("POST-CHECKOUT PROD DECR: failed to log product state", _e)

                    # Create checkout row
                    Checkout.objects.create(
                        order=order,
                        cart_item=cart_item,
                        quantity=cart_item.quantity,
                        total_amount=line_total,
                        status="pending"
                    )

                # Update order total
                order.total_amount = total_amount
                
                # Calculate and store transaction fee: 5% of total, capped at ₱50
                transaction_fee = min(total_amount * Decimal('0.05'), Decimal('50'))
                order.transaction_fee = float(transaction_fee)
                
                # Calculate and store shipping fee: 5% of total, capped at ₱50, only for standard delivery
                if delivery_method and delivery_method.lower() == "standard delivery":
                    shipping_fee = min(total_amount * Decimal('0.05'), Decimal('50'))
                    order.shipping_fee = float(shipping_fee)
                
                order.save(update_fields=["total_amount", "transaction_fee", "shipping_fee"])

                # Clear cart
                cart_items.delete()

            return Response({
                "success": True,
                "message": "Checkout successful",
                "order_id": str(order.order),
                "total_amount": str(order.total_amount),
                "payment_method": order.payment_method,
                "delivery_method": order.delivery_method,
                "delivery_address": order.delivery_address
            }, status=201)

        except Exception as e:
            return Response(
                {"error": "Checkout failed", "details": str(e)},
                status=500
            )



