    @action(detail=False, methods=['get'], url_path='status-counts')
    def status_counts(self, request):
        """Return counts per order status for the session user."""
        user_id = request.headers.get('X-User-Id')
        if not user_id:
            return Response({'error': 'X-User-Id header is required'}, status=status.HTTP_400_BAD_REQUEST)

        try:
            user = User.objects.get(id=user_id)
        except User.DoesNotExist:
            return Response({'error': 'User not found'}, status=status.HTTP_404_NOT_FOUND)

        try:
            processing = Order.objects.filter(user=user, status__in=['pending', 'processing']).count()
            shipped = Order.objects.filter(user=user, status='shipped').count()
            rate = Order.objects.filter(user=user, status='completed').count()
            returns = Order.objects.filter(user=user, status__in=['cancelled', 'refunded']).count()

            return Response({
                'processing': processing,
                'shipped': shipped,
                'rate': rate,
                'returns': returns
            }, status=status.HTTP_200_OK)
        except Exception as e:
            logger.exception('Error computing status counts: %s', e)
            return Response({'error': str(e)}, status=status.HTTP_500_INTERNAL_SERVER_ERROR)

    @action(detail=True, methods=['post'], url_path='cancel')
    def cancel(self, request, pk=None):
        """Allow buyer to cancel an order if it's still cancellable."""
        user_id = request.headers.get('X-User-Id')
        if not user_id:
            return Response({'error': 'X-User-Id header is required'}, status=status.HTTP_400_BAD_REQUEST)

        try:
            user = User.objects.get(id=user_id)
        except User.DoesNotExist:
            return Response({'error': 'User not found'}, status=status.HTTP_404_NOT_FOUND)

        try:
            order = Order.objects.get(order=pk, user=user)
        except Order.DoesNotExist:
            return Response({'error': 'Order not found'}, status=status.HTTP_404_NOT_FOUND)

        if order.status in ['shipped', 'delivered', 'completed', 'cancelled', 'refunded']:
            return Response({'error': 'Order cannot be cancelled at this stage'}, status=status.HTTP_400_BAD_REQUEST)

        try:
            order.status = 'cancelled'
            order.save()
            return Response({'success': True, 'message': 'Order cancelled successfully'}, status=status.HTTP_200_OK)
        except Exception as e:
            logger.exception('Error cancelling order: %s', e)
            return Response({'error': str(e)}, status=status.HTTP_500_INTERNAL_SERVER_ERROR)

    def retrieve(self, request, pk=None):
        """Get a single order by ID"""
        user_id = request.headers.get("X-User-Id")
        if not user_id:
            return Response(
                {"error": "User ID required"}, 
                status=status.HTTP_400_BAD_REQUEST
            )
        
        try:
            user = User.objects.get(id=user_id)
        except User.DoesNotExist:
            return Response(
                {"error": "User not found"}, 
                status=status.HTTP_404_NOT_FOUND
            )
        
        try:
            order = Order.objects.get(order=pk, user=user)
        except Order.DoesNotExist:
            return Response(
                {"error": "Order not found"}, 
                status=status.HTTP_404_NOT_FOUND
            )
        
        self._auto_complete_if_needed(order)
        self._update_order_status_from_checkouts(order)
        
        payment = Payment.objects.filter(order_id=order.order).first()
        delivery = Delivery.objects.filter(order_id=order.order).first()
        
        delivery_address = None
        if order.shipping_address:
            delivery_address = order.shipping_address.get_full_address()
        elif order.delivery_address_text:
            delivery_address = order.delivery_address_text
        
        items_data = []
        for checkout in order.checkout_set.all():
            if checkout.cart_item and checkout.cart_item.product:
                product = checkout.cart_item.product
                
                variant = checkout.cart_item.variant
                variant_title = variant.title if variant else None
                product_price = getattr(product, 'price', 0)
                variant_price_value = variant.price if variant and variant.price is not None else product_price
                variant_price = str(variant_price_value)
                variant_sku = variant.sku_code if variant else None
                
                product_images = []
                for media in product.productmedia_set.all():
                    if media.file_data:
                        url = get_media_url(media.file_data)
                        if url:
                            product_images.append({
                                'id': str(media.id),
                                'url': url,
                                'file_type': media.file_type
                            })
                
                primary_image = product_images[0] if product_images else None
                
                has_reviewed = False
                try:
                    customer_profile = Customer.objects.get(customer=user)
                    has_reviewed = Review.objects.filter(
                        customer=customer_profile,
                        product=product
                    ).exists()
                except Customer.DoesNotExist:
                    has_reviewed = False
                
                shop_picture_url = None
                if product.shop and product.shop.shop_picture:
                    shop_picture_url = get_media_url(product.shop.shop_picture)
                
                item_status = checkout.status if hasattr(checkout, 'status') else 'pending'
                
                item_data = {
                    'checkout_id': str(checkout.id),
                    'cart_item_id': str(checkout.cart_item.id) if checkout.cart_item else None,
                    'product_id': str(product.id),
                    'product_name': product.name,
                    'product_description': product.description,
                    'product_condition': product.condition,
                    'product_status': product.status,
                    'variant_id': str(variant.id) if variant else None,
                    'variant_title': variant_title,
                    'variant_sku': variant_sku,
                    'shop_id': str(product.shop.id) if product.shop else None,
                    'shop_name': product.shop.name if product.shop else None,
                    'shop_picture': shop_picture_url,
                    'seller_username': product.customer.customer.username if product.customer and product.customer.customer else None,
                    'quantity': checkout.quantity,
                    'price': variant_price,
                    'subtotal': str(checkout.total_amount),
                    'status': item_status,
                    'item_status': item_status,
                    'remarks': checkout.remarks,
                    'purchased_at': checkout.created_at.isoformat() if hasattr(checkout.created_at, 'isoformat') else checkout.created_at,
                    'product_images': product_images,
                    'primary_image': primary_image,
                    'voucher_applied': {
                        'id': str(checkout.voucher.id),
                        'name': checkout.voucher.name,
                        'code': checkout.voucher.code
                    } if checkout.voucher else None,
                    'can_review': (item_status == 'delivered' or item_status == 'completed') and not has_reviewed,
                    'shipping_fee': str(getattr(checkout, 'shipping_fee', 0.00)),
                }
                items_data.append(item_data)
            else:
                item_status = checkout.status if hasattr(checkout, 'status') else 'pending'
                item_data = {
                    'checkout_id': str(checkout.id),
                    'cart_item_id': None,
                    'product_id': None,
                    'product_name': 'Item no longer available',
                    'product_description': '',
                    'product_condition': '',
                    'product_status': '',
                    'variant_id': None,
                    'variant_title': None,
                    'variant_sku': None,
                    'shop_id': None,
                    'shop_name': 'Unknown Shop',
                    'shop_picture': None,
                    'seller_username': None,
                    'quantity': checkout.quantity,
                    'price': '0.00',
                    'subtotal': str(checkout.total_amount),
                    'status': item_status,
                    'item_status': item_status,
                    'remarks': checkout.remarks,
                    'purchased_at': checkout.created_at.isoformat() if hasattr(checkout.created_at, 'isoformat') else checkout.created_at,
                    'product_images': [],
                    'primary_image': None,
                    'voucher_applied': None,
                    'can_review': False
                }
                items_data.append(item_data)
        
        order_data = {
            'order_id': str(order.order),
            'status': order.status,
            'total_amount': str(order.total_amount),
            'payment_method': order.payment_method,
            'delivery_method': order.delivery_method,
            'delivery_address': delivery_address,
            'created_at': order.created_at.isoformat(),
            'payment_status': payment.status if payment else None,
            'delivery_status': delivery.status if delivery else None,
            'delivery_rider': delivery.rider.rider.username if delivery and delivery.rider and delivery.rider.rider else None,
            'pickup_date': order.pickup_date.isoformat() if order.pickup_date else None,
            'items': items_data
        }
        
        return Response(order_data)

            
    @action(detail=True, methods=['get'], url_path='view-order')
    def view_order_detail(self, request, pk=None):
        """
        Get detailed information for a specific order (for view-order page)
        """
        user_id = request.headers.get('X-User-Id')
        if not user_id:
            return Response(
                {'error': 'X-User-Id header is required'},
                status=status.HTTP_400_BAD_REQUEST
            )
        
        try:
            user = User.objects.get(id=user_id)
        except User.DoesNotExist:
            return Response(
                {'error': 'User not found'},
                status=status.HTTP_404_NOT_FOUND
            )
        except Exception as exc:
            logger.exception('view_order_detail user lookup failed: %s', exc)
            return Response({'error': 'Invalid user ID'}, status=status.HTTP_400_BAD_REQUEST)
        
        try:
            order = Order.objects.get(order=pk, user=user)
        except Order.DoesNotExist:
            return Response(
                {'error': 'Order not found'},
                status=status.HTTP_404_NOT_FOUND
            )
        except Exception as exc:
            logger.exception('view_order_detail order lookup failed: %s', exc)
            return Response({'error': 'Invalid order identifier'}, status=status.HTTP_400_BAD_REQUEST)
        
        # Update order status based on checkout items
        self._update_order_status_from_checkouts(order)
        self._auto_complete_if_needed(order)
        
        try:
            payment = Payment.objects.filter(order_id=order.order).first()
            delivery = Delivery.objects.filter(order_id=order.order).first()

            proof_images = []
            if delivery:
                proofs = Proof.objects.filter(delivery=delivery).order_by('-uploaded_at')
                for proof in proofs:
                    proof_images.append({
                        'id': str(proof.id),
                        'file_url': get_media_url(proof.file_data),
                        'file_type': proof.file_type,
                        'uploaded_at': proof.uploaded_at.isoformat(),
                        'proof_type': proof.proof_type,
                        'proof_type_display': proof.get_proof_type_display(),
                    })
            
            delivery_address = None
            if order.shipping_address:
                delivery_address = order.shipping_address.get_full_address()
            elif order.delivery_address_text:
                delivery_address = order.delivery_address_text
            
            full_name = None
            if hasattr(user, 'full_name') and user.full_name:
                full_name = user.full_name
            else:
                first = getattr(user, 'first_name', '') or ''
                last = getattr(user, 'last_name', '') or ''
                full_name = (f"{first} {last}".strip() if (first or last) else getattr(user, 'username', None))
            
            shipping_info = {
                'logistics_carrier': order.delivery_method if order.delivery_method else 'Standard Delivery',
                'tracking_number': f"PH{order.created_at.strftime('%y%m%d')}{str(order.order)[:6].upper()}" if order.order else None,
                'delivery_method': order.delivery_method,
                'estimated_delivery': (order.created_at + timedelta(days=3)).strftime('%m/%d/%Y') if order.created_at else None,
            }
            
            delivery_address_info = {
                'recipient_name': full_name or getattr(user, 'username', ''),
                'phone_number': user.phone_number if hasattr(user, 'phone_number') else '(+63) 912 345 6789',
                'address': delivery_address,
                'address_details': {
                    'street': order.shipping_address.street if order.shipping_address and hasattr(order.shipping_address, 'street') else '',
                    'barangay': order.shipping_address.barangay if order.shipping_address and hasattr(order.shipping_address, 'barangay') else '',
                    'city': order.shipping_address.city if order.shipping_address and hasattr(order.shipping_address, 'city') else '',
                    'province': order.shipping_address.province if order.shipping_address and hasattr(order.shipping_address, 'province') else '',
                    'postal_code': order.shipping_address.postal_code if order.shipping_address and hasattr(order.shipping_address, 'postal_code') else '',
                }
            }
            
            items_data = []
            total_items = 0
            subtotal = 0
            
            for checkout in order.checkout_set.all():
                if checkout.cart_item and checkout.cart_item.product:
                    product = checkout.cart_item.product
                    total_items += checkout.quantity
                    
                    variant = checkout.cart_item.variant
                    variant_title = variant.title if variant else 'Default'
                    product_price = getattr(product, 'price', 0)
                    variant_price_value = variant.price if variant and variant.price is not None else product_price
                    variant_price = str(variant_price_value)
                    if variant and variant.compare_price is not None:
                        variant_original_price = str(variant.compare_price)
                    else:
                        try:
                            variant_original_price = str(float(variant_price_value) * 1.1)
                        except (TypeError, ValueError):
                            variant_original_price = '0.0'
                    variant_is_refundable = variant.is_refundable if variant else getattr(product, 'is_refundable', False)
                    
                    subtotal += float(checkout.total_amount or 0)
                    
                    product_serializer = ProductSerializer(product, context={'request': request})
                    product_data = product_serializer.data
                    
                    product_images = product_data.get('media_files', [])
                    primary_image = product_data.get('primary_image')
                    
                    shop_info = {}
                    if product.shop:
                        shop_picture_url = None
                        if product.shop.shop_picture:
                            try:
                                shop_picture_url = get_media_url(product.shop.shop_picture)
                            except Exception:
                                shop_picture_url = None
                        
                        followers_count = ShopFollow.objects.filter(shop=product.shop).count()
                        
                        shop_info = {
                            'id': str(product.shop.id),
                            'name': product.shop.name,
                            'picture': shop_picture_url,
                            'description': product.shop.description if hasattr(product.shop, 'description') else '',
                            'items_count': product.shop.products.count() if product.shop else 0,
                            'followers_count': followers_count,
                            'is_choices': False,
                            'is_new': False,
                        }
                    
                    # Check if user has already reviewed this product
                    has_reviewed = False
                    try:
                        customer_profile = Customer.objects.get(customer=user)
                        has_reviewed = Review.objects.filter(
                            customer=customer_profile,
                            product=product
                        ).exists()
                    except Customer.DoesNotExist:
                        has_reviewed = False
                    
                    # Check if this item has already been refunded
                    has_refunded = False
                    try:
                        has_refunded = Refund.objects.filter(
                            order_id=order,
                            items__checkout=checkout,
                            status__in=['completed', 'approved']
                        ).exists()
                    except Exception:
                        has_refunded = False
                    
                    # Use checkout.status for per-item status
                    item_status = checkout.status if hasattr(checkout, 'status') else 'pending'
                    
                    # Get shop_status from OrderShopStatus
                    shop_status = 'pending'
                    if product.shop:
                        try:
                            order_shop_status = OrderShopStatus.objects.get(order=order, shop=product.shop)
                            shop_status = order_shop_status.status
                        except OrderShopStatus.DoesNotExist:
                            shop_status = 'pending'
                    
                    # Allow review and return for both 'delivered' AND 'completed' items
                    can_review = (item_status == 'delivered' or item_status == 'completed')
                    can_return = (item_status == 'delivered' or item_status == 'completed') and not has_refunded
                    
                    # If already refunded, is_refundable should be false
                    is_refundable = variant_is_refundable and not has_refunded
                    
                    item_data = {
                        'checkout_id': str(checkout.id),
                        'product_id': str(product.id),
                        'product_name': product.name,
                        'product_description': product.description,
                        'variant_id': str(variant.id) if variant else None,
                        'product_variant': variant_title,
                        'variant_sku': variant.sku_code if variant else None,
                        'quantity': checkout.quantity,
                        'price': variant_price,
                        'original_price': variant_original_price,
                        'subtotal': str(checkout.total_amount or '0.00'),
                        'status': item_status,
                        'item_status': item_status,
                        'shop_status': shop_status,
                        'purchased_at': checkout.created_at.isoformat(),
                        'product_images': product_images,
                        'primary_image': primary_image,
                        'shop_info': shop_info,
                        'can_review': can_review,
                        'can_return': can_return,
                        'has_reviewed': has_reviewed,
                        'has_refunded': has_refunded,
                        'is_refundable': is_refundable,
                        'return_deadline': (checkout.created_at + timedelta(days=14)).isoformat() if checkout.created_at else None,
                        'shipping_fee': str(getattr(checkout, 'shipping_fee', 0.00)),
                        'distance_km': getattr(checkout, 'distance_km', None),
                    }
                    items_data.append(item_data)
                else:
                    item_status = checkout.status if hasattr(checkout, 'status') else 'pending'
                    item_data = {
                        'checkout_id': str(checkout.id),
                        'cart_item_id': None,
                        'product_id': None,
                        'product_name': 'Item no longer available',
                        'product_description': '',
                        'product_condition': '',
                        'product_status': '',
                        'variant_id': None,
                        'variant_title': None,
                        'variant_sku': None,
                        'shop_id': None,
                        'shop_name': 'Unknown Shop',
                        'shop_picture': None,
                        'seller_username': None,
                        'quantity': checkout.quantity,
                        'price': '0.00',
                        'subtotal': str(checkout.total_amount),
                        'status': item_status,
                        'item_status': item_status,
                        'remarks': checkout.remarks,
                        'purchased_at': checkout.created_at.isoformat() if hasattr(checkout.created_at, 'isoformat') else checkout.created_at,
                        'product_images': [],
                        'primary_image': None,
                        'voucher_applied': None,
                        'can_review': False,
                        'can_return': False,
                        'has_reviewed': False,
                        'has_refunded': False,
                        'is_refundable': False
                    }
                    items_data.append(item_data)
            
            total_shipping_fee = 0
            shipping_fees_by_shop = {}

            if hasattr(order, 'shipping_fees_breakdown') and order.shipping_fees_breakdown:
                shipping_fees_by_shop = order.shipping_fees_breakdown
                total_shipping_fee = sum(shipping_fees_by_shop.values())
            elif hasattr(order, 'shipping_fee') and order.shipping_fee:
                total_shipping_fee = float(order.shipping_fee)

            order_summary = {
                'subtotal': str(subtotal),
                'shipping_fee': str(total_shipping_fee),
                'shipping_fees_breakdown': shipping_fees_by_shop,
                'tax': str(float(subtotal) * 0.12),
                'discount': '0.00',
                'total': str(order.total_amount),
                'transaction_fee': str(float(order.transaction_fee) if order.transaction_fee else 0.00),
                'payment_fee': str(float(order.transaction_fee) if order.transaction_fee else 0.00),
            }
            
            response_data = {
                'order': {
                    'id': str(order.order),
                    'status': order.status,
                    'status_display': self._get_status_display(order.status),
                    'status_color': self._get_status_color(order.status),
                    'created_at': order.created_at.isoformat(),
                    'updated_at': order.updated_at.isoformat() if order.updated_at else None,
                    'completed_at': order.completed_at.isoformat() if order.completed_at else None,
                    'refund_expire_date': order.refund_expire_date.isoformat() if order.refund_expire_date else None,   
                    'payment_method': order.payment_method,
                    'payment_status': payment.status if payment else None,
                    'delivery_status': delivery.status if delivery else None,
                    'delivery_rider': delivery.rider.rider.username if delivery and delivery.rider and delivery.rider.rider else None,
                    'delivery_notes': delivery.notes if delivery else None,
                    'delivery_date': (
                        (getattr(delivery, 'delivery_date', None)
                        or getattr(delivery, 'delivered_at', None)
                        or getattr(delivery, 'updated_at', None)).isoformat()
                        if delivery and (getattr(delivery, 'delivery_date', None)
                                        or getattr(delivery, 'delivered_at', None)
                                        or getattr(delivery, 'updated_at', None))
                        else None
                    ),
                    'pickup_expire_date': order.pickup_expire_date.isoformat() if order.pickup_expire_date else None,
                    'pickup_date': order.pickup_date.isoformat() if order.pickup_date else None,
                    'metadata': order.metadata if order.metadata else None,
                    'shop_statuses': {str(oss.shop.id): oss.status for oss in OrderShopStatus.objects.filter(order=order)},
                },
                'shipping_info': shipping_info,
                'delivery_address': delivery_address_info,
                'items': items_data,
                'order_summary': order_summary,
                'summary_counts': {
                    'total_items': total_items,
                    'total_unique_items': len(items_data),
                },
                'timeline': self._get_order_timeline(order, delivery, payment),
                'actions': {
                    'can_cancel': order.status in ['pending', 'processing'],
                    'can_track': order.status in ['shipped', 'delivered', 'completed', 'partially_delivered'],
                    'can_review': any(item['can_review'] for item in items_data),
                    'can_return': any(item['can_return'] for item in items_data),
                    'can_contact_seller': True,
                    'can_buy_again': True,
                },
                'proof_images': proof_images,
            }
            
            return Response(response_data)
        
        except Exception as exc:
            logger.exception('Unhandled exception in view_order_detail for order %s user %s: %s', pk, user_id, exc)
            return Response({'error': 'An internal error occurred while fetching the order'}, status=status.HTTP_500_INTERNAL_SERVER_ERROR)



    def _get_item_status(self, order, checkout):
        """Determine the correct status for an item"""
        if checkout.status == 'cancelled':
            return checkout.status
        return checkout.status if hasattr(checkout, 'status') else order.status
    
    def _get_status_display(self, status):
        status_map = {
            'pending': 'Pending',
            'processing': 'Processing',
            'shipped': 'Shipped',
            'delivered': 'Delivered',
            'partially_delivered': 'Partially Delivered',
            'completed': 'Completed',
            'cancelled': 'Cancelled',
            'refunded': 'Refunded',
        }
        return status_map.get(status, status)
    
    def _get_status_color(self, status):
        color_map = {
            'pending': '#F59E0B',
            'processing': '#F59E0B',
            'shipped': '#3B82F6',
            'delivered': '#10B981',
            'partially_delivered': '#F97316',
            'completed': '#10B981',
            'cancelled': '#EF4444',
            'refunded': '#EF4444',
        }
        return color_map.get(status, '#6B7280')
    
    def _get_order_timeline(self, order, delivery, payment):
        """Generate timeline events for the order"""
        timeline = []
        
        timeline.append({
            'event': 'Order Placed',
            'date': order.created_at.isoformat(),
            'description': 'Your order has been received',
            'icon': 'checkmark-circle',
            'color': '#10B981',
            'completed': True,
        })
        
        if payment and payment.status == 'completed':
            timeline.append({
                'event': 'Payment Confirmed',
                'date': payment.updated_at.isoformat() if payment.updated_at else payment.created_at.isoformat(),
                'description': 'Payment has been confirmed',
                'icon': 'card',
                'color': '#10B981',
                'completed': True,
            })
        
        shops_involved = set()
        for checkout in order.checkout_set.all():
            if checkout.cart_item and checkout.cart_item.product and checkout.cart_item.product.shop:
                shops_involved.add(checkout.cart_item.product.shop.name)
            elif hasattr(checkout, 'direct_shop_name') and checkout.direct_shop_name:
                shops_involved.add(checkout.direct_shop_name)
        
        shop_count = len(shops_involved)
        shop_names = ', '.join(list(shops_involved)) if shops_involved else 'Seller'
        
        if order.status in ['processing', 'shipped', 'delivered', 'partially_delivered', 'completed']:
            timeline.append({
                'event': 'Order Processed',
                'date': order.updated_at.isoformat() if order.updated_at else order.created_at.isoformat(),
                'description': f'{shop_count} seller(s) are preparing your order: {shop_names}',
                'icon': 'package',
                'color': '#10B981',
                'completed': True,
            })
        
        if order.status in ['shipped', 'delivered', 'partially_delivered', 'completed']:
            shipped_date = delivery.created_at if delivery else order.updated_at
            timeline.append({
                'event': 'Shipped',
                'date': shipped_date.isoformat() if shipped_date else None,
                'description': f'Your order has been shipped from {shop_names}',
                'icon': 'truck',
                'color': '#10B981',
                'completed': True,
            })
        
        if order.status in ['delivered', 'partially_delivered', 'completed']:
            delivered_date = (
                (getattr(delivery, 'delivery_date', None)
                or getattr(delivery, 'delivered_at', None)
                or getattr(delivery, 'updated_at', None))
                if delivery else order.updated_at
            )
            delivery_status_text = 'Your order has been delivered' if order.status == 'delivered' else 'Some items have been delivered'
            timeline.append({
                'event': 'Delivery Status',
                'date': delivered_date.isoformat() if delivered_date else None,
                'description': f'{delivery_status_text} from {shop_names}',
                'icon': 'checkmark-done',
                'color': '#10B981',
                'completed': order.status == 'delivered',
            })
        
        if order.status == 'completed':
            timeline.append({
                'event': 'Completed',
                'date': order.updated_at.isoformat() if order.updated_at else None,
                'description': 'Order completed successfully',
                'icon': 'trophy',
                'color': '#10B981',
                'completed': True,
            })
        
        if order.status == 'pending':
            timeline.append({
                'event': 'Processing',
                'date': None,
                'description': f'Waiting for {shop_count} seller(s) to process',
                'icon': 'time',
                'color': '#F59E0B',
                'completed': False,
            })
        
        return timeline

    @action(detail=True, methods=['patch'], url_path='complete')
    def complete(self, request, pk=None):
        """Buyer can mark delivered order as completed."""
        user_id = request.headers.get('X-User-Id')
        if not user_id:
            return Response({'success': False, 'message': 'X-User-Id header is required'}, status=status.HTTP_400_BAD_REQUEST)

        try:
            order = Order.objects.get(order=pk)
        except Order.DoesNotExist:
            return Response({'success': False, 'message': 'Order not found'}, status=status.HTTP_404_NOT_FOUND)

        if str(order.user.id) != str(user_id):
            return Response({'success': False, 'message': 'Permission denied'}, status=status.HTTP_403_FORBIDDEN)

        if order.status not in ['delivered', 'picked_up']:
            return Response({
                'success': False, 
                'message': f'Order is not in a completable state. Current status: {order.status}'
            }, status=status.HTTP_400_BAD_REQUEST)

        try:
            from django.utils import timezone
            from datetime import timedelta
            
            order.status = 'completed'
            order.completed_at = timezone.now()
            order.refund_expire_date = order.completed_at + timedelta(days=1)
            order.save(update_fields=['status', 'completed_at', 'refund_expire_date'])

            # Update all OrderShopStatus for this order to 'completed'
            OrderShopStatus.objects.filter(order=order).update(
                status='completed'
            )
            print(f"✅ [COMPLETE] Order {order.order} marked as completed - all shop statuses set to 'completed'")

            delivery = Delivery.objects.filter(order=order).first()
            if delivery:
                delivery.status = 'completed'
                delivery.delivered_at = timezone.now()
                delivery.save(update_fields=['status', 'delivered_at'])

            return Response({
                'success': True, 
                'message': 'Order marked as completed successfully'
            }, status=status.HTTP_200_OK)
            
        except Exception as e:
            logger.exception('Error marking order as completed: %s', e)
            return Response({
                'success': False, 
                'message': str(e)
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)

    @action(detail=True, methods=['get'], url_path='shipping-timeline')
    def shipping_timeline(self, request, pk=None):
        """Return shipping timeline data shaped for the frontend ShippingTimelinePage"""
        user_id = request.headers.get('X-User-Id')
        if not user_id:
            return Response({'error': 'X-User-Id header is required'}, status=status.HTTP_400_BAD_REQUEST)

        try:
            user = User.objects.get(id=user_id)
            order = Order.objects.get(order=pk, user=user)
        except (User.DoesNotExist, Order.DoesNotExist):
            return Response({'error': 'Order not found or access denied'}, status=status.HTTP_404_NOT_FOUND)

        self._update_order_status_from_checkouts(order)
        
        payment = Payment.objects.filter(order_id=order.order).first()
        delivery = Delivery.objects.filter(order_id=order.order).first()

        order_info = {
            'id': str(order.order),
            'status': order.status,
            'status_display': self._get_status_display(order.status),
            'status_color': self._get_status_color(order.status),
            'created_at': order.created_at.isoformat(),
        }

        tracking_status = delivery.status if delivery else order.status
        tracking_last = delivery.updated_at.isoformat() if delivery and getattr(delivery, 'updated_at', None) else order.updated_at.isoformat() if order.updated_at else None

        status_to_progress = {
            'pending': 5,
            'processing': 30,
            'ready_for_pickup': 50,
            'shipped': 70,
            'out_for_delivery': 90,
            'delivered': 100,
            'partially_delivered': 85,
            'completed': 100,
            'cancelled': 0,
            'refunded': 0,
        }

        progress = status_to_progress.get(tracking_status, 0)

        tracking = {
            'tracking_number': f"PH{order.created_at.strftime('%y%m%d')}{str(order.order)[:6].upper()}" if order.order else None,
            'status': tracking_status,
            'last_update': tracking_last,
            'progress_percentage': progress,
            'estimated_delivery': (order.created_at + timedelta(days=3)).strftime('%m/%d/%Y') if order.created_at else None,
            'delivery_date': delivery.delivery_date.isoformat() if delivery and getattr(delivery, 'delivery_date', None) else None,
        }

        from_address = None
        first_item = order.checkout_set.filter(cart_item__product__shop__isnull=False).select_related('cart_item__product__shop').first()
        if first_item and first_item.cart_item and first_item.cart_item.product and first_item.cart_item.product.shop:
            shop = first_item.cart_item.product.shop
            from_address = {
                'shop_name': shop.name,
                'address': shop.street + ', ' + shop.city if shop else '',
                'contact': shop.contact_number if shop else '',
            }

        to_address = {
            'recipient': None,
            'phone': None,
            'address': None,
        }
        if order.shipping_address:
            to_address = {
                'recipient': order.shipping_address.recipient_name,
                'phone': order.shipping_address.recipient_phone,
                'address': order.shipping_address.get_full_address(),
            }
        elif order.delivery_address_text:
            to_address['address'] = order.delivery_address_text

        shipping_info = {
            'carrier': {
                'name': order.delivery_method or 'Standard Delivery',
                'logo': None,
                'contact': {
                    'phone': None,
                    'website': None,
                    'email': None,
                },
                'estimated_delivery': (order.created_at + timedelta(days=3)).strftime('%m/%d/%Y') if order.created_at else None,
                'service_type': order.delivery_method,
            },
            'from_address': from_address,
            'to_address': to_address,
            'package': {
                'weight': None,
                'dimensions': None,
                'package_type': None,
                'insurance_value': None,
                'reference_number': tracking['tracking_number'],
            }
        }

        package_items = []
        total_value = 0
        total_items = 0
        for checkout in order.checkout_set.all():
            if checkout.cart_item and checkout.cart_item.product:
                prod = checkout.cart_item.product
                qty = checkout.quantity
                
                variant = checkout.cart_item.variant
                product_price = getattr(prod, 'price', 0)
                price = float(variant.price) if variant and variant.price is not None else float(product_price or 0)
                
                val = price * qty
                package_items.append({
                    'name': prod.name,
                    'variant': variant.title if variant else 'Default',
                    'quantity': qty, 
                    'value': str(val)
                })
                total_value += val
                total_items += qty

        package_contents = {
            'total_items': total_items,
            'items': package_items,
            'total_value': str(total_value)
        }

        rider_info = None
        if delivery and delivery.rider and getattr(delivery.rider, 'rider', None):
            r = delivery.rider.rider
            rider_info = {
                'name': f"{r.first_name} {r.last_name}".strip(),
                'phone': getattr(r, 'contact_number', None),
                'vehicle': getattr(r, 'vehicle_type', None),
                'last_seen': getattr(r, 'last_status_update', None).isoformat() if getattr(r, 'last_status_update', None) else None,
                'eta': tracking['estimated_delivery']
            }

        raw_timeline = self._get_order_timeline(order, delivery, payment)
        mapped_timeline = []
        for ev in raw_timeline:
            mapped_timeline.append({
                'event': ev.get('event'),
                'description': ev.get('description'),
                'date': ev.get('date'),
                'location': ev.get('location', ''),
                'status': 'completed' if ev.get('completed') else 'pending',
                'icon': ev.get('icon')
            })

        data = {
            'order': order_info,
            'tracking': tracking,
            'shipping_info': shipping_info,
            'timeline': mapped_timeline,
            'package_contents': package_contents,
            'rider_info': rider_info,
            'actions': {
                'can_contact_rider': delivery is not None and getattr(delivery, 'rider', None) is not None,
                'can_change_address': False,
                'can_reschedule': False,
                'can_view_proof': False,
            }
        }

        return Response(data, status=status.HTTP_200_OK)

    @action(detail=True, methods=['get'], url_path='get-rider-info')
    def get_rider_info(self, request, pk=None):
        """Return rider(s) assigned to deliveries for an order."""
        user_id = request.headers.get('X-User-Id')
        if not user_id:
            return Response({'error': 'X-User-Id header is required'}, status=status.HTTP_400_BAD_REQUEST)

        try:
            user = User.objects.get(id=user_id)
            order = Order.objects.get(order=pk, user=user)
        except (User.DoesNotExist, Order.DoesNotExist):
            return Response({'error': 'Order not found or access denied'}, status=status.HTTP_404_NOT_FOUND)

        deliveries = Delivery.objects.filter(order=order).select_related('rider')
        riders_data = []
        
        for delivery in deliveries:
            if delivery.rider:
                rider = delivery.rider
                riders_data.append({
                    "id": str(rider.rider_id),
                    "rider_id": str(rider.rider_id),
                    "user": {
                        "id": str(rider.rider.id),
                        "first_name": rider.rider.first_name if rider.rider else '',
                        "last_name": rider.rider.last_name if rider.rider else '',
                        "phone": rider.rider.contact_number if rider.rider else ''
                    }
                })

        return Response({
            "success": True, 
            "order_id": str(order.order), 
            "riders": riders_data
        })

    @action(detail=True, methods=['post'], url_path='cancel-items')
    def cancel_items(self, request, pk=None):
        """
        Cancel specific items from an order (not the entire order)
        Expected payload: {"checkout_ids": ["checkout_id_1", "checkout_id_2"]}
        """
        from django.utils import timezone
        from decimal import Decimal
        
        user_id = request.headers.get('X-User-Id')
        if not user_id:
            return Response({'error': 'X-User-Id header is required'}, status=status.HTTP_400_BAD_REQUEST)

        try:
            user = User.objects.get(id=user_id)
        except User.DoesNotExist:
            return Response({'error': 'User not found'}, status=status.HTTP_404_NOT_FOUND)

        try:
            order = Order.objects.get(order=pk, user=user)
        except Order.DoesNotExist:
            return Response({'error': 'Order not found'}, status=status.HTTP_404_NOT_FOUND)

        checkout_ids = request.data.get('checkout_ids', [])
        if not checkout_ids:
            return Response({'error': 'checkout_ids array is required'}, status=status.HTTP_400_BAD_REQUEST)

        # Allow cancellation for pending orders only
        if order.status not in ['pending', 'processing']:
            return Response({
                'error': f'Cannot cancel items for order with status: {order.status}',
                'success': False
            }, status=status.HTTP_400_BAD_REQUEST)

        try:
            checkouts = Checkout.objects.filter(
                order=order,
                id__in=checkout_ids
            )
            
            if not checkouts.exists():
                return Response({
                    'error': 'No valid checkout items found to cancel',
                    'success': False
                }, status=status.HTTP_404_NOT_FOUND)

            cancelled_count = 0
            cancelled_items = []
            cancelled_total = Decimal('0')
            affected_shops = set()  # Track which shops have cancelled items
            
            for checkout in checkouts:
                # Only allow cancelling items with pending status
                if checkout.status != 'pending':
                    continue
                    
                checkout.status = 'cancelled'
                checkout.save(update_fields=['status'])
                cancelled_count += 1
                cancelled_items.append(str(checkout.id))
                
                # Track the shop for this checkout
                shop_id = None
                if checkout.cart_item and checkout.cart_item.product and checkout.cart_item.product.shop:
                    shop_id = checkout.cart_item.product.shop.id
                elif hasattr(checkout, 'direct_shop_id') and checkout.direct_shop_id:
                    shop_id = checkout.direct_shop_id
                
                if shop_id:
                    affected_shops.add(shop_id)
                
                if checkout.total_amount:
                    cancelled_total += checkout.total_amount
                
                # Restore stock
                if checkout.cart_item and checkout.cart_item.variant:
                    variant = checkout.cart_item.variant
                    variant.quantity += checkout.quantity
                    variant.save(update_fields=['quantity'])
                elif checkout.cart_item and checkout.cart_item.product:
                    product = checkout.cart_item.product
                    product.quantity += checkout.quantity
                    product.save(update_fields=['quantity'])
                elif hasattr(checkout, 'direct_variant_id') and checkout.direct_variant_id:
                    try:
                        variant = Variants.objects.get(id=checkout.direct_variant_id)
                        variant.quantity += checkout.quantity
                        variant.save(update_fields=['quantity'])
                    except Variants.DoesNotExist:
                        pass
            
            # Update OrderShopStatus for each affected shop
            for shop_id in affected_shops:
                try:
                    from api.models import Shop
                    shop = Shop.objects.get(id=shop_id)
                    order_shop_status, created = OrderShopStatus.objects.get_or_create(
                        order=order,
                        shop=shop,
                        defaults={'status': 'cancelled'}
                    )
                    
                    # Check if all items from this shop are cancelled
                    shop_checkouts = Checkout.objects.filter(
                        Q(order=order, cart_item__product__shop=shop) |
                        Q(order=order, direct_shop_id=str(shop.id))
                    )
                    
                    all_cancelled = all(c.status == 'cancelled' for c in shop_checkouts)
                    
                    if all_cancelled:
                        order_shop_status.status = 'cancelled'
                        order_shop_status.save(update_fields=['status'])
                        print(f"✅ Shop {shop.name} status updated to 'cancelled' for order {order.order}")
                    else:
                        # If some items are still pending, keep as pending
                        has_pending = any(c.status == 'pending' for c in shop_checkouts)
                        if has_pending and order_shop_status.status != 'pending':
                            order_shop_status.status = 'pending'
                            order_shop_status.save(update_fields=['status'])
                            print(f"✅ Shop {shop.name} status updated to 'pending' (some items pending) for order {order.order}")
                except Shop.DoesNotExist:
                    pass
            
            if cancelled_total > 0:
                new_total = order.total_amount - cancelled_total
                if new_total < 0:
                    new_total = Decimal('0')
                order.total_amount = new_total
                order.save(update_fields=['total_amount'])
            
            # Update order status based on remaining checkouts
            self._update_order_status_from_checkouts(order)
            
            remaining_checkouts = Checkout.objects.filter(order=order).exclude(status='cancelled')
            if remaining_checkouts.count() == 0:
                order.status = 'cancelled'
                order.save(update_fields=['status'])
                message = 'All items cancelled. Order has been cancelled.'
            else:
                message = f'{cancelled_count} item(s) cancelled successfully.'

            return Response({
                'success': True,
                'message': message,
                'cancelled_count': cancelled_count,
                'cancelled_items': cancelled_items,
                'updated_total': float(order.total_amount)
            }, status=status.HTTP_200_OK)
            
        except Exception as e:
            logger.exception('Error cancelling items: %s', e)
            return Response({
                'error': str(e),
                'success': False
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
            
    @action(detail=True, methods=['post'], url_path='complete-shop-item')
    def complete_shop_item(self, request, pk=None):
        """Buyer can mark a specific item as completed/received"""
        print(f"🔥 [complete_item] Request received for order {pk}")
        print(f"🔥 Request data: {request.data}")
        print(f"🔥 Headers: {request.headers.get('X-User-Id')}")
        
        user_id = request.headers.get('X-User-Id')
        if not user_id:
            return Response({'success': False, 'message': 'X-User-Id header is required'}, status=status.HTTP_400_BAD_REQUEST)

        try:
            order = Order.objects.get(order=pk)
        except Order.DoesNotExist:
            return Response({'success': False, 'message': 'Order not found'}, status=status.HTTP_404_NOT_FOUND)

        if str(order.user.id) != str(user_id):
            return Response({'success': False, 'message': 'Permission denied'}, status=status.HTTP_403_FORBIDDEN)

        checkout_id = request.data.get('checkout_id')
        print(f"🔥 checkout_id: {checkout_id}")
        
        if not checkout_id:
            return Response({'success': False, 'message': 'checkout_id is required'}, status=status.HTTP_400_BAD_REQUEST)

        try:
            checkout = Checkout.objects.get(id=checkout_id, order=order)
            print(f"🔥 Found checkout: {checkout.id}, status: {checkout.status}")
        except Checkout.DoesNotExist:
            return Response({'success': False, 'message': 'Item not found'}, status=status.HTTP_404_NOT_FOUND)

        # Only allow completing delivered items
        if checkout.status != 'delivered':
            return Response({
                'success': False, 
                'message': f'Item cannot be completed. Current status: {checkout.status}'
            }, status=status.HTTP_400_BAD_REQUEST)

        try:
            from django.utils import timezone
            from datetime import timedelta
            
            # Mark this checkout as completed
            checkout.status = 'completed'
            checkout.save(update_fields=['status'])
            print(f"✅ Checkout {checkout.id} marked as completed")

            # Get shop_id from request or from checkout
            shop_id = request.data.get('shop_id')
            if not shop_id and checkout.cart_item and checkout.cart_item.product and checkout.cart_item.product.shop:
                shop_id = str(checkout.cart_item.product.shop.id)
            elif not shop_id and hasattr(checkout, 'direct_shop_id') and checkout.direct_shop_id:
                shop_id = checkout.direct_shop_id
            
            # Update OrderShopStatus for this shop
            if shop_id:
                try:
                    from api.models import Shop, OrderShopStatus
                    shop = Shop.objects.get(id=shop_id)
                    order_shop_status, created = OrderShopStatus.objects.get_or_create(
                        order=order,
                        shop=shop,
                        defaults={'status': 'completed'}
                    )
                    if not created and order_shop_status.status == 'delivered':
                        order_shop_status.status = 'completed'
                        order_shop_status.save(update_fields=['status'])
                        print(f"✅ OrderShopStatus for {shop.name} updated to 'completed'")
                    elif created:
                        print(f"✅ Created new OrderShopStatus for {shop.name} with status 'completed'")
                except Shop.DoesNotExist:
                    print(f"⚠️ Shop {shop_id} not found")
            else:
                print(f"⚠️ No shop_id found for checkout {checkout.id}")

            # Update order status based on all checkouts
            self._update_order_status_from_checkouts(order)

            # Check if all items are completed
            all_completed = all(c.status == 'completed' for c in Checkout.objects.filter(order=order))
            print(f"🔥 All items completed: {all_completed}")

            if all_completed:
                order.status = 'completed'
                order.completed_at = timezone.now()
                order.refund_expire_date = order.completed_at + timedelta(days=1)
                order.save(update_fields=['status', 'completed_at', 'refund_expire_date'])
                print(f"✅ Order {order.order} marked as completed")

            return Response({
                'success': True, 
                'message': 'Item marked as received successfully',
                'item_status': checkout.status,
                'order_status': order.status
            }, status=status.HTTP_200_OK)
            
        except Exception as e:
            import traceback
            traceback.print_exc()
            logger.exception('Error marking item as completed: %s', e)
            return Response({'success': False, 'message': str(e)}, status=status.HTTP_500_INTERNAL_SERVER_ERROR)

            

