class ReturnAddressViewSet(viewsets.ViewSet):
    """
    SELLER VIEW: Manage return addresses for refunds (CRUD).
    """
    def list(self, request):
        """List return addresses for a shop. Requires X-User-Id and optional X-Shop-Id or shop_id query."""
        user_id = request.headers.get('X-User-Id')
        shop_id = request.headers.get('X-Shop-Id') or request.query_params.get('shop_id')
        if not user_id:
            return Response({"error": "User ID required"}, status=status.HTTP_400_BAD_REQUEST)
        try:
            user = User.objects.get(id=user_id)
            shops = Shop.objects.filter(customer__customer=user)
            if not shops.exists():
                return Response({"results": []})
            if shop_id:
                try:
                    shop = shops.get(id=shop_id)
                except Shop.DoesNotExist:
                    return Response({"error": "Shop not found"}, status=status.HTTP_404_NOT_FOUND)
                addresses = ReturnAddress.objects.filter(shop=shop).order_by('-created_at')
            else:
                addresses = ReturnAddress.objects.filter(shop__in=shops).order_by('-created_at')

            serializer = ReturnAddressSerializer(addresses, many=True, context={'request': request})
            return Response(serializer.data)
        except User.DoesNotExist:
            return Response({"error": "User not found"}, status=status.HTTP_404_NOT_FOUND)

    def retrieve(self, request, pk=None):
        try:
            ra = ReturnAddress.objects.get(id=pk)
            serializer = ReturnAddressSerializer(ra, context={'request': request})
            return Response(serializer.data)
        except ReturnAddress.DoesNotExist:
            return Response({"error": "Return address not found"}, status=status.HTTP_404_NOT_FOUND)

    def create(self, request):
        """Create a return address. Requires X-User-Id and X-Shop-Id (or refund_id to infer shop)."""
        user_id = request.headers.get('X-User-Id')
        if not user_id:
            return Response({"error": "User ID required"}, status=status.HTTP_400_BAD_REQUEST)
        try:
            user = User.objects.get(id=user_id)

            # Resolve shop: prefer header/query, else try refund
            shop_id = request.headers.get('X-Shop-Id') or request.data.get('shop_id') or request.query_params.get('shop_id')
            shop = None
            if not shop_id and request.data.get('refund_id'):
                try:
                    refund = Refund.objects.get(refund_id=request.data.get('refund_id'))
                    shop_ids = list(
                        Checkout.objects.filter(
                            order=refund.order_id,
                            cart_item__product__shop__isnull=False,
                        ).values_list('cart_item__product__shop_id', flat=True).distinct()
                    )
                    if len(shop_ids) == 1:
                        shop = Shop.objects.get(id=shop_ids[0])
                except Exception:
                    pass

            if shop_id and not shop:
                try:
                    shop = Shop.objects.get(id=shop_id)
                except Shop.DoesNotExist:
                    return Response({"error": "Shop not found"}, status=status.HTTP_404_NOT_FOUND)

            if not shop:
                return Response({"error": "Shop required"}, status=status.HTTP_400_BAD_REQUEST)

            # Authorization check: user must be shop owner
            if not shop.customer or str(shop.customer.customer.id) != str(user.id):
                return Response({"error": "Not authorized for this shop"}, status=status.HTTP_403_FORBIDDEN)

            required = ['recipient_name', 'contact_number', 'country', 'province', 'city', 'barangay', 'street', 'zip_code']
            missing = [f for f in required if not request.data.get(f)]
            if missing:
                return Response({"error": f"Missing fields: {', '.join(missing)}"}, status=status.HTTP_400_BAD_REQUEST)

            ra = ReturnAddress.objects.create(
                refund=Refund.objects.get(refund_id=request.data.get('refund_id')) if request.data.get('refund_id') else None,
                shop=shop,
                seller=user,
                recipient_name=request.data.get('recipient_name'),
                contact_number=request.data.get('contact_number'),
                country=request.data.get('country'),
                province=request.data.get('province'),
                city=request.data.get('city'),
                barangay=request.data.get('barangay'),
                street=request.data.get('street'),
                zip_code=request.data.get('zip_code'),
                notes=request.data.get('notes', ''),
                created_by=user
            )

            serializer = ReturnAddressSerializer(ra, context={'request': request})
            return Response(serializer.data, status=status.HTTP_201_CREATED)

        except User.DoesNotExist:
            return Response({"error": "User not found"}, status=status.HTTP_404_NOT_FOUND)

    def partial_update(self, request, pk=None):
        user_id = request.headers.get('X-User-Id')
        if not user_id:
            return Response({"error": "User ID required"}, status=status.HTTP_400_BAD_REQUEST)
        try:
            user = User.objects.get(id=user_id)
            ra = ReturnAddress.objects.get(id=pk)
            # Authorization: ensure seller owns the shop
            if not ra.shop or not ra.shop.customer or str(ra.shop.customer.customer.id) != str(user.id):
                return Response({"error": "Not authorized to update this address"}, status=status.HTTP_403_FORBIDDEN)

            for field in ['recipient_name','contact_number','country','province','city','barangay','street','zip_code','notes']:
                if field in request.data:
                    setattr(ra, field, request.data.get(field))
            ra.save()
            serializer = ReturnAddressSerializer(ra, context={'request': request})
            return Response(serializer.data)
        except (User.DoesNotExist, ReturnAddress.DoesNotExist):
            return Response({"error": "Not found"}, status=status.HTTP_404_NOT_FOUND)

    def destroy(self, request, pk=None):
        user_id = request.headers.get('X-User-Id')
        if not user_id:
            return Response({"error": "User ID required"}, status=status.HTTP_400_BAD_REQUEST)
        try:
            user = User.objects.get(id=user_id)
            ra = ReturnAddress.objects.get(id=pk)
            if not ra.shop or not ra.shop.customer or str(ra.shop.customer.customer.id) != str(user.id):
                return Response({"error": "Not authorized to delete this address"}, status=status.HTTP_403_FORBIDDEN)
            ra.delete()
            return Response({"message": "Return address deleted"})
        except (User.DoesNotExist, ReturnAddress.DoesNotExist):
            return Response({"error": "Not found"}, status=status.HTTP_404_NOT_FOUND)


# Dispute views (placed at end for easy removal)
class DisputeViewSet(viewsets.ModelViewSet):
    """Admin-facing disputes endpoint. Allows partial updates (PATCH) and admin actions."""
    queryset = DisputeRequest.objects.all().order_by('-created_at')
    serializer_class = DisputeRequestSerializer

    def get_queryset(self):
        qs = super().get_queryset()
        status = self.request.query_params.get('status')
        refund_id = self.request.query_params.get('refund_id')
        requested_by = self.request.query_params.get('requested_by')
        if status:
            qs = qs.filter(status=status)
        if refund_id:
            # accept either refund_id string or full refund uuid
            qs = qs.filter(refund_id__refund_id=refund_id)
        if requested_by:
            qs = qs.filter(requested_by__id=requested_by)
        return qs

    def partial_update(self, request, pk=None):
        """Allow partial updates via PATCH for fields like case_category and admin_notes.
        Also accepts processed_by via `X-User-Id` header and will sanitize it.
        """
        try:
            dispute = self.get_object()

            # Only allow specific writable fields from the payload
            writable = ['case_category', 'admin_notes', 'status']
            changed = False
            for key in writable:
                if key in request.data:
                    val = request.data.get(key)
                    # Normalize case_category into a list for JSONField storage
                    if key == 'case_category':
                        if isinstance(val, str):
                            # if comma-separated string provided, split
                            if ',' in val:
                                val = [v.strip() for v in val.split(',') if v.strip()]
                            else:
                                val = [val.strip()] if val.strip() else []
                        elif isinstance(val, (list, tuple)):
                            val = [str(x).strip() for x in val if x is not None]
                        else:
                            # fallback: coerce to single-item list
                            val = [str(val)] if val is not None else []
                    setattr(dispute, key, val)
                    changed = True

            # Resolve processed_by from header if present
            user_id = request.headers.get('X-User-Id') or request.data.get('processed_by')
            if user_id:
                import re
                user_id = str(user_id).strip()
                user_id = re.sub(r"^[\'\"\u201c\u201d\u2018\u2019]+|[\'\"\u201c\u201d\u2018\u2019]+$", '', user_id)
                resolved_user = None
                try:
                    resolved_user = User.objects.get(id=user_id)
                except (User.DoesNotExist, ValueError):
                    try:
                        resolved_user = User.objects.get(username=user_id)
                    except User.DoesNotExist:
                        try:
                            resolved_user = User.objects.get(email=user_id)
                        except User.DoesNotExist:
                            resolved_user = None
                if resolved_user:
                    dispute.processed_by = resolved_user
                    changed = True

            if changed:
                dispute.save()

            return Response(DisputeRequestSerializer(dispute, context={'request': request}).data)
        except Exception as e:
            return Response({'error': str(e)}, status=status.HTTP_400_BAD_REQUEST)

    @action(detail=False, methods=['get'])
    def stats(self, request):
        total = DisputeRequest.objects.count()
        filed = DisputeRequest.objects.filter(status='filed').count()
        under_review = DisputeRequest.objects.filter(status='under_review').count()
        approved = DisputeRequest.objects.filter(status='approved').count()
        rejected = DisputeRequest.objects.filter(status='rejected').count()
        resolved = DisputeRequest.objects.filter(status='resolved').count()
        return Response({
            'total': total,
            'filed': filed,
            'under_review': under_review,
            'approved': approved,
            'rejected': rejected,
            'resolved': resolved,
        })

    @action(detail=True, methods=['post'])
    def start_review(self, request, pk=None):
        try:
            dispute = self.get_object()
            
            # Check if dispute can be reviewed
            if dispute.status not in ['filed', 'pending']:
                return Response(
                    {'error': f'Cannot start review for dispute with status: {dispute.status}'},
                    status=status.HTTP_400_BAD_REQUEST
                )
            
            dispute.status = 'under_review'
            user_id = request.headers.get('X-User-Id')
            resolved_user = None
            
            if user_id:
                # sanitize header: trim whitespace and surrounding quotes
                import re
                user_id = user_id.strip()
                # remove leading/trailing quotes (', ", and unicode smart quotes)
                user_id = re.sub(r'^[\'"\u201c\u201d\u2018\u2019]+|[\'"\u201c\u201d\u2018\u2019]+$', '', user_id)
                
                # Try to find user by ID first
                try:
                    resolved_user = User.objects.get(id=user_id)
                except (User.DoesNotExist, ValueError):
                    # If not found by ID, try username
                    try:
                        resolved_user = User.objects.get(username=user_id)
                    except User.DoesNotExist:
                        # Try email
                        try:
                            resolved_user = User.objects.get(email=user_id)
                        except User.DoesNotExist:
                            # Last resort: try to get first admin user
                            resolved_user = User.objects.filter(is_admin=True).first()
                            if resolved_user:
                                print(f"Using fallback admin user: {resolved_user.id} - {resolved_user.username}")
            
            if resolved_user:
                dispute.processed_by = resolved_user
            else:
                # Even if no user found, we can still update the status
                # But log this issue
                print(f"Warning: No user found for X-User-Id: {user_id}")
            
            dispute.save(update_fields=['status', 'processed_by'])
            
            return Response(
                DisputeRequestSerializer(dispute, context={'request': request}).data,
                status=status.HTTP_200_OK
            )
        except Exception as e:
            import traceback
            traceback.print_exc()
            return Response(
                {'error': str(e), 'traceback': traceback.format_exc()},
                status=status.HTTP_400_BAD_REQUEST
            )
    @action(detail=True, methods=['post'])
    def partial(self, request, pk=None):
        """Admin marks dispute decision as partial; does not process refund yet"""
        try:
            dispute = self.get_object()
            dispute.status = 'partial'
            # Optionally record amount in admin_notes
            amt = request.data.get('partial_amount')
            note = request.data.get('admin_notes')
            if amt is not None:
                try:
                    from decimal import Decimal
                    amt_val = float(amt)
                    prefix = f"Partial amount decided: ₱{amt_val:.2f}. "
                    # Store partial amount on the refund record as approved_refund_amount
                    if getattr(dispute, 'refund_id', None):
                        refund = dispute.refund_id
                        try:
                            refund.approved_refund_amount = Decimal(str(amt_val))
                            refund.save(update_fields=['approved_refund_amount'])
                        except Exception:
                            # Fallback without crashing; keep admin_notes
                            pass
                except Exception:
                    prefix = "Partial amount decided. "
                dispute.admin_notes = f"{prefix}{note or (dispute.admin_notes or '')}".strip()
            elif note:
                dispute.admin_notes = note

            # Set processed_by from X-User-Id when available
            user_id = request.headers.get('X-User-Id')
            resolved_user = None
            if user_id:
                import re
                user_id = user_id.strip()
                user_id = re.sub(r'^[\'"\u201c\u201d\u2018\u2019]+|[\'"\u201c\u201d\u2018\u2019]+$', '', user_id)
                try:
                    resolved_user = User.objects.get(id=user_id)
                except (User.DoesNotExist, ValueError):
                    try:
                        resolved_user = User.objects.get(username=user_id)
                    except User.DoesNotExist:
                        try:
                            resolved_user = User.objects.get(email=user_id)
                        except User.DoesNotExist:
                            if str(user_id).isdigit():
                                resolved_user = User.objects.filter(is_admin=True).first()
                            else:
                                resolved_user = None
            if resolved_user:
                dispute.processed_by = resolved_user

            # Do not set resolved_at; partial decision precedes processing
            dispute.save(update_fields=['status', 'admin_notes', 'processed_by'])
            return Response(DisputeRequestSerializer(dispute, context={'request': request}).data)
        except Exception as e:
            return Response({'error': str(e)}, status=status.HTTP_400_BAD_REQUEST)

    @action(detail=True, methods=['post'])
    def accept(self, request, pk=None):
        """Admin accepts dispute: set status to 'approved' and mark resolved_by/at"""
        try:
            dispute = self.get_object()
            dispute.status = 'approved'
            dispute.resolved_at = timezone.now()
            user_id = request.headers.get('X-User-Id')
            resolved_user = None
            if user_id:
                import re
                user_id = user_id.strip()
                user_id = re.sub(r'^[\'"\u201c\u201d\u2018\u2019]+|[\'"\u201c\u201d\u2018\u2019]+$', '', user_id)
                try:
                    resolved_user = User.objects.get(id=user_id)
                except (User.DoesNotExist, ValueError):
                    try:
                        resolved_user = User.objects.get(username=user_id)
                    except User.DoesNotExist:
                        try:
                            resolved_user = User.objects.get(email=user_id)
                        except User.DoesNotExist:
                            if str(user_id).isdigit():
                                resolved_user = User.objects.filter(is_admin=True).first()
                            else:
                                resolved_user = None
            if resolved_user:
                dispute.processed_by = resolved_user
                
            # When approved, set approved/final amounts to the requested total.
            try:
                import logging
                logger = logging.getLogger(__name__)
                if getattr(dispute, 'refund_id', None):
                    refund = dispute.refund_id
                    logger.info('Accept: found refund %s, total_refund_amount=%s', getattr(refund, 'refund_id', None), getattr(refund, 'total_refund_amount', None))
                    requested_total = getattr(refund, 'total_refund_amount', None)
                    if requested_total is None:
                        try:
                            from .models import Checkout
                            agg = Checkout.objects.filter(order=refund.order_id).aggregate(total=Sum('total_amount'))
                            requested_total = agg.get('total')
                            logger.info('Accept: computed requested_total from checkouts=%s', requested_total)
                        except Exception as e:
                            logger.exception('Accept: failed to compute requested_total fallback: %s', e)
                            requested_total = None
                    if requested_total is not None:
                        try:
                            from decimal import Decimal
                            refund.approved_refund_amount = Decimal(str(requested_total))
                            # CRITICAL: Update the refund status to 'approved'
                            refund.status = 'approved'
                            refund.save(update_fields=['approved_refund_amount', 'status'])
                            logger.info('Accept: saved approved_refund_amount=%s and set status=approved for refund=%s', 
                                    refund.approved_refund_amount, getattr(refund, 'refund_id', None))
                        except Exception as e:
                            logger.exception('Accept: failed to save refund amounts: %s', e)
            except Exception:
                # Non-blocking: continue saving dispute approval even if refund update fails
                pass
                
            dispute.save(update_fields=['status', 'processed_by', 'resolved_at'])
            return Response(DisputeRequestSerializer(dispute, context={'request': request}).data)
        except Exception as e:
            return Response({'error': str(e)}, status=status.HTTP_400_BAD_REQUEST)
        
    @action(detail=True, methods=['post'])
    def reject(self, request, pk=None):
        """Admin rejects dispute: set status to 'rejected' and store admin notes"""
        try:
            dispute = self.get_object()
            dispute.status = 'rejected'
            dispute.resolved_at = timezone.now()
            admin_notes = request.data.get('admin_notes')
            if admin_notes:
                dispute.admin_notes = admin_notes
            user_id = request.headers.get('X-User-Id')
            resolved_user = None
            if user_id:
                import re
                user_id = user_id.strip()
                user_id = re.sub(r'^[\'"\u201c\u201d\u2018\u2019]+|[\'"\u201c\u201d\u2018\u2019]+$', '', user_id)
                try:
                    resolved_user = User.objects.get(id=user_id)
                except (User.DoesNotExist, ValueError):
                    try:
                        resolved_user = User.objects.get(username=user_id)
                    except User.DoesNotExist:
                        try:
                            resolved_user = User.objects.get(email=user_id)
                        except User.DoesNotExist:
                            if str(user_id).isdigit():
                                resolved_user = User.objects.filter(is_admin=True).first()
                            else:
                                resolved_user = None
            if resolved_user:
                dispute.processed_by = resolved_user
            dispute.save(update_fields=['status', 'processed_by', 'resolved_at', 'admin_notes'])
            return Response(DisputeRequestSerializer(dispute, context={'request': request}).data)
        except Exception as e:
            return Response({'error': str(e)}, status=status.HTTP_400_BAD_REQUEST)

    @action(detail=True, methods=['post'])
    def acknowledge(self, request, pk=None):
        """Buyer acknowledgement endpoint: mark dispute resolved and set refund.status to 'completed'"""
        try:
            dispute = self.get_object()
            refund = getattr(dispute, 'refund_id', None)

            # Update refund to completed when buyer acknowledges a rejected dispute
            if refund:
                # Only move forward if refund is currently 'dispute' or not already completed
                if str(refund.status).lower() == 'dispute':
                    refund.status = 'completed'
                    refund.processed_at = timezone.now()
                    # Buyer acknowledgement should mark payment as completed
                    refund.refund_payment_status = 'completed'
                    refund.save(update_fields=['status', 'processed_at', 'refund_payment_status'])

            # Mark dispute as resolved and set resolved_at
            dispute.status = 'resolved'
            dispute.resolved_at = timezone.now()
            dispute.save(update_fields=['status', 'resolved_at'])

            return Response(DisputeRequestSerializer(dispute, context={'request': request}).data)
        except Exception as e:
            return Response({'error': str(e)}, status=status.HTTP_400_BAD_REQUEST)

    @action(detail=False, methods=['post'])
    def approve_refund(self, request):
        """
        Admin approves dispute and processes refund.
        Stores decision in dispute fields: adjusted_amount, liability, outcome, case_category
        Also updates the associated refund with approved amount and status.
        """
        try:
            # Get admin user from header
            user_id = request.headers.get('X-User-Id')
            if not user_id:
                return Response({"error": "User ID required"}, status=status.HTTP_400_BAD_REQUEST)
            
            try:
                admin_user = User.objects.get(id=user_id)
            except User.DoesNotExist:
                return Response({"error": "User not found"}, status=status.HTTP_404_NOT_FOUND)
            
            # Validate required fields
            refund_id = request.data.get('refund_id')
            dispute_id = request.data.get('dispute_id')
            decision = request.data.get('decision')  # 'approve', 'reject', 'partial'
            refund_type = request.data.get('refund_type')  # 'full', 'partial'
            adjusted_amount = request.data.get('adjusted_amount')
            liability_distribution = request.data.get('liability_distribution', {})
            outcome = request.data.get('outcome')
            case_category = request.data.get('case_category')
            admin_notes = request.data.get('admin_notes', '')
            
            if not refund_id:
                return Response({"error": "refund_id required"}, status=status.HTTP_400_BAD_REQUEST)
            
            # Get refund
            try:
                refund = Refund.objects.get(refund_id=refund_id)
            except Refund.DoesNotExist:
                return Response({"error": "Refund not found"}, status=status.HTTP_404_NOT_FOUND)
            
            # Get or create dispute
            dispute = None
            if dispute_id:
                try:
                    dispute = DisputeRequest.objects.get(id=dispute_id)
                except DisputeRequest.DoesNotExist:
                    pass
            
            if not dispute:
                # Try to find dispute by refund_id
                try:
                    dispute = DisputeRequest.objects.get(refund_id=refund)
                except DisputeRequest.DoesNotExist:
                    return Response({"error": "No dispute found for this refund"}, status=status.HTTP_404_NOT_FOUND)
            
            # Update dispute with admin decision
            with transaction.atomic():
                # Store the adjusted amount (full or partial refund amount)
                if adjusted_amount is not None:
                    dispute.adjusted_amount = Decimal(str(adjusted_amount))
                
                # Store liability distribution as JSON
                if liability_distribution:
                    dispute.liability = liability_distribution
                
                # Store outcome if provided
                if outcome:
                    dispute.outcome = outcome
                
                # Store case category if provided
                if case_category:
                    dispute.case_category = case_category
                
                # Store admin notes
                if admin_notes:
                    dispute.admin_notes = admin_notes
                
                # Set processed_by and resolved_at
                dispute.processed_by = admin_user
                dispute.resolved_at = timezone.now()
                
                # Set status based on decision
                if decision == 'approve':
                    dispute.status = 'approved'
                elif decision == 'reject':
                    dispute.status = 'rejected'
                elif decision == 'partial':
                    dispute.status = 'partial'
                else:
                    dispute.status = 'approved'
                
                dispute.save()
                
                # Update refund based on decision
                if decision == 'approve':
                    # Update refund with approved amount
                    if adjusted_amount is not None:
                        refund.approved_refund_amount = Decimal(str(adjusted_amount))
                    
                    # Set refund status to approved
                    refund.status = 'approved'
                    refund.processed_by = admin_user
                    refund.processed_at = timezone.now()
                    
                    # If full refund, set total_refund_amount to match
                    if refund_type == 'full':
                        refund.total_refund_amount = Decimal(str(adjusted_amount)) if adjusted_amount else refund.total_refund_amount
                    
                    refund.save()
                    
                    # Refund the Buyer
                    if adjusted_amount and Decimal(str(adjusted_amount)) > 0:
                        buyer_user = refund.requested_by
                        buyer_wallet, _ = UserWallet.objects.get_or_create(user=buyer_user)
                        
                        buyer_wallet.available_balance += Decimal(str(adjusted_amount))
                        buyer_wallet.save()
                        
                        from .models import WalletTransaction
                        WalletTransaction.objects.create(
                            wallet=buyer_wallet,
                            user=buyer_user,
                            amount=Decimal(str(adjusted_amount)),
                            transaction_type='credit',
                            source_type='refund',
                            status='completed',
                            order=refund.order_id
                        )
                        
                    # Also update seller_deduction_amount and rider_deduction_amount if liability distribution provided
                    if liability_distribution:
                        seller_pct = liability_distribution.get('seller', 0)
                        rider_pct = liability_distribution.get('rider', 0)
                        
                        if seller_pct > 0 and adjusted_amount:
                            dispute.seller_deduction_amount = Decimal(str(adjusted_amount)) * Decimal(str(seller_pct)) / Decimal('100')
                            
                            # Deduct from Seller Wallet
                            if refund.order_id and refund.order_id.shop:
                                seller_user = refund.order_id.shop.seller
                                seller_wallet, _ = UserWallet.objects.get_or_create(user=seller_user)
                                
                                deduction = dispute.seller_deduction_amount
                                if seller_wallet.pending_balance >= deduction:
                                    seller_wallet.pending_balance -= deduction
                                else:
                                    remaining = deduction - seller_wallet.pending_balance
                                    seller_wallet.pending_balance = 0
                                    seller_wallet.available_balance -= remaining
                                    
                                seller_wallet.save()

                                
                                WalletTransaction.objects.create(
                                    wallet=seller_wallet,
                                    user=seller_user,
                                    amount=dispute.seller_deduction_amount,
                                    transaction_type='debit',
                                    source_type='dispute',
                                    status='completed',
                                    order=refund.order_id
                                )

                        if rider_pct > 0 and adjusted_amount:
                            dispute.rider_deduction_amount = Decimal(str(adjusted_amount)) * Decimal(str(rider_pct)) / Decimal('100')
                            
                            # Deduct from Rider Wallet
                            if refund.order_id:
                                from .models import Delivery
                                delivery = Delivery.objects.filter(order=refund.order_id).first()
                                if delivery and delivery.rider and delivery.rider.user:
                                    rider_user = delivery.rider.user
                                    rider_wallet, _ = UserWallet.objects.get_or_create(user=rider_user)
                                    rider_wallet.available_balance -= dispute.rider_deduction_amount
                                    rider_wallet.save()
                                    
                                    WalletTransaction.objects.create(
                                        wallet=rider_wallet,
                                        user=rider_user,
                                        amount=dispute.rider_deduction_amount,
                                        transaction_type='debit',
                                        source_type='dispute',
                                        status='completed',
                                        order=refund.order_id
                                    )

                        dispute.save(update_fields=['seller_deduction_amount', 'rider_deduction_amount'])
                    
                elif decision == 'reject':
                    # Update refund status to rejected
                    refund.status = 'rejected'
                    refund.processed_by = admin_user
                    refund.processed_at = timezone.now()
                    refund.save()
                
                elif decision == 'partial':
                    # Partial decision - store adjusted amount but keep refund pending
                    if adjusted_amount is not None:
                        refund.approved_refund_amount = Decimal(str(adjusted_amount))
                    refund.save(update_fields=['approved_refund_amount'])
                
                # Create notification for buyer
                try:
                    from .models import Notification
                    
                    if decision == 'approve':
                        notification_title = "Dispute Approved - Refund Processing"
                        notification_message = f"Your dispute has been approved. A {refund_type} refund of ₱{float(adjusted_amount or 0):.2f} will be processed."
                    elif decision == 'reject':
                        notification_title = "Dispute Rejected"
                        notification_message = f"Your dispute has been reviewed and rejected. {admin_notes or 'Please contact support for more information.'}"
                    else:
                        notification_title = "Dispute Partially Resolved"
                        notification_message = f"Your dispute has been partially resolved. {admin_notes or 'Please check your refund status for updates.'}"
                    
                    Notification.objects.create(
                        user=refund.requested_by,
                        title=notification_title,
                        message=notification_message,
                        type='dispute',
                        related_refund=refund,
                        action_url=f'/refunds/{refund.refund_id}',
                        action_type='refund',
                        action_id=str(refund.refund_id)
                    )
                except Exception as e:
                    print(f"Failed to create notification: {e}")
                
                # Return updated data
                dispute_serializer = DisputeRequestSerializer(dispute, context={'request': request})
                refund_serializer = RefundSerializer(refund, context={'request': request})
                
                return Response({
                    "message": f"Dispute {decision}ed successfully",
                    "dispute": dispute_serializer.data,
                    "refund": refund_serializer.data,
                    "adjusted_amount": str(dispute.adjusted_amount) if dispute.adjusted_amount else None,
                    "liability": dispute.liability,
                    "outcome": dispute.outcome,
                    "case_category": dispute.case_category
                }, status=status.HTTP_200_OK)
                
        except Exception as e:
            import traceback
            traceback.print_exc()
            return Response({"error": str(e)}, status=status.HTTP_400_BAD_REQUEST)

class SellerGifts(viewsets.ModelViewSet):
    serializer_class = ProductSerializer
    
    @action(detail=False, methods=['get'], url_path='global-categories')    
    def get_global_categories(self, request):
        """
        Fetch global categories (where shop_id is null/empty)
        """
        try:
            # Fetch categories where shop is null (global categories)
            global_categories = Category.objects.filter(shop__isnull=True).order_by('name')
            
            # Serialize the data
            categories_data = []
            for category in global_categories:
                category_data = {
                    "id": str(category.id),
                    "name": category.name,
                    "shop": None,  # Explicitly set to null since we're filtering for null shop
                    "user": {
                        "id": str(category.user.id),
                        "username": category.user.username
                    } if category.user else None,
                }
                categories_data.append(category_data)
            
            return Response({
                "success": True,
                "categories": categories_data,
                "message": "Global categories retrieved successfully",
                "total_count": len(categories_data),
                "is_global": True
            }, status=status.HTTP_200_OK)
            
        except Exception as e:
            return Response({
                "success": False,
                "error": "Failed to fetch global categories",
                "details": str(e)
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
        
    @action(detail=False, methods=['post'], url_path='global-categories/predict')    
    def predict_category(self, request):
        """
        Predict category for a product - FIXED VERSION with UUIDs
        """
        try:
            import pandas as pd
            import numpy as np
            import tensorflow as tf
            import joblib
            import os
            
            CURRENT_DIR = os.path.dirname(os.path.abspath(__file__))
            MODEL_DIR = os.path.join(os.path.dirname(CURRENT_DIR), 'model')
            
            print(f"Looking for models in: {MODEL_DIR}")

            # Load the trained models
            try:
                category_le = joblib.load(os.path.join(MODEL_DIR, 'category_label_encoder.pkl'))
                scaler = joblib.load(os.path.join(MODEL_DIR, 'scaler.pkl'))
                model = tf.keras.models.load_model(os.path.join(MODEL_DIR, 'category_classifier.keras'))
                
                # Load the EXACT feature columns used during training
                feature_columns = joblib.load(os.path.join(MODEL_DIR, 'feature_columns.pkl'))
                
                print(f"✅ Models loaded successfully!")
                print(f"Model expects {len(feature_columns)} features: {feature_columns}")

                print(f"Model input shape: {model.input_shape}")
                print(f"Model expects {model.input_shape[1]} features")
                print(f"Loaded {len(feature_columns)} features from file")
                
            except FileNotFoundError as e:
                print(f"❌ Model file not found: {str(e)}")
                return Response(
                    {'success': False, 'error': f'Model files not found. Please train the model first.'},
                    status=status.HTTP_500_INTERNAL_SERVER_ERROR
                )
            
            # Extract data from request
            data = request.data
            
            # Required fields from UI - price still required but will be set to 0
            required_fields = ['name', 'description', 'quantity', 'price', 'condition']
            
            # Validate required fields
            for field in required_fields:
                if field not in data:
                    return Response(
                        {'success': False, 'error': f'Missing required field: {field}'},
                        status=status.HTTP_400_BAD_REQUEST
                    )
            
            # Prepare item data - set price to 0
            item_data = {
                'name': str(data['name']),
                'description': str(data['description']),
                'quantity': int(data['quantity']),
                'price': 0.0,  # SET PRICE TO 0
                'condition': str(data['condition'])
            }
            
            print(f"\n=== PREDICTION STARTED ===")
            print(f"Product: {item_data['name']}")
            print(f"Price: ${item_data['price']}, Quantity: {item_data['quantity']}")
            
            # ================================================
            # CREATE FEATURES - EXACTLY AS DURING TRAINING
            # ================================================
            
            # Initialize all features to 0
            features = {col: 0 for col in feature_columns}
            
            # Basic numeric features - only if they're in feature_columns
            price = item_data['price']  # This will be 0
            quantity = item_data['quantity']
            
            # Set only the features that exist in feature_columns
            if 'price' in feature_columns:
                features['price'] = price
            if 'quantity' in feature_columns:
                features['quantity'] = quantity
            if 'price_quantity_interaction' in feature_columns:
                features['price_quantity_interaction'] = price * np.log1p(quantity + 1)
            if 'log_price' in feature_columns:
                features['log_price'] = np.log1p(price)
            if 'price_per_unit' in feature_columns:
                features['price_per_unit'] = price / (quantity + 1)
            if 'price_to_quantity_ratio' in feature_columns:
                features['price_to_quantity_ratio'] = price / (quantity + 1e-5)
            if 'price_scaled' in feature_columns:
                features['price_scaled'] = price / 10000  # Use same scaling as training
            if 'quantity_scaled' in feature_columns:
                features['quantity_scaled'] = quantity / 100  # Use same scaling as training
            
            # Condition features
            condition_lower = item_data['condition'].lower()
            
            if 'condition_score' in feature_columns:
                if 'new' in condition_lower:
                    features['condition_score'] = 3
                elif 'like new' in condition_lower:
                    features['condition_score'] = 2
                elif 'refurbished' in condition_lower:
                    features['condition_score'] = 1
                elif 'excellent' in condition_lower:
                    features['condition_score'] = 0
                elif 'good' in condition_lower:
                    features['condition_score'] = -1
                elif 'fair' in condition_lower:
                    features['condition_score'] = -2
                else:
                    features['condition_score'] = 0
            
            # is_refurbished feature (if present)
            if 'is_refurbished' in feature_columns:
                features['is_refurbished'] = 1 if 'refurbished' in condition_lower else 0
            
            # Text features
            name_lower = item_data['name'].lower()
            desc_lower = item_data['description'].lower()
            all_text = name_lower + ' ' + desc_lower
            
            if 'name_length' in feature_columns:
                features['name_length'] = len(item_data['name'])
            if 'desc_length' in feature_columns:
                features['desc_length'] = len(item_data['description'])
            if 'name_desc_ratio' in feature_columns:
                desc_len = len(item_data['description'])
                if desc_len > 0:
                    features['name_desc_ratio'] = len(item_data['name']) / desc_len
                else:
                    features['name_desc_ratio'] = len(item_data['name'])
            
            # Keyword features - only for features that start with 'has_' AND are in feature_columns
            for feature in feature_columns:
                if feature.startswith('has_'):
                    keyword = feature[4:]  # Remove 'has_' prefix
                    features[feature] = 1 if keyword in all_text else 0
            
            # Price bins - only if they're in feature_columns (all will be 0 since price is 0)
            if 'price_bin_0' in feature_columns:
                features['price_bin_0'] = 1 if price < 100 else 0  # This will be 1
            if 'price_bin_1' in feature_columns:
                features['price_bin_1'] = 1 if 100 <= price < 500 else 0
            if 'price_bin_2' in feature_columns:
                features['price_bin_2'] = 1 if 500 <= price < 1000 else 0
            if 'price_bin_3' in feature_columns:
                features['price_bin_3'] = 1 if 1000 <= price < 2000 else 0
            if 'price_bin_4' in feature_columns:
                features['price_bin_4'] = 1 if price >= 2000 else 0
            
            # Category-specific features (these use category stats, so set to 0 for prediction)
            if 'price_category_zscore' in feature_columns:
                features['price_category_zscore'] = 0  # Can't compute without category
            if 'quantity_category_zscore' in feature_columns:
                features['quantity_category_zscore'] = 0  # Can't compute without category
            if 'price_category_quartile' in feature_columns:
                features['price_category_quartile'] = 2  # Default middle quartile
            
            # Additional simple text features
            if 'name_word_count' in feature_columns:
                features['name_word_count'] = len(item_data['name'].split())
            if 'desc_word_count' in feature_columns:
                features['desc_word_count'] = len(item_data['description'].split())
            if 'keyword_count' in feature_columns:
                # Count keyword features that are set to 1
                keyword_features = [f for f in feature_columns if f.startswith('has_')]
                features['keyword_count'] = sum(1 for f in keyword_features if features.get(f, 0) == 1)
            if 'unique_keywords' in feature_columns:
                # Same as keyword_count for prediction
                keyword_features = [f for f in feature_columns if f.startswith('has_')]
                features['unique_keywords'] = sum(1 for f in keyword_features if features.get(f, 0) == 1)
            
            # Brand mentions
            for brand_feature in ['has_iphone', 'has_samsung', 'has_apple', 'has_sony']:
                if brand_feature in feature_columns:
                    brand_name = brand_feature[4:]  # Remove 'has_' prefix
                    features[brand_feature] = 1 if brand_name in all_text else 0
            
            # New/Used flags
            if 'is_new' in feature_columns:
                features['is_new'] = 1 if 'new' in condition_lower else 0
            if 'is_used' in feature_columns:
                features['is_used'] = 1 if 'used' in condition_lower else 0
            
            print(f"\n=== FEATURE SUMMARY ===")
            print(f"Total features created: {len(features)}")
            print(f"Features expected: {len(feature_columns)}")
            
            # Create DataFrame with EXACTLY the expected features
            X_item = pd.DataFrame([features])
            
            # Ensure we only have the expected features (remove extras, add missing)
            for col in feature_columns:
                if col not in X_item.columns:
                    X_item[col] = 0
            
            # Remove any columns not in feature_columns
            extra_cols = [col for col in X_item.columns if col not in feature_columns]
            if extra_cols:
                print(f"Removing extra columns: {extra_cols}")
                X_item = X_item.drop(columns=extra_cols)
            
            # Reorder columns to match training order
            X_item = X_item[feature_columns]
            
            print(f"DataFrame shape: {X_item.shape}")
            print(f"Columns: {list(X_item.columns)}")
            
            # Show top non-zero features
            non_zero = X_item.loc[:, (X_item != 0).any()].columns.tolist()
            print(f"Non-zero features ({len(non_zero)}): {non_zero}")
            
            # ================================================
            # SCALE AND PREDICT
            # ================================================
            
            try:
                X_scaled = scaler.transform(X_item)
                print(f"Scaled successfully to shape: {X_scaled.shape}")
            except Exception as e:
                print(f"Scaling error: {e}, using raw features")
                X_scaled = X_item.values.astype(np.float32)
            
            # Make prediction
            prediction_probs = model.predict(X_scaled, verbose=0)
            predicted_class = np.argmax(prediction_probs, axis=1)[0]
            confidence = np.max(prediction_probs, axis=1)[0]
            
            # Convert predicted class to actual category label
            predicted_label = category_le.inverse_transform([predicted_class])[0]
            
            print(f"\n✅ PREDICTION SUCCESSFUL!")
            print(f"Predicted: {predicted_label}")
            print(f"Confidence: {confidence:.2%}")
            
            # ================================================
            # GET UUID FROM DATABASE (NEW CODE)
            # ================================================
            
            # Try to find the category in the database
            try:
                # First, try to find the category by name (case-insensitive)
                category_obj = Category.objects.filter(
                    name__iexact=predicted_label,
                    shop__isnull=True  # Only global categories
                ).first()
                
                if category_obj:
                    category_uuid = str(category_obj.id)
                    category_name = category_obj.name
                    print(f"✅ Found category in DB: {category_name} (UUID: {category_uuid})")
                else:
                    # If not found by exact name, try to find similar
                    # You might need to adjust this based on your category naming
                    similar_categories = Category.objects.filter(
                        name__icontains=predicted_label,
                        shop__isnull=True
                    ).first()
                    
                    if similar_categories:
                        category_uuid = str(similar_categories.id)
                        category_name = similar_categories.name
                        print(f"✅ Found similar category in DB: {category_name} (UUID: {category_uuid})")
                    else:
                        # Fallback: get the first available global category
                        first_category = Category.objects.filter(shop__isnull=True).first()
                        if first_category:
                            category_uuid = str(first_category.id)
                            category_name = first_category.name
                            print(f"⚠️  Category not found, using first available: {category_name}")
                        else:
                            # No categories in database
                            category_uuid = None
                            category_name = predicted_label
                            print(f"❌ No categories found in database")
                            
            except Exception as db_error:
                print(f"Database lookup error: {db_error}")
                category_uuid = None
                category_name = predicted_label
            
            # ================================================
            # PREPARE RESPONSE WITH UUIDs
            # ================================================
            
            # Get all category names from database (not just from model)
            try:
                all_categories_objs = Category.objects.filter(shop__isnull=True)
                all_categories_list = []
                
                for cat in all_categories_objs:
                    all_categories_list.append({
                        'uuid': str(cat.id),
                        'name': cat.name,
                        'id': str(cat.id)  # Include both uuid and id for compatibility
                    })
            except Exception as e:
                print(f"Error fetching categories from DB: {e}")
                all_categories_list = list(category_le.classes_)
            
            # Prepare top 3 categories
            top_3_indices = np.argsort(prediction_probs[0])[-3:][::-1]
            top_categories = []
            
            for idx in top_3_indices:
                category_label = category_le.inverse_transform([idx])[0]
                
                # Try to find this category in DB for UUID
                try:
                    cat_obj = Category.objects.filter(
                        name__iexact=category_label,
                        shop__isnull=True
                    ).first()
                    
                    if cat_obj:
                        category_uuid_for_alt = str(cat_obj.id)
                        category_name_for_alt = cat_obj.name
                    else:
                        category_uuid_for_alt = None
                        category_name_for_alt = category_label
                        
                except Exception:
                    category_uuid_for_alt = None
                    category_name_for_alt = category_label
                
                top_categories.append({
                    'category_id': int(idx),  # Keep numeric ID for model reference
                    'category_uuid': category_uuid_for_alt,  # Add UUID for database
                    'category_name': category_name_for_alt,
                    'confidence': float(prediction_probs[0][idx])
                })
            
            # Get keywords found
            keyword_cols = [col for col in feature_columns if col.startswith('has_')]
            keywords_found = [col.replace('has_', '') for col in keyword_cols if features.get(col, 0) == 1]
            
            # Determine price range (will always be Ultra Budget since price is 0)
            price_range = 'Ultra Budget'  # Since price is 0
            
            # Build the response
            result = {
                'success': True,
                'predicted_category': {
                    'category_id': int(predicted_class),  # Numeric ID from model
                    'category_uuid': category_uuid,  # UUID from database
                    'category_name': predicted_label,
                    'confidence': float(confidence)
                },
                'alternative_categories': top_categories[1:] if len(top_categories) > 1 else [],
                'all_categories': all_categories_list,
                'feature_insights': {
                    'keywords_found': keywords_found,
                    'price_range': price_range,
                    'price': float(price),
                    'quantity': int(quantity),
                    'condition': item_data['condition']
                }
            }
            
            return Response(result, status=status.HTTP_200_OK)
            
        except Exception as e:
            print(f"\n❌ PREDICTION ERROR: {str(e)}")
            import traceback
            traceback.print_exc()
            
            return Response(
                {
                    'success': False, 
                    'error': f'Prediction failed: {str(e)}'
                },
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )
        
    def get_queryset(self):
        # Get user_id from request data instead of authenticated user
        user_id = self.request.data.get('customer_id')
        if user_id:
            try:
                seller = Customer.objects.get(customer_id=user_id)
                return Product.objects.filter(customer=seller).order_by('-created_at')
            except Customer.DoesNotExist:
                return Product.objects.none()
        return Product.objects.none()

    def create(self, request):
        # Validate required fields for seller product creation
        required_fields = ["name", "description", "quantity", "price", "condition", "shop", "customer_id"]
        missing_fields = [f for f in required_fields if f not in request.data]

        if missing_fields:
            return Response({
                "error": "Missing required fields",
                "missing_fields": missing_fields
            }, status=status.HTTP_400_BAD_REQUEST)

        # Get the user ID from session (sent from frontend)
        user_id = request.data.get("customer_id")
        if not user_id:
            return Response({"error": "User ID is required"}, status=status.HTTP_400_BAD_REQUEST)

        # Get seller using the user_id from session
        try:
            seller = Customer.objects.get(customer_id=user_id)
        except Customer.DoesNotExist:
            return Response({"error": "Seller not found"}, status=status.HTTP_404_NOT_FOUND)

        shop_id = request.data.get("shop")
        
        # Verify the shop belongs to the seller
        try:
            shop = Shop.objects.get(id=shop_id, customer=seller)
        except Shop.DoesNotExist:
            return Response({
                "error": "Shop not found or does not belong to you"
            }, status=status.HTTP_404_NOT_FOUND)

        # Check if seller can add more products
        if not seller.can_add_product():
            return Response({
                "error": f"Cannot add more than {seller.product_limit} products. Current count: {seller.current_product_count}"
            }, status=status.HTTP_400_BAD_REQUEST)

        # Prepare data with the seller from session user_id
        # Create a shallow copy excluding file fields
        product_data = {}
        for key, value in request.data.items():
            if not hasattr(value, 'file'):  # Skip file objects
                product_data[key] = value
        product_data['customer'] = seller.customer_id
        
        # Set price to 0 for gifts
        product_data['price'] = 0.0
        
        # Handle category_admin_id for global categories
        category_admin_id = request.data.get('category_admin_id')
        if category_admin_id and category_admin_id != "none":
            try:
                category_admin = Category.objects.get(id=category_admin_id, shop__isnull=True)
                product_data['category_admin'] = category_admin_id
            except Category.DoesNotExist:
                return Response({
                    "error": "Invalid global category selected"
                }, status=status.HTTP_400_BAD_REQUEST)

        # If accepted_categories was sent as a JSON string, parse it into a list for the serializer
        try:
            import json
            accepted_raw = product_data.get('accepted_categories')
            if accepted_raw and isinstance(accepted_raw, str):
                accepted_list = json.loads(accepted_raw)
                try:
                    product_data.setlist('accepted_categories', accepted_list)
                except Exception:
                    product_data['accepted_categories'] = accepted_list
        except Exception as e:
            print('Failed to parse accepted_categories:', e)

        serializer = ProductCreateSerializer(data=product_data, context={'request': request})
        if serializer.is_valid():
            with transaction.atomic():
                # Save product and catch validation errors cleanly
                try:
                    product = serializer.save()
                except ValidationError as e:
                    return Response({
                        "error": "Validation failed",
                        "details": str(e)
                    }, status=status.HTTP_400_BAD_REQUEST)

                # Handle media files if any
                media_files = request.FILES.getlist('media_files')
                print(f"Number of media files received: {len(media_files)}")  # Debug
                for i, media_file in enumerate(media_files):
                    print(f"Media file {i}: name={media_file.name}, size={media_file.size}, type={media_file.content_type}")  # Debug
                    try:
                        product_media = ProductMedia.objects.create(
                            product=product,
                            file_data=media_file,
                            file_type=media_file.content_type
                        )
                        print(f"Created ProductMedia: {product_media.id}, file saved to: {product_media.file_data}")  # Debug
                    except Exception as e:
                        print(f"Error creating ProductMedia: {e}")  # Debug

                # Process variants JSON (if provided) to create Variants
                variants_raw = request.data.get('variants')
                if variants_raw:
                    try:
                        import json
                        variants_list = json.loads(variants_raw) if isinstance(variants_raw, str) else variants_raw
                        # Collect uploaded files per option_id to later apply to matching variants
                        option_image_files = {}
                        
                        for variant_data in variants_list:
                            # Create variant
                            variant = Variants.objects.create(
                                product=product,
                                shop=shop,
                                title=variant_data.get('title', ''),
                                option_title=variant_data.get('option_title', ''),
                                option_ids=variant_data.get('option_ids', []),
                                option_map=variant_data.get('option_map', {}),
                                sku_code=variant_data.get('sku_code', ''),
                                price=Decimal('0.00'),  # SET VARIANT PRICE TO 0
                                compare_price=Decimal(str(variant_data.get('compare_price'))) if variant_data.get('compare_price') not in (None, '') else None,
                                quantity=int(variant_data.get('quantity', 0)),
                                weight=Decimal(str(variant_data.get('weight'))) if variant_data.get('weight') not in (None, '') else None,
                                weight_unit=variant_data.get('weight_unit', 'g'),
                                critical_trigger=int(variant_data.get('critical_trigger')) if variant_data.get('critical_trigger') not in (None, '') else None,
                                is_active=True,
                                allow_swap=bool(variant_data.get('allow_swap', False)),
                                swap_type=variant_data.get('swap_type', 'direct_swap'),
                                minimum_additional_payment=Decimal(str(variant_data.get('minimum_additional_payment'))) if variant_data.get('minimum_additional_payment') not in (None, '') else Decimal('0.00'),
                                maximum_additional_payment=Decimal(str(variant_data.get('maximum_additional_payment'))) if variant_data.get('maximum_additional_payment') not in (None, '') else Decimal('0.00'),
                                swap_description=variant_data.get('swap_description', ''),
                                is_refundable=bool(variant_data.get('is_refundable', False)),
                                refund_days=int(variant_data.get('refund_days', 0)) if variant_data.get('refund_days') else 0,
                                original_price=Decimal(str(variant_data.get('original_price'))) if variant_data.get('original_price') not in (None, '') else None,
                                usage_period=float(variant_data.get('usage_period')) if variant_data.get('usage_period') else None,
                                usage_unit=variant_data.get('usage_unit', None),
                                depreciation_rate=float(variant_data.get('depreciation_rate')) if variant_data.get('depreciation_rate') else None,
                                critical_stock=int(variant_data.get('critical_stock')) if variant_data.get('critical_stock') not in (None, '') else None
                            )
                            
                            print(f"Created variant: {variant.id} - {variant.title}")
                            
                            # Handle variant image
                            variant_id = variant_data.get('id')
                            file_key = f"variant_image_{variant_id}" if variant_id else None
                            
                            if file_key and file_key in request.FILES:
                                try:
                                    variant.image = request.FILES[file_key]
                                    variant.save()
                                    print(f"Added image to variant {variant.id}")
                                except Exception as e:
                                    print('Failed to save variant image', e)
                            
                    except Exception as e:
                        print('Failed to parse variants payload:', e)

                # Return same format as get_product_list
                return Response({
                    "success": True,
                    "products": [
                        {
                            "id": str(product.id),
                            "name": product.name,
                            "description": product.description,
                            "quantity": product.quantity,
                            "price": str(product.price),  # This will be "0.00"
                            "status": product.status,
                            "upload_status": product.upload_status,
                            "condition": product.condition,
                            "shop": {
                                "id": str(product.shop.id),
                                "name": product.shop.name
                            } if product.shop else None,
                            "category_admin": {
                                "id": str(product.category_admin.id),
                                "name": product.category_admin.name
                            } if product.category_admin else None,
                            "category": {
                                "id": str(product.category.id),
                                "name": product.category.name
                            } if product.category else None,
                            "created_at": product.created_at.isoformat() if product.created_at else None,
                            "updated_at": product.updated_at.isoformat() if product.updated_at else None,
                        }
                    ],
                    "message": "Product created successfully",
                    "data_source": "database",
                    "product_limit_info": {
                        "current_count": seller.current_product_count,
                        "limit": seller.product_limit,
                        "remaining": seller.product_limit - seller.current_product_count
                    }
                }, status=status.HTTP_201_CREATED)
        else:
            return Response({
                "error": "Validation failed",
                "details": serializer.errors
            }, status=status.HTTP_400_BAD_REQUEST)

    def list(self, request):
        # For listing, we need to get user_id from request data or query params
        user_id = request.data.get('customer_id') or request.query_params.get('customer_id')
        
        if not user_id:
            return Response({
                "error": "User ID is required"
            }, status=status.HTTP_400_BAD_REQUEST)
            
        try:
            seller = Customer.objects.get(customer_id=user_id)
            # Prefetch variants to avoid N+1 queries
            queryset = Product.objects.filter(customer=seller)\
                .prefetch_related('variants')\
                .order_by('-created_at')
            
            # Build response manually like in create method
            products_data = []
            for product in queryset:
                # Build variants data
                variants_data = []
                # Get all variants for this product
                for variant in product.variants.all():
                    variant_data = {
                        "id": str(variant.id),
                        "title": variant.title,
                        "option_title": variant.option_title,
                        "option_ids": variant.option_ids,
                        "option_map": variant.option_map,
                        "sku_code": variant.sku_code,
                        "price": str(variant.price) if variant.price else "0.00",
                        "compare_price": str(variant.compare_price) if variant.compare_price else None,
                        "quantity": variant.quantity,
                        "allow_swap": variant.allow_swap,
                        "swap_type": variant.swap_type,
                        "minimum_additional_payment": str(variant.minimum_additional_payment),
                        "maximum_additional_payment": str(variant.maximum_additional_payment),
                        "swap_description": variant.swap_description,
                        "image": variant.image.url if variant.image else None,
                        "is_refundable": variant.is_refundable,
                        "refund_days": variant.refund_days,
                        "original_price": str(variant.original_price) if variant.original_price else None,
                        "usage_period": variant.usage_period,
                        "usage_unit": variant.usage_unit,
                        "depreciation_rate": variant.depreciation_rate,
                        "critical_stock": variant.critical_stock,
                        "is_active": variant.is_active
                    }
                    variants_data.append(variant_data)
                
                product_data = {
                    "id": str(product.id),
                    "name": product.name,
                    "description": product.description,
                    "quantity": product.quantity,
                    "price": str(product.price),  # This will show "0.00" for gifts
                    "status": product.status,
                    "upload_status": product.upload_status,
                    "condition": product.condition,
                    "shop": {
                        "id": str(product.shop.id),
                        "name": product.shop.name
                    } if product.shop else None,
                    "category_admin": {
                        "id": str(product.category_admin.id),
                        "name": product.category_admin.name
                    } if product.category_admin else None,
                    "category": {
                        "id": str(product.category.id),
                        "name": product.category.name
                    } if product.category else None,
                    "variants": variants_data,  # ADD VARIANTS HERE
                    "created_at": product.created_at.isoformat() if product.created_at else None,
                    "updated_at": product.updated_at.isoformat() if product.updated_at else None,
                }
                products_data.append(product_data)
            
            return Response({
                "success": True,
                "products": products_data,
                "message": "Products retrieved successfully",
                "data_source": "database"
            }, status=status.HTTP_200_OK)
        except Customer.DoesNotExist:
            return Response({
                "success": True,
                "products": [],
                "message": "No seller found for this user",
                "data_source": "database"
            }, status=status.HTTP_200_OK)

    def retrieve(self, request, pk=None):
        """Retrieve an AppliedGift by id OR, if not found, return minimal product info when pk is a product id."""
        shop_id = request.query_params.get('shop_id') or request.data.get('shop_id')
        customer_id = request.query_params.get('customer_id') or request.data.get('customer_id')

        # Try to find an AppliedGift by id OR by gift product id
        qs = AppliedGift.objects.filter(Q(id=pk) | Q(gift_product_id__id=pk))
        if shop_id:
            qs = qs.filter(shop_id__id=shop_id)
        elif customer_id:
            try:
                seller = Customer.objects.get(customer_id=customer_id)
                qs = qs.filter(shop_id__customer=seller)
            except Customer.DoesNotExist:
                pass

        ag = qs.order_by('-start_time').first()
        if ag:
            applied_data = {
                "id": str(ag.id),
                "shop_id": str(ag.shop_id.id) if ag.shop_id else None,
                "gift_product_id": str(ag.gift_product_id.id) if ag.gift_product_id else None,
                "gift_product_name": ag.gift_product_id.name if ag.gift_product_id else None,
                "start_time": ag.start_time.isoformat() if ag.start_time else None,
                "end_time": ag.end_time.isoformat() if ag.end_time else None,
                "is_active": ag.is_active,
                "eligible_product_ids": [str(ap.product_id.id) for ap in ag.eligible_products.all() if ap.product_id]
            }
            return Response({"success": True, "applied_gift": applied_data}, status=status.HTTP_200_OK)

        # No AppliedGift found: try to treat pk as a product id and return minimal info
        try:
            product = None
            if shop_id:
                try:
                    product = Product.objects.get(pk=pk, shop__id=shop_id)
                except Product.DoesNotExist:
                    product = None
            if not product and customer_id:
                try:
                    seller = Customer.objects.get(customer_id=customer_id)
                    product = Product.objects.get(pk=pk, customer=seller)
                except (Customer.DoesNotExist, Product.DoesNotExist):
                    product = None

            if not product:
                product = Product.objects.get(pk=pk)

            prod_info = {
                "id": str(product.id),
                "gift_product_id": str(product.id),
                "gift_product_name": getattr(product, 'name', None),
                "price": str(getattr(product, 'price', '0')),
                "start_time": None,
                "end_time": None,
                "is_active": False,
                "eligible_product_ids": []
            }
            return Response({"success": True, "applied_gift": prod_info}, status=status.HTTP_200_OK)
        except Product.DoesNotExist:
            return Response({"detail": "Not found."}, status=status.HTTP_404_NOT_FOUND)

    @action(detail=False, methods=['get'], url_path='by-shop')
    def get_applied_gifts_by_shop(self, request):
        shop_id = request.query_params.get('shop_id')
        if not shop_id:
            return Response({"success": False, "error": "shop_id is required"}, status=status.HTTP_400_BAD_REQUEST)
        applied = AppliedGift.objects.filter(shop_id__id=shop_id).order_by('-start_time')
        data = []
        for a in applied:
            data.append({
                'id': str(a.id),
                'gift_product_id': str(a.gift_product_id.id) if a.gift_product_id else None,
                'gift_product_name': a.gift_product_id.name if a.gift_product_id else None,
                'start_time': a.start_time.isoformat() if a.start_time else None,
                'end_time': a.end_time.isoformat() if a.end_time else None,
                'is_active': a.is_active,
                'eligible_product_ids': [str(ep.product_id.id) for ep in a.eligible_products.all() if ep.product_id]
            })
        return Response({"success": True, "applied_gifts": data}, status=status.HTTP_200_OK)

    def update(self, request, pk=None):
        """Update an AppliedGift by id or by gift product id (pk can be either).
        Only the owning seller (via customer_id or X-User-Id) can update the applied gift."""
        customer_id = request.data.get('customer_id') or request.headers.get('X-User-Id')
        if not customer_id:
            return Response({"success": False, "error": "customer_id is required"}, status=status.HTTP_400_BAD_REQUEST)
        try:
            seller = Customer.objects.get(customer_id=customer_id)
        except Customer.DoesNotExist:
            return Response({"success": False, "error": "Seller not found"}, status=status.HTTP_404_NOT_FOUND)

        # Try to find AppliedGift by id or by gift_product_id (unscoped) and then check ownership
        ag = AppliedGift.objects.filter(Q(id=pk) | Q(gift_product_id__id=pk)).order_by('-start_time').first()

        if not ag:
            # No existing AppliedGift found — attempt to create one if pk is a product id owned by this seller
            try:
                product_candidate = None
                try:
                    product_candidate = Product.objects.get(pk=pk, customer=seller)
                except Product.DoesNotExist:
                    try:
                        product_candidate = Product.objects.get(pk=pk, shop__customer=seller)
                    except Product.DoesNotExist:
                        product_candidate = None

                if product_candidate:
                    # Determine shop for applied gift: prefer provided shop_id, else product's shop, else seller's first shop
                    shop_id = request.data.get('shop_id') or request.query_params.get('shop_id')
                    shop_obj = None
                    if shop_id:
                        try:
                            shop_obj = Shop.objects.get(pk=shop_id, customer=seller)
                        except Shop.DoesNotExist:
                            # Provided shop does not belong to seller; reject
                            return Response({"success": False, "error": "Shop not found or not owned by seller"}, status=status.HTTP_404_NOT_FOUND)
                    elif product_candidate.shop:
                        shop_obj = product_candidate.shop
                    else:
                        # Find a shop owned by seller if exists
                        seller_shops = Shop.objects.filter(customer=seller)
                        shop_obj = seller_shops.first() if seller_shops.exists() else None

                    # Create AppliedGift using provided times (if any)
                    from django.utils.dateparse import parse_datetime
                    start_time = None
                    end_time = None
                    if 'start_time' in request.data:
                        st = parse_datetime(request.data.get('start_time'))
                        if not st:
                            return Response({"success": False, "error": "Invalid start_time format"}, status=status.HTTP_400_BAD_REQUEST)
                        start_time = st
                    if 'end_time' in request.data:
                        et = parse_datetime(request.data.get('end_time'))
                        if not et:
                            return Response({"success": False, "error": "Invalid end_time format"}, status=status.HTTP_400_BAD_REQUEST)
                        end_time = et

                    # Provide sensible defaults if times are not provided
                    if not start_time:
                        start_time = timezone.now()
                    if not end_time:
                        end_time = timezone.now() + timedelta(days=30)

                    ag = AppliedGift.objects.create(
                        shop_id=shop_obj,
                        gift_product_id=product_candidate,
                        start_time=start_time,
                        end_time=end_time,
                        is_active=bool(request.data.get('is_active', True))
                    )
                else:
                    return Response({"success": False, "error": "AppliedGift not found for this seller or product"}, status=status.HTTP_404_NOT_FOUND)
            except Exception as e:
                return Response({"success": False, "error": str(e)}, status=status.HTTP_400_BAD_REQUEST)

        # Authorization: allow if the shop on the applied gift is owned by seller, or the gift product is owned by seller (as customer or via shop)
        authorized = False
        if ag.shop_id and ag.shop_id.customer == seller:
            authorized = True
        elif ag.gift_product_id:
            try:
                gp = ag.gift_product_id
                if gp.customer and gp.customer == seller:
                    authorized = True
                elif gp.shop and gp.shop.customer and gp.shop.customer == seller:
                    authorized = True
            except Exception:
                authorized = False

        if not authorized:
            return Response({"success": False, "error": "You do not own this applied gift"}, status=status.HTTP_403_FORBIDDEN)

        from django.utils.dateparse import parse_datetime
        data = request.data
        changed = False
        if 'start_time' in data:
            dt = parse_datetime(data.get('start_time'))
            if not dt:
                return Response({"success": False, "error": "Invalid start_time format"}, status=status.HTTP_400_BAD_REQUEST)
            ag.start_time = dt
            changed = True
        if 'end_time' in data:
            dt = parse_datetime(data.get('end_time'))
            if not dt:
                return Response({"success": False, "error": "Invalid end_time format"}, status=status.HTTP_400_BAD_REQUEST)
            ag.end_time = dt
            changed = True
        if 'is_active' in data:
            ag.is_active = bool(data.get('is_active'))
            changed = True
        def _get_seller_product(pid):
            try:
                return Product.objects.get(pk=pid, customer=seller)
            except Product.DoesNotExist:
                try:
                    return Product.objects.get(pk=pid, shop__customer=seller)
                except Product.DoesNotExist:
                    raise

        if 'gift_product_id' in data:
            gp_id = data.get('gift_product_id')
            try:
                gp = _get_seller_product(gp_id)
            except Product.DoesNotExist:
                return Response({"success": False, "error": "Gift product not found or not owned by seller"}, status=status.HTTP_404_NOT_FOUND)
            ag.gift_product_id = gp
            changed = True

        if 'eligible_product_ids' in data:
            ids = data.get('eligible_product_ids') or []
            if isinstance(ids, str):
                try:
                    import json
                    ids = json.loads(ids)
                except Exception:
                    ids = [i.strip() for i in ids.split(',') if i.strip()]
            valid_prods = []
            for pid in ids:
                try:
                    prod = _get_seller_product(pid)
                    valid_prods.append(prod)
                except Product.DoesNotExist:
                    return Response({"success": False, "error": f"Eligible product {pid} not found or not owned by seller"}, status=status.HTTP_400_BAD_REQUEST)
            # Replace eligible products
            ag.eligible_products.all().delete()
            for p in valid_prods:
                AppliedGiftProduct.objects.create(applied_gift_id=ag, product_id=p)
            changed = True

        if changed:
            ag.save()

        applied_data = {
            "id": str(ag.id),
            "shop_id": str(ag.shop_id.id) if ag.shop_id else None,
            "gift_product_id": str(ag.gift_product_id.id) if ag.gift_product_id else None,
            "gift_product_name": ag.gift_product_id.name if ag.gift_product_id else None,
            "start_time": ag.start_time.isoformat() if ag.start_time else None,
            "end_time": ag.end_time.isoformat() if ag.end_time else None,
            "is_active": ag.is_active,
            "eligible_product_ids": [str(ap.product_id.id) for ap in ag.eligible_products.all() if ap.product_id]
        }

        return Response({"success": True, "applied_gift": applied_data}, status=status.HTTP_200_OK)

    @action(detail=True, methods=['post'], url_path='apply-to-product')
    def apply_to_product(self, request, pk=None):
        """Attach product(s) as eligible for this AppliedGift."""
        customer_id = request.data.get('customer_id') or request.headers.get('X-User-Id')
        if not customer_id:
            return Response({"success": False, "error": "customer_id is required"}, status=status.HTTP_400_BAD_REQUEST)

        try:
            seller = Customer.objects.get(customer_id=customer_id)
        except Customer.DoesNotExist:
            return Response({"success": False, "error": "Seller not found"}, status=status.HTTP_404_NOT_FOUND)

        try:
            ag = AppliedGift.objects.get(id=pk)
        except AppliedGift.DoesNotExist:
            return Response({"success": False, "error": "AppliedGift not found"}, status=status.HTTP_404_NOT_FOUND)

        if not ag.shop_id or ag.shop_id.customer != seller:
            return Response({"success": False, "error": "You do not own this applied gift"}, status=status.HTTP_403_FORBIDDEN)

        raw_ids = request.data.get('product_ids') or request.data.get('product_id')
        if not raw_ids:
            return Response({"success": False, "error": "product_id or product_ids is required"}, status=status.HTTP_400_BAD_REQUEST)

        ids = []
        if isinstance(raw_ids, list):
            ids = raw_ids
        elif isinstance(raw_ids, str):
            try:
                import json
                parsed = json.loads(raw_ids)
                if isinstance(parsed, list):
                    ids = parsed
                else:
                    ids = [s.strip() for s in raw_ids.split(',') if s.strip()]
            except Exception:
                ids = [s.strip() for s in raw_ids.split(',') if s.strip()]
        else:
            return Response({"success": False, "error": "Invalid product_ids format"}, status=status.HTTP_400_BAD_REQUEST)

        added = []
        errors = []
        with transaction.atomic():
            for pid in ids:
                if ag.gift_product_id and str(ag.gift_product_id.id) == str(pid):
                    errors.append(f"Product {pid} is the gift product itself and cannot be an eligible product")
                    continue
                try:
                    prod = Product.objects.get(pk=pid, customer=seller)
                except Product.DoesNotExist:
                    errors.append(f"Product {pid} not found or not owned by seller")
                    continue
                if AppliedGiftProduct.objects.filter(applied_gift_id=ag, product_id=prod).exists():
                    continue
                AppliedGiftProduct.objects.create(applied_gift_id=ag, product_id=prod)
                added.append(str(prod.id))

        ag.refresh_from_db()
        eligible_ids = [str(ep.product_id.id) for ep in ag.eligible_products.all() if ep.product_id]

        return Response({
            "success": True, 
            "added": added, 
            "errors": errors, 
            "eligible_product_ids": eligible_ids,
            "message": f"Successfully added {len(added)} product(s) to gift promotion"
        }, status=status.HTTP_200_OK)
    
class CustomerGiftViewSet(viewsets.ViewSet):
    """
    Comprehensive ViewSet for customer gift management 
    (No shop required - for personal listings)
    """
    
    @action(detail=False, methods=['get'])
    def global_categories(self, request):
        """Get all global categories (no shop) for customer gifts"""
        try:
            categories = Category.objects.filter(shop__isnull=True).order_by('name')
            categories_data = []
            
            for category in categories:
                categories_data.append({
                    "id": str(category.id),
                    "name": category.name,
                    "shop": None,
                    "user": {
                        "id": str(category.user.id),
                        "username": category.user.username
                    } if category.user else None,
                })
            
            return Response({
                "success": True,
                "categories": categories_data,
                "message": "Global categories retrieved successfully",
                "total_count": len(categories_data)
            }, status=status.HTTP_200_OK)
            
        except Exception as e:
            return Response({
                "success": False,
                "error": "Failed to fetch global categories",
                "details": str(e)
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
    
    @action(detail=False, methods=['get'], url_path='active-applied-gift-product-ids')
    def active_applied_gift_product_ids(self, request):
        """
        Get IDs of gift products that are currently applied to promotions
        These should be hidden from regular product listings
        """
        try:
            from django.utils import timezone
            
            # Get all active AppliedGift records
            active_gifts = AppliedGift.objects.filter(
                is_active=True,
                start_time__lte=timezone.now(),
                end_time__gte=timezone.now()
            ).select_related('gift_product_id')
            
            # Extract unique gift product IDs
            gift_product_ids = []
            gift_details = {}
            
            for gift in active_gifts:
                if gift.gift_product_id and str(gift.gift_product_id.id) not in gift_product_ids:
                    product_id = str(gift.gift_product_id.id)
                    gift_product_ids.append(product_id)
                    gift_details[product_id] = {
                        'id': product_id,
                        'name': gift.gift_product_id.name,
                        'applied_gift_id': str(gift.id),
                        'shop_id': str(gift.shop_id.id) if gift.shop_id else None,
                        'start_time': gift.start_time.isoformat() if gift.start_time else None,
                        'end_time': gift.end_time.isoformat() if gift.end_time else None
                    }
            
            return Response({
                "success": True,
                "gift_product_ids": gift_product_ids,
                "gift_details": gift_details,
                "count": len(gift_product_ids),
                "message": "Active applied gift product IDs retrieved successfully"
            }, status=status.HTTP_200_OK)
            
        except Exception as e:
            print(f"Error fetching active applied gift product IDs: {str(e)}")
            import traceback
            traceback.print_exc()
            return Response({
                "success": False,
                "error": "Failed to fetch active applied gift product IDs",
                "details": str(e)
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
    
    @action(detail=False, methods=['post'])
    def create_gift(self, request):
        """
        Comprehensive gift creation for customers - handles everything:
        - Basic gift info
        - Categories (global only)
        - Media files
        - Variants
        - No price (always 0) and no swap features
        - No shop required
        """
        try:
            # Get user_id from headers or data
            user_id = request.data.get('customer_id') or request.headers.get('X-User-Id')
            
            if not user_id:
                return Response({
                    "error": "User ID is required"
                }, status=status.HTTP_400_BAD_REQUEST)
            
            # Get customer profile
            try:
                customer = Customer.objects.get(customer_id=user_id)
            except Customer.DoesNotExist:
                return Response({
                    "error": "Customer profile not found"
                }, status=status.HTTP_404_NOT_FOUND)
            
            # Check product limit (gifts count towards product limit)
            if not customer.can_add_product():
                return Response({
                    "error": f"Cannot add more than {customer.product_limit} products. Current count: {customer.current_product_count}"
                }, status=status.HTTP_400_BAD_REQUEST)
            
            # Prepare base gift data
            gift_data = {}
            
            # Handle single values (fix duplicates from FormData)
            single_value_fields = [
                'name', 'description', 'condition', 'category_admin_id', 
                'weight_unit', 'upload_status', 'status'
            ]
            
            for field in single_value_fields:
                value = request.data.get(field)
                if isinstance(value, list) and len(value) > 0:
                    gift_data[field] = value[0]  # Take first if list
                elif value is not None:
                    gift_data[field] = value
            
            # Handle numeric fields with validation
            numeric_fields = ['quantity', 'length', 'width', 'height', 'weight', 'critical_stock']
            for field in numeric_fields:
                value = request.data.get(field)
                if value:
                    try:
                        if isinstance(value, list) and len(value) > 0:
                            gift_data[field] = float(value[0])
                        else:
                            gift_data[field] = float(value)
                    except (ValueError, TypeError):
                        pass
            
            # Set customer and defaults
            gift_data['customer'] = customer.customer_id
            gift_data['upload_status'] = gift_data.get('upload_status', 'draft')
            gift_data['status'] = gift_data.get('status', 'active')
            
            # Set price to 0 for gifts
            gift_data['price'] = 0.0
            
            # Validate global category if provided
            category_admin_id = gift_data.get('category_admin_id')
            if category_admin_id and category_admin_id != "none":
                try:
                    Category.objects.get(id=category_admin_id, shop__isnull=True)
                except Category.DoesNotExist:
                    return Response({
                        "error": "Invalid global category selected"
                    }, status=status.HTTP_400_BAD_REQUEST)
            
            # Handle shipping zones (for customer gifts if needed)
            shipping_zones_raw = request.data.get('shipping_zones')
            if shipping_zones_raw:
                try:
                    if isinstance(shipping_zones_raw, str):
                        shipping_zones = json.loads(shipping_zones_raw)
                    else:
                        shipping_zones = shipping_zones_raw
                    
                    # Validate shipping zones
                    valid_zones = []
                    for zone in shipping_zones:
                        if isinstance(zone, dict) and 'name' in zone:
                            valid_zones.append({
                                'name': zone.get('name'),
                                'fee': float(zone.get('fee', 0)),
                                'free_shipping': bool(zone.get('free_shipping', False))
                            })
                    
                    if valid_zones:
                        gift_data['shipping_zones'] = valid_zones
                except (json.JSONDecodeError, TypeError, ValueError):
                    pass
            
            # Create gift with transaction
            with transaction.atomic():
                serializer = ProductCreateSerializer(
                    data=gift_data, 
                    context={'request': request}
                )
                
                if serializer.is_valid():
                    # Create the gift (shop will be null for customer gifts)
                    gift = serializer.save()
                    
                    # Handle media files
                    media_files = request.FILES.getlist('media_files', [])
                    for media_file in media_files:
                        ProductMedia.objects.create(
                            product=gift,
                            file_data=media_file,
                            file_type=media_file.content_type
                        )
                    
                    # Handle variants if provided
                    variants_raw = request.data.get('variants')
                    
                    if variants_raw:
                        # Parse variants data
                        try:
                            variants_list = json.loads(variants_raw) if isinstance(variants_raw, str) else variants_raw
                            
                            # Process variants (without swap features)
                            self._create_variants(
                                product=gift,
                                variants_data=variants_list,
                                files=request.FILES
                            )
                        except Exception as e:
                            print(f"Error processing variants: {type(e)} - {str(e)}")
                            import traceback
                            traceback.print_exc()
                            # Rollback transaction if variant creation fails
                            raise ValidationError(f"Failed to create variants: {str(e)}")
                    
                    # Increment customer's product count
                    customer.increment_product_count()
                    
                    # Return comprehensive success response
                    return Response({
                        "success": True,
                        "gift": self._get_gift_detail_data(gift),
                        "message": "Customer gift created successfully",
                        "product_limit": {
                            "current_count": customer.current_product_count,
                            "limit": customer.product_limit,
                            "remaining": customer.product_limit - customer.current_product_count
                        }
                    }, status=status.HTTP_201_CREATED)
                else:
                    return Response({
                        "error": "Validation failed",
                        "details": serializer.errors
                    }, status=status.HTTP_400_BAD_REQUEST)
                    
        except ValidationError as e:
            return Response({
                "error": "Validation failed",
                "details": str(e)
            }, status=status.HTTP_400_BAD_REQUEST)
            
        except Exception as e:
            import traceback
            traceback.print_exc()
            return Response({
                "error": "Gift creation failed",
                "details": str(e)
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
    
    def _create_variants(self, product, variants_data, files):
        """Helper method to create variants for customer gifts (no swap features)"""
        
        print(f"Creating variants for gift {product.id}")
        print(f"Variants data: {variants_data}")
        print(f"Files keys: {list(files.keys())}")
        
        # Create variants
        for variant_data in variants_data:
            # Safe Decimal conversion helper function
            def safe_decimal(value, default=None):
                if value is None or value == '':
                    return default
                try:
                    # Handle string or numeric values
                    if isinstance(value, str):
                        # Remove any whitespace and check if empty
                        value = value.strip()
                        if value == '':
                            return default
                        # Replace comma with dot for decimal separator
                        value = value.replace(',', '.')
                    return Decimal(str(value))
                except (ValueError, TypeError, InvalidOperation):
                    print(f"Warning: Could not convert '{value}' to Decimal, using default: {default}")
                    return default
            
            # Create variant - price always 0 for gifts
            variant = Variants.objects.create(
                product=product,
                shop=None,  # Customer gifts have no shop
                title=variant_data.get('title', ''),
                option_title=variant_data.get('option_title', ''),
                option_ids=variant_data.get('option_ids', []),
                option_map=variant_data.get('option_map', {}),
                sku_code=variant_data.get('sku_code', ''),
                price=Decimal('0.00'),  # Gifts always have price 0
                compare_price=safe_decimal(variant_data.get('compare_price'), None),
                quantity=int(variant_data.get('quantity', 0)),
                weight=safe_decimal(variant_data.get('weight'), None),
                weight_unit=variant_data.get('weight_unit', 'g'),
                critical_trigger=int(variant_data.get('critical_trigger')) if variant_data.get('critical_trigger') not in (None, '') else None,
                is_active=True,
                allow_swap=False,  # No swap for gifts
                swap_type='direct_swap',  # Default, not used
                minimum_additional_payment=Decimal('0.00'),  # No swap
                maximum_additional_payment=Decimal('0.00'),  # No swap
                swap_description='',  # No swap
                is_refundable=False,  # Gifts typically not refundable
                refund_days=0,
                original_price=None,
                usage_period=None,
                usage_unit=None,
                depreciation_rate=None,
                critical_stock=int(variant_data.get('critical_stock')) if variant_data.get('critical_stock') not in (None, '') else None
            )
            
            print(f"Created variant: {variant.id} - {variant.title}")
            
            # Handle variant image
            variant_id = variant_data.get('id')
            file_key = f"variant_image_{variant_id}" if variant_id else None
            
            if file_key and file_key in files:
                try:
                    variant.image = files[file_key]
                    variant.save()
                    print(f"Added image to variant {variant.id}")
                except Exception as e:
                    print('Failed to save variant image', e)

    def _get_gift_detail_data(self, gift):
        """Get detailed gift data for response"""
        # Get media files
        media_files = []
        for media in gift.productmedia_set.all():
            media_files.append({
                "id": str(media.id),
                "file_data": media.file_data.url if media.file_data else None,
                "file_type": media.file_type
            })
        
        # Get variants
        variants = []
        for variant in gift.variants.all():
            variant_data = {
                "id": str(variant.id),
                "title": variant.title,
                "option_title": variant.option_title,
                "option_ids": variant.option_ids,
                "option_map": variant.option_map,
                "sku_code": variant.sku_code,
                "price": str(variant.price) if variant.price else "0.00",  # Will be "0.00"
                "compare_price": str(variant.compare_price) if variant.compare_price else None,
                "quantity": variant.quantity,
                "weight": str(variant.weight) if variant.weight else None,
                "weight_unit": variant.weight_unit,
                "allow_swap": variant.allow_swap,  # Will always be False
                "swap_type": variant.swap_type,
                "minimum_additional_payment": str(variant.minimum_additional_payment) if variant.minimum_additional_payment else "0.00",
                "maximum_additional_payment": str(variant.maximum_additional_payment) if variant.maximum_additional_payment else "0.00",
                "swap_description": variant.swap_description,
                "image": variant.image.url if variant.image else None,
                "is_refundable": variant.is_refundable,
                "refund_days": variant.refund_days,
                "original_price": str(variant.original_price) if variant.original_price else None,
                "usage_period": variant.usage_period,
                "usage_unit": variant.usage_unit,
                "depreciation_rate": variant.depreciation_rate,
                "critical_stock": variant.critical_stock,
                "is_active": variant.is_active,
                "created_at": variant.created_at.isoformat() if variant.created_at else None,
            }
            variants.append(variant_data)
        
        return {
            "id": str(gift.id),
            "name": gift.name,
            "description": gift.description,
            "quantity": gift.quantity,
            "price": str(gift.price),  # Will be "0.00"
            "compare_price": str(gift.compare_price) if gift.compare_price else None,
            "upload_status": gift.upload_status,
            "status": gift.status,
            "condition": gift.condition,
            "category_admin": {
                "id": str(gift.category_admin.id),
                "name": gift.category_admin.name
            } if gift.category_admin else None,
            "media_files": media_files,
            "variants": variants,
            "dimensions": {
                "length": str(gift.length) if gift.length else None,
                "width": str(gift.width) if gift.width else None,
                "height": str(gift.height) if gift.height else None,
                "weight": str(gift.weight) if gift.weight else None,
                "weight_unit": gift.weight_unit,
            } if any([gift.length, gift.width, gift.height, gift.weight]) else None,
            "created_at": gift.created_at.isoformat(),
            "updated_at": gift.updated_at.isoformat(),
        }
    
    @action(detail=False, methods=['post'])
    def predict_category(self, request):
        """
        Predict category for a gift - Similar to product prediction but with price=0
        """
        try:
            import pandas as pd
            import numpy as np
            import tensorflow as tf
            import joblib
            import os
            
            CURRENT_DIR = os.path.dirname(os.path.abspath(__file__))
            MODEL_DIR = os.path.join(os.path.dirname(CURRENT_DIR), 'model')
            
            # Load models
            try:
                category_le = joblib.load(os.path.join(MODEL_DIR, 'category_label_encoder.pkl'))
                scaler = joblib.load(os.path.join(MODEL_DIR, 'scaler.pkl'))
                model = tf.keras.models.load_model(os.path.join(MODEL_DIR, 'category_classifier.keras'))
                feature_columns = joblib.load(os.path.join(MODEL_DIR, 'feature_columns.pkl'))
                
            except FileNotFoundError as e:
                return Response(
                    {'success': False, 'error': f'Model files not found. Please train the model first.'},
                    status=status.HTTP_500_INTERNAL_SERVER_ERROR
                )
            
            # Extract data from request
            data = request.data
            
            # Required fields - price not required since it's always 0 for gifts
            required_fields = ['name', 'description', 'quantity', 'condition']
            for field in required_fields:
                if field not in data:
                    return Response(
                        {'success': False, 'error': f'Missing required field: {field}'},
                        status=status.HTTP_400_BAD_REQUEST
                    )
            
            # Prepare item data - price always 0 for gifts
            item_data = {
                'name': str(data['name']),
                'description': str(data['description']),
                'quantity': int(data['quantity']),
                'price': 0.0,  # Gifts always have price 0
                'condition': str(data['condition'])
            }
            
            # Initialize all features to 0
            features = {col: 0 for col in feature_columns}
            
            # Basic numeric features
            price = item_data['price']  # This will be 0
            quantity = item_data['quantity']
            
            # Set only the features that exist in feature_columns
            if 'price' in feature_columns:
                features['price'] = price
            if 'quantity' in feature_columns:
                features['quantity'] = quantity
            if 'price_quantity_interaction' in feature_columns:
                features['price_quantity_interaction'] = price * np.log1p(quantity + 1)
            if 'log_price' in feature_columns:
                features['log_price'] = np.log1p(price)
            if 'price_per_unit' in feature_columns:
                features['price_per_unit'] = price / (quantity + 1)
            if 'price_to_quantity_ratio' in feature_columns:
                features['price_to_quantity_ratio'] = price / (quantity + 1e-5)
            if 'price_scaled' in feature_columns:
                features['price_scaled'] = price / 10000
            if 'quantity_scaled' in feature_columns:
                features['quantity_scaled'] = quantity / 100
            
            # Condition features
            condition_lower = item_data['condition'].lower()
            
            if 'condition_score' in feature_columns:
                if 'new' in condition_lower:
                    features['condition_score'] = 3
                elif 'like new' in condition_lower:
                    features['condition_score'] = 2
                elif 'refurbished' in condition_lower:
                    features['condition_score'] = 1
                elif 'excellent' in condition_lower:
                    features['condition_score'] = 0
                elif 'good' in condition_lower:
                    features['condition_score'] = -1
                elif 'fair' in condition_lower:
                    features['condition_score'] = -2
                else:
                    features['condition_score'] = 0
            
            # is_refurbished feature (if present)
            if 'is_refurbished' in feature_columns:
                features['is_refurbished'] = 1 if 'refurbished' in condition_lower else 0
            
            # Text features
            name_lower = item_data['name'].lower()
            desc_lower = item_data['description'].lower()
            all_text = name_lower + ' ' + desc_lower
            
            if 'name_length' in feature_columns:
                features['name_length'] = len(item_data['name'])
            if 'desc_length' in feature_columns:
                features['desc_length'] = len(item_data['description'])
            
            # Keyword features
            for feature in feature_columns:
                if feature.startswith('has_'):
                    keyword = feature[4:]  # Remove 'has_' prefix
                    features[feature] = 1 if keyword in all_text else 0
            
            # Price bins (all will be 0 since price is 0)
            if 'price_bin_0' in feature_columns:
                features['price_bin_0'] = 1 if price < 100 else 0  # This will be 1
            if 'price_bin_1' in feature_columns:
                features['price_bin_1'] = 1 if 100 <= price < 500 else 0
            if 'price_bin_2' in feature_columns:
                features['price_bin_2'] = 1 if 500 <= price < 1000 else 0
            if 'price_bin_3' in feature_columns:
                features['price_bin_3'] = 1 if 1000 <= price < 2000 else 0
            if 'price_bin_4' in feature_columns:
                features['price_bin_4'] = 1 if price >= 2000 else 0
            
            # Additional features
            if 'name_word_count' in feature_columns:
                features['name_word_count'] = len(item_data['name'].split())
            if 'desc_word_count' in feature_columns:
                features['desc_word_count'] = len(item_data['description'].split())
            
            # Create DataFrame
            X_item = pd.DataFrame([features])
            
            # Ensure we only have the expected features
            for col in feature_columns:
                if col not in X_item.columns:
                    X_item[col] = 0
            
            # Remove any columns not in feature_columns
            extra_cols = [col for col in X_item.columns if col not in feature_columns]
            if extra_cols:
                X_item = X_item.drop(columns=extra_cols)
            
            X_item = X_item[feature_columns]
            
            # Scale and predict
            try:
                X_scaled = scaler.transform(X_item)
            except Exception as e:
                X_scaled = X_item.values.astype(np.float32)
            
            # Make prediction
            prediction_probs = model.predict(X_scaled, verbose=0)
            predicted_class = np.argmax(prediction_probs, axis=1)[0]
            confidence = np.max(prediction_probs, axis=1)[0]
            
            # Convert predicted class to actual category label
            predicted_label = category_le.inverse_transform([predicted_class])[0]
            
            # Try to find the category in the database
            try:
                category_obj = Category.objects.filter(
                    name__iexact=predicted_label,
                    shop__isnull=True
                ).first()
                
                if category_obj:
                    category_uuid = str(category_obj.id)
                    category_name = category_obj.name
                else:
                    # Fallback
                    first_category = Category.objects.filter(shop__isnull=True).first()
                    if first_category:
                        category_uuid = str(first_category.id)
                        category_name = first_category.name
                    else:
                        category_uuid = None
                        category_name = predicted_label
                        
            except Exception as db_error:
                category_uuid = None
                category_name = predicted_label
            
            # Prepare response
            result = {
                'success': True,
                'predicted_category': {
                    'category_id': int(predicted_class),
                    'category_uuid': category_uuid,
                    'category_name': predicted_label,
                    'confidence': float(confidence)
                },
                'feature_insights': {
                    'condition': item_data['condition'],
                    'price': 0,  # Gifts have price 0
                    'quantity': int(quantity)
                }
            }
            
            return Response(result, status=status.HTTP_200_OK)
            
        except Exception as e:
            print(f"\n❌ PREDICTION ERROR: {str(e)}")
            import traceback
            traceback.print_exc()
            
            return Response(
                {
                    'success': False, 
                    'error': f'Prediction failed: {str(e)}'
                },
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )

class RiderDashboardViewSet(viewsets.ViewSet):
    """
    Rider Dashboard API endpoints with optimized queries and data integrity
    User authentication via X-User-Id header from frontend middleware
    """
    
    def _get_user_from_header(self, request):
        """Extract and validate user from X-User-Id header"""
        user_id = request.headers.get('X-User-Id')
        
        if not user_id:
            raise ValueError('X-User-Id header is required')
        
        try:
            user = User.objects.get(id=user_id)
            return user
        except User.DoesNotExist:
            raise ValueError(f'User with ID {user_id} does not exist')
    
    def get_queryset(self, user):
        """Get deliveries for the authenticated rider"""
        try:
            rider = user.rider
            return Delivery.objects.filter(rider=rider).select_related(
                'order',
                'order__user',
                'order__shipping_address'
            ).prefetch_related(
                'order__checkout_set__cart_item__product__shop'
            ).order_by('-created_at')
        except (Rider.DoesNotExist, AttributeError):
            return Delivery.objects.none()
    
    @action(detail=False, methods=['get'])
    def rider_dashboard(self, request):
        """
        Get comprehensive dashboard data for rider
        Returns metrics and recent delivery stats with date filtering
        """
        try:
            # Get user from X-User-Id header
            user = self._get_user_from_header(request)
            
            # Check if user is a rider
            if not hasattr(user, 'rider'):
                return Response({
                    'error': 'User is not a rider'
                }, status=status.HTTP_403_FORBIDDEN)
            
            # Get base queryset
            deliveries = self.get_queryset(user)
            
            # Get date range parameters from request
            start_date = request.query_params.get('start_date')
            end_date = request.query_params.get('end_date')
            
            # Apply date filtering if provided
            if start_date and end_date:
                try:
                    start_date_obj = datetime.strptime(start_date, '%Y-%m-%d').date()
                    end_date_obj = datetime.strptime(end_date, '%Y-%m-%d').date()
                    
                    # Filter deliveries by date range
                    deliveries = deliveries.filter(
                        created_at__date__gte=start_date_obj,
                        created_at__date__lte=end_date_obj
                    )
                except ValueError:
                    return Response(
                        {'error': 'Invalid date format. Use YYYY-MM-DD'},
                        status=status.HTTP_400_BAD_REQUEST
                    )
            
            if not deliveries.exists():
                return Response({
                    'metrics': self._get_empty_metrics(),
                    'deliveries': []
                })
            
            # Calculate metrics efficiently (now based on filtered deliveries)
            metrics = self._calculate_metrics(deliveries, user.rider)
            
            # Filter to only show active deliveries (exclude delivered and cancelled)
            active_deliveries = deliveries.exclude(
                status__in=['delivered', 'completed', 'cancelled']
            )[:50]  # Increased limit for date ranges
            
            delivery_serializer = DeliveryStatsSerializer(active_deliveries, many=True)
            
            # Post-process to normalize "pending_offer" to "pending"
            data = delivery_serializer.data
            
            return Response({
                'metrics': metrics,
                'deliveries': delivery_serializer.data
            })
            
        except ValueError as e:
            return Response(
                {'error': str(e)},
                status=status.HTTP_400_BAD_REQUEST
            )
        except Exception as e:
            return Response(
                {'error': str(e)},
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )
    
    def _calculate_metrics(self, deliveries, rider):
        """Calculate all metrics in optimized queries based on filtered deliveries"""
        
        # Update any delivered/completed deliveries with missing/zero delivery_fee before calculating metrics
        delivered_without_fee = deliveries.filter(
            status__in=['delivered', 'completed']
        ).filter(
            Q(delivery_fee__isnull=True) | Q(delivery_fee=0)
        )
        if delivered_without_fee.exists():
            delivered_without_fee.update(delivery_fee=Decimal('40.00'))
        
        # 1. Basic counts (single query)
        status_counts = deliveries.aggregate(
            total=Count('id'),
            delivered=Count('id', filter=Q(status__in=['delivered', 'completed'])),
            pending=Count('id', filter=Q(status__in=['pending', 'picked_up'])),
            cancelled=Count('id', filter=Q(status='cancelled'))
        )
        
        # 2. Total earnings from delivered orders (using delivery_fee)
        total_earnings = deliveries.filter(
            status__in=['delivered', 'completed']
        ).aggregate(
            total=Sum('delivery_fee')
        )['total'] or Decimal('0.00')
        
        # 3. Average delivery time in minutes
        delivered_deliveries = deliveries.filter(
            status__in=['delivered', 'completed'],
            picked_at__isnull=False,
            delivered_at__isnull=False
        )
        
        avg_delivery_minutes = 0
        if delivered_deliveries.exists():
            # Calculate average time difference in minutes
            total_seconds = 0
            count = 0
            
            for delivery in delivered_deliveries:
                if delivery.picked_at and delivery.delivered_at:
                    time_diff = (delivery.delivered_at - delivery.picked_at).total_seconds()
                    total_seconds += time_diff
                    count += 1
            
            if count > 0:
                avg_delivery_minutes = total_seconds / (60 * count)
        
        # 4. Average rating — ratings are stored in the Review model (not on Delivery)
        avg_rating = Review.objects.filter(
            rider=rider,
            delivery_rating__isnull=False
        ).aggregate(
            avg=Avg('delivery_rating')
        )['avg'] or 0
        
        # 5. On-time percentage (delivered within estimated time)
        on_time_deliveries = deliveries.filter(
            status__in=['delivered', 'completed'],
            estimated_minutes__isnull=False,
            actual_minutes__isnull=False,
            actual_minutes__lte=F('estimated_minutes')  # Actual <= Estimated
        ).count()
        
        delivered_count = status_counts['delivered']
        on_time_percentage = (on_time_deliveries / delivered_count * 100) if delivered_count > 0 else 0
        
        # 6. Current week deliveries (based on filtered data, but use actual current week)
        week_start = timezone.now() - timedelta(days=timezone.now().weekday())
        current_week_deliveries = deliveries.filter(
            created_at__gte=week_start,
            status__in=['delivered', 'completed']
        ).count()
        
        # 7. Current month earnings (based on filtered data, but use actual current month)
        # Uses delivery_fee (rider's actual earnings) not order total_amount
        month_start = timezone.now().replace(day=1, hour=0, minute=0, second=0, microsecond=0)
        current_month_earnings = deliveries.filter(
            status__in=['delivered', 'completed'],
            delivered_at__gte=month_start
        ).aggregate(
            total=Sum('delivery_fee')
        )['total'] or Decimal('0.00')
        
        # 8. Growth metrics - calculate based on the filtered date range
        # If date range is provided, use it for growth calculation
        growth_metrics = self._calculate_growth_metrics(deliveries, rider)
        
        return {
            'total_deliveries': status_counts['total'],
            'completed_deliveries': status_counts['delivered'],
            'pending_deliveries': status_counts['pending'],
            'cancelled_deliveries': status_counts['cancelled'],
            'total_earnings': float(total_earnings),
            'avg_delivery_time': round(avg_delivery_minutes, 1),
            'avg_rating': round(avg_rating, 1),
            'on_time_percentage': round(on_time_percentage, 1),
            'current_week_deliveries': current_week_deliveries,
            'current_month_earnings': float(current_month_earnings),
            'has_data': status_counts['total'] > 0,
            'growth_metrics': growth_metrics
        }
    
    def _calculate_growth_metrics(self, deliveries, rider):
        """
        Calculate growth compared to previous period of same duration
        Based on the filtered date range or default to last 7 days
        """
        # Get the date range of the filtered deliveries
        if deliveries.exists():
            date_range = deliveries.aggregate(
                min_date=Min('created_at'),
                max_date=Max('created_at')
            )
            
            start_date = date_range['min_date']
            end_date = date_range['max_date']
            
            # Calculate period duration in days
            if start_date and end_date:
                period_days = (end_date - start_date).days + 1
            else:
                period_days = 7
        else:
            period_days = 7
        
        # Current period (the filtered date range)
        current_deliveries = deliveries.filter(status__in=['delivered', 'completed']).count()
        current_earnings = deliveries.filter(
            status__in=['delivered', 'completed']
        ).aggregate(
            total=Sum('delivery_fee')
        )['total'] or Decimal('0.00')
        
        # For growth comparison, we need to get previous period data
        # If we have a date range, get the same duration before that
        try:
            if deliveries.exists() and 'min_date' in locals():
                previous_start = start_date - timedelta(days=period_days)
                previous_end = start_date - timedelta(days=1)
                
                # Get all deliveries for the rider to query previous period
                all_deliveries = deliveries.model.objects.filter(
                    rider=deliveries.first().rider
                )
                
                previous_period = all_deliveries.filter(
                    created_at__date__gte=previous_start.date(),
                    created_at__date__lte=previous_end.date()
                )
                
                previous_deliveries = previous_period.filter(status__in=['delivered', 'completed']).count()
                previous_earnings = previous_period.filter(
                    status__in=['delivered', 'completed']
                ).aggregate(
                    total=Sum('delivery_fee')
                )['total'] or Decimal('0.00')
                
                # Rating for previous period — query from Review model
                previous_rating = Review.objects.filter(
                    rider=rider,
                    delivery_rating__isnull=False,
                    created_at__date__gte=previous_start.date(),
                    created_at__date__lte=previous_end.date()
                ).aggregate(
                    avg=Avg('delivery_rating')
                )['avg'] or 0
                
            else:
                # Default to 7-day comparison if no date range
                previous_deliveries = 0
                previous_earnings = Decimal('0.00')
                previous_rating = 0
                
        except:
            # Fallback in case of any error
            previous_deliveries = 0
            previous_earnings = Decimal('0.00')
            previous_rating = 0
            period_days = 7
        
        # Calculate growth percentages
        deliveries_growth = 0
        earnings_growth = 0
        
        if previous_deliveries > 0:
            deliveries_growth = ((current_deliveries - previous_deliveries) / previous_deliveries) * 100
        elif current_deliveries > 0:
            deliveries_growth = 100  # 100% growth from 0
        
        if previous_earnings > 0:
            earnings_growth = ((current_earnings - previous_earnings) / previous_earnings) * 100
        elif current_earnings > 0:
            earnings_growth = 100  # 100% growth from 0
        
        # Rating growth — query from Review model
        current_rating = Review.objects.filter(
            rider=rider,
            delivery_rating__isnull=False
        ).aggregate(
            avg=Avg('delivery_rating')
        )['avg'] or 0
        
        rating_growth = 0
        if previous_rating > 0:
            rating_growth = ((current_rating - previous_rating) / previous_rating) * 100
        elif current_rating > 0:
            rating_growth = 100  # 100% growth from 0
        
        return {
            'deliveries_growth': round(deliveries_growth, 1),
            'earnings_growth': round(earnings_growth, 1),
            'rating_growth': round(rating_growth, 1),
            'previous_period_deliveries': previous_deliveries,
            'previous_period_earnings': float(previous_earnings),
            'period_days': period_days
        }
    
    def _get_empty_metrics(self):
        """Return empty metrics structure"""
        return {
            'total_deliveries': 0,
            'completed_deliveries': 0,
            'pending_deliveries': 0,
            'cancelled_deliveries': 0,
            'total_earnings': 0.0,
            'avg_delivery_time': 0,
            'avg_rating': 0,
            'on_time_percentage': 0,
            'current_week_deliveries': 0,
            'current_month_earnings': 0.0,
            'has_data': False,
            'growth_metrics': {
                'deliveries_growth': 0,
                'earnings_growth': 0,
                'rating_growth': 0,
                'previous_period_deliveries': 0,
                'previous_period_earnings': 0.0,
                'period_days': 7
            }
        }

class RiderEarningsViewSet(viewsets.ViewSet):
    """
    Rider Earnings API - track delivery fee earnings by time period
    """
    
    def _get_user_from_header(self, request):
        """Extract and validate user from X-User-Id header"""
        user_id = request.headers.get('X-User-Id')
        
        if not user_id:
            raise ValueError('X-User-Id header is required')
        
        try:
            user = User.objects.get(id=user_id)
            return user
        except User.DoesNotExist:
            raise ValueError(f'User with ID {user_id} does not exist')
    
    def list(self, request):
        """
        Get rider earnings breakdown for today, this week, and this month
        Returns all delivered orders with their delivery fees
        """
        try:
            # Get user from X-User-Id header
            user = self._get_user_from_header(request)
            
            # Check if user is a rider
            if not hasattr(user, 'rider'):
                return Response({
                    'error': 'User is not a rider'
                }, status=status.HTTP_403_FORBIDDEN)
            
            rider = user.rider
            now = timezone.now()
            today_start = now.replace(hour=0, minute=0, second=0, microsecond=0)
            week_start = today_start - timedelta(days=now.weekday())
            month_start = today_start.replace(day=1)
            
            # Helper function to get earnings for a period
            def get_period_earnings(start_date, end_date):
                # Include deliveries that are:
                # 1. Delivered with delivered_at in the date range, OR
                # 2. Delivered with NULL delivered_at (fallback to updated_at), OR
                # 3. Delivered recently (last 30 days) if no timestamp
                deliveries = Delivery.objects.filter(
                    rider=rider,
                    status__in=['delivered', 'completed']
                ).filter(
                    Q(delivered_at__date__gte=start_date.date(), delivered_at__date__lte=end_date.date()) |
                    Q(delivered_at__isnull=True, updated_at__date__gte=start_date.date(), updated_at__date__lte=end_date.date())
                ).select_related('order__user')
                
                # Update any delivered deliveries with missing/zero delivery_fee
                deliveries_to_update = deliveries.filter(
                    Q(delivery_fee__isnull=True) | Q(delivery_fee=0)
                )
                if deliveries_to_update.exists():
                    deliveries_to_update.update(delivery_fee=Decimal('40.00'))
                
                # Refresh the queryset to get updated values
                deliveries = Delivery.objects.filter(
                    rider=rider,
                    status__in=['delivered', 'completed']
                ).filter(
                    Q(delivered_at__date__gte=start_date.date(), delivered_at__date__lte=end_date.date()) |
                    Q(delivered_at__isnull=True, updated_at__date__gte=start_date.date(), updated_at__date__lte=end_date.date())
                ).select_related('order__user')
                
                total_fees = deliveries.aggregate(
                    total=Sum('delivery_fee')
                )['total'] or Decimal('0.00')
                
                return float(total_fees), list(deliveries.values(
                    'id',
                    'delivery_fee',
                    'status',
                    'created_at',
                    'delivered_at',
                    'order__user__first_name'
                ))
            
            # Get earnings for each period
            today_earnings, today_deliveries = get_period_earnings(today_start, now)
            week_earnings, week_deliveries = get_period_earnings(week_start, now)
            month_earnings, month_deliveries = get_period_earnings(month_start, now)
            
            # Format deliveries response
            def format_deliveries(deliveries_data):
                return [
                    {
                        'id': d['id'],
                        'delivery_fee': float(d['delivery_fee'] or 0),
                        'status': d['status'],
                        'shop_name': d['order__user__first_name'] or 'Unknown',
                        'created_at': d['created_at'].isoformat() if d['created_at'] else None,
                        'delivered_at': d['delivered_at'].isoformat() if d['delivered_at'] else d['created_at'].isoformat()
                    }
                    for d in deliveries_data
                    if d['delivery_fee'] and float(d['delivery_fee']) > 0  # Only include deliveries with valid fees
                ]
            
            return Response({
                'today_earnings': today_earnings,
                'week_earnings': week_earnings,
                'month_earnings': month_earnings,
                'deliveries': format_deliveries(
                    list(month_deliveries)  # Show all deliveries from current month
                )
            }, status=status.HTTP_200_OK)
        
        except ValueError as e:
            return Response(
                {'error': str(e)},
                status=status.HTTP_401_UNAUTHORIZED
            )
        except Exception as e:
            return Response(
                {'error': str(e)},
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )

