class RiderDeliveryActionsViewSet(viewsets.ViewSet):
    """
    Rider Delivery Actions API - Mark pickups and deliveries with proof
    """
    
    def _get_user_from_header(self, request):
        """Extract and validate user from X-User-Id header"""
        user_id = request.headers.get('X-User-Id')
        
        if not user_id:
            raise ValueError('X-User-Id header is required')
        
        try:
            user = User.objects.get(id=user_id)
            return user
        except User.DoesNotExist:
            raise ValueError(f'User with ID {user_id} does not exist')
    
    @action(detail=True, methods=['post'], url_path='mark-pickup')
    def mark_pickup(self, request, pk=None):
        """
        Mark delivery as picked up with optional proof photo
        POST /rider-delivery-actions/{delivery_id}/mark-pickup/
        
        Body:
        - pickup_proof: image file (optional)
        - notes: string (optional)
        """
        try:
            # Get user from header
            user = self._get_user_from_header(request)
            
            # Check if user is a rider
            if not hasattr(user, 'rider'):
                return Response({
                    'error': 'User is not a rider'
                }, status=status.HTTP_403_FORBIDDEN)
            
            # Get delivery
            try:
                delivery = Delivery.objects.get(id=pk, rider=user.rider)
            except Delivery.DoesNotExist:
                return Response({
                    'error': 'Delivery not found or not assigned to you'
                }, status=status.HTTP_404_NOT_FOUND)
            
            # Check if already picked up
            if delivery.status not in ['pending']:
                return Response({
                    'error': f'Cannot mark as picked up. Current status: {delivery.status}'
                }, status=status.HTTP_400_BAD_REQUEST)
            
            # Update delivery
            delivery.status = 'picked_up'
            delivery.picked_at = timezone.now()
            
            # Handle proof upload if provided
            if 'pickup_proof' in request.FILES:
                delivery.pickup_proof = request.FILES['pickup_proof']
            
            # Add notes if provided
            if 'notes' in request.data:
                current_notes = delivery.notes or ''
                pickup_note = f"\n[PICKUP {timezone.now().strftime('%Y-%m-%d %H:%M')}]: {request.data['notes']}"
                delivery.notes = current_notes + pickup_note
            
            delivery.save()
            
            return Response({
                'success': True,
                'message': 'Delivery marked as picked up',
                'data': {
                    'delivery_id': str(delivery.id),
                    'status': delivery.status,
                    'picked_at': delivery.picked_at.isoformat(),
                    'has_proof': bool(delivery.pickup_proof)
                }
            }, status=status.HTTP_200_OK)
        
        except ValueError as e:
            return Response(
                {'error': str(e)},
                status=status.HTTP_401_UNAUTHORIZED
            )
        except Exception as e:
            return Response(
                {'error': str(e)},
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )
    
    @action(detail=True, methods=['post'], url_path='mark-delivered')
    def mark_delivered(self, request, pk=None):
        """
        Mark delivery as delivered with optional proof photo
        POST /rider-delivery-actions/{delivery_id}/mark-delivered/
        
        Body:
        - delivery_proof: image file (optional)
        - notes: string (optional)
        """
        try:
            # Get user from header
            user = self._get_user_from_header(request)
            
            # Check if user is a rider
            if not hasattr(user, 'rider'):
                return Response({
                    'error': 'User is not a rider'
                }, status=status.HTTP_403_FORBIDDEN)
            
            # Get delivery
            try:
                delivery = Delivery.objects.get(id=pk, rider=user.rider)
            except Delivery.DoesNotExist:
                return Response({
                    'error': 'Delivery not found or not assigned to you'
                }, status=status.HTTP_404_NOT_FOUND)
            
            # Check if picked up first
            if delivery.status not in ['picked_up', 'in_progress']:
                return Response({
                    'error': f'Cannot mark as delivered. Current status: {delivery.status}. Must be picked up first.'
                }, status=status.HTTP_400_BAD_REQUEST)
            
            # Update delivery
            delivery.status = 'delivered'
            delivery.delivered_at = timezone.now()
            
            # Calculate actual delivery time if picked_at exists
            if delivery.picked_at:
                time_diff = delivery.delivered_at - delivery.picked_at
                delivery.actual_minutes = int(time_diff.total_seconds() / 60)
            
            # Handle proof upload if provided
            if 'delivery_proof' in request.FILES:
                delivery.delivery_proof = request.FILES['delivery_proof']
            
            # Add notes if provided
            if 'notes' in request.data:
                current_notes = delivery.notes or ''
                delivery_note = f"\n[DELIVERED {timezone.now().strftime('%Y-%m-%d %H:%M')}]: {request.data['notes']}"
                delivery.notes = current_notes + delivery_note
            
            # Ensure delivery_fee is set (for backward compatibility)
            if not delivery.delivery_fee or delivery.delivery_fee == 0:
                delivery.delivery_fee = Decimal('40.00')
            
            delivery.save()
            
            # Update order status to delivered
            order = delivery.order
            order.status = 'delivered'
            order.completed_at = delivery.delivered_at
            order.save()
            
            # Credit delivery fee to rider's wallet
            if delivery.delivery_fee and delivery.delivery_fee > 0:
                try:
                    rider_user = user.rider.user
                    wallet, _ = UserWallet.objects.get_or_create(user=rider_user)
                    
                    wallet.available_balance += delivery.delivery_fee
                    wallet.save()
                    
                    # Create wallet transaction record for Delivery Fee
                    WalletTransaction.objects.create(
                        wallet=wallet,
                        user=rider_user,
                        amount=delivery.delivery_fee,
                        transaction_type='credit',
                        source_type='delivery_fee',
                        status='completed',
                        order=order
                    )
                    
                except Exception as e:
                    print(f"Error crediting delivery fee to wallet: {e}")
            
            # Also create a wallet transaction record for Total Collected Money (COD)
            # This is purely for display in the transaction history and does NOT increase available_balance
            if order.payment_method == 'Cash on Delivery' and order.total_amount and order.total_amount > 0:
                try:
                    rider_user = user.rider.user
                    wallet, _ = UserWallet.objects.get_or_create(user=rider_user)
                    WalletTransaction.objects.create(
                        wallet=wallet,
                        user=rider_user,
                        amount=order.total_amount,
                        transaction_type='credit',
                        source_type='cod_collection',
                        status='completed',
                        order=order
                    )
                except Exception as e:
                    print(f"Error logging cod collection to wallet: {e}")
            
            return Response({
                'success': True,
                'message': 'Delivery marked as delivered',
                'data': {
                    'delivery_id': str(delivery.id),
                    'order_id': str(order.order),
                    'status': delivery.status,
                    'delivered_at': delivery.delivered_at.isoformat(),
                    'actual_minutes': delivery.actual_minutes,
                    'delivery_fee': float(delivery.delivery_fee) if delivery.delivery_fee else 0,
                    'has_proof': bool(delivery.delivery_proof)
                }
            }, status=status.HTTP_200_OK)
        
        except ValueError as e:
            return Response(
                {'error': str(e)},
                status=status.HTTP_401_UNAUTHORIZED
            )
        except Exception as e:
            return Response(
                {'error': str(e)},
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )

class RiderOrderHistoryViewSet(viewsets.ViewSet):
    """
    Rider Order History API endpoints with optimized queries and data integrity
    """

    # ================================================================
    # PRIVATE HELPERS
    # ================================================================

    def _get_user_from_header(self, request):
        """Extract and validate user from X-User-Id header"""
        user_id = request.headers.get('X-User-Id')
        if not user_id:
            raise ValueError('X-User-Id header is required')
        try:
            user_uuid = uuid.UUID(user_id)
            user = User.objects.get(id=user_uuid)
            return user
        except (ValueError, User.DoesNotExist):
            raise ValueError(f'Invalid or non-existent user ID: {user_id}')

    def get_queryset(self, user):
        """Get optimized queryset for rider's deliveries with all necessary relations"""
        try:
            rider = user.rider
            return Delivery.objects.filter(rider=rider).select_related(
                'order',
                'order__user',
                'order__shipping_address'
            ).prefetch_related(
                'order__payment_set'
            ).order_by('-created_at')
        except (Rider.DoesNotExist, AttributeError):
            return Delivery.objects.none()

    def _apply_date_filter(self, queryset, start_date, end_date):
        """Apply date filtering to queryset"""
        if start_date and end_date:
            return queryset.filter(
                created_at__date__gte=start_date,
                created_at__date__lte=end_date
            )
        return queryset

    def _is_cod_order(self, order):
        """Check if order is Cash on Delivery"""
        return order.payment_method and order.payment_method.lower() in ['cod', 'cash on delivery', 'cash']

    def _calculate_amount_to_remit(self, order, delivery):
        """Calculate total amount rider needs to remit for an order"""
        if self._is_cod_order(order):
            return float(order.total_amount) + float(delivery.delivery_fee or 0)
        else:
            return float(delivery.delivery_fee or 0)

    def _calculate_rider_earnings(self, delivery):
        """Calculate rider's earnings from delivery"""
        return float(delivery.delivery_fee or 0)

    def _get_unremitted_deliveries_queryset(self, user):
        """
        Returns delivered deliveries that have NOT been included
        in a completed remittance. Used by both unremitted_amounts
        and initiate_remittance to stay in sync.
        """
        return self.get_queryset(user).filter(
            status__in=['delivered', 'completed'],
            delivered_at__isnull=False
        ).exclude(
            remittance_items__remittance__status='completed'
        )

    # ================================================================
    # ORDER HISTORY
    # ================================================================

    @action(detail=False, methods=['get'])
    def order_history(self, request):
        """
        Get comprehensive order history for rider with metrics.
        Query params: status (optional), start_date (YYYY-MM-DD), end_date (YYYY-MM-DD)
        """
        try:
            user = self._get_user_from_header(request)

            if not hasattr(user, 'rider'):
                return Response({
                    'success': False,
                    'error': 'User is not a rider'
                }, status=status.HTTP_403_FORBIDDEN)

            status_filter = request.query_params.get('status', 'all')
            start_date = request.query_params.get('start_date')
            end_date = request.query_params.get('end_date')
            deliveries = self.get_queryset(user)

            # Apply date filtering if provided (matches dashboard behavior)
            if start_date and end_date:
                deliveries = self._apply_date_filter(deliveries, start_date, end_date)

            if status_filter != 'all':
                status_map = {
                    'completed': {'status__in': ['delivered', 'completed']},
                    'active':    {'status__in': ['pending', 'picked_up', 'in_progress', 'accepted']},
                    'cancelled': {'status': 'cancelled'},
                    'pending':   {'status': 'pending'},
                    'accepted':  {'status': 'accepted'},
                    'picked_up': {'status': 'picked_up'},
                    'in_progress': {'status': 'in_progress'},
                    'delivered': {'status__in': ['delivered', 'completed']},
                }
                if status_filter in status_map:
                    deliveries = deliveries.filter(**status_map[status_filter])
                else:
                    deliveries = deliveries.filter(status=status_filter)

            metrics = self._calculate_all_time_metrics(deliveries, user.rider)
            deliveries_data = self._format_delivery_data(deliveries)

            return Response({
                'success': True,
                'metrics': metrics,
                'deliveries': deliveries_data,
                'count': len(deliveries_data),
                'filters': {'status': status_filter, 'start_date': start_date, 'end_date': end_date}
            })

        except ValueError as e:
            return Response({'success': False, 'error': str(e)}, status=status.HTTP_400_BAD_REQUEST)
        except Exception as e:
            return Response({'success': False, 'error': f'An unexpected error occurred: {str(e)}'}, status=status.HTTP_500_INTERNAL_SERVER_ERROR)

    # ================================================================
    # METRICS
    # ================================================================

    def _calculate_all_time_metrics(self, deliveries, rider):
        """Calculate comprehensive all-time metrics for the rider"""
        if not deliveries.exists():
            return self._get_empty_metrics()

        # Backfill any delivered/completed deliveries with missing/zero delivery_fee
        # This ensures older deliveries without a fee are counted properly
        delivered_without_fee = deliveries.filter(
            status__in=['delivered', 'completed']
        ).filter(
            Q(delivery_fee__isnull=True) | Q(delivery_fee=0)
        )
        if delivered_without_fee.exists():
            delivered_without_fee.update(delivery_fee=Decimal('40.00'))

        delivered_deliveries = deliveries.filter(status__in=['delivered', 'completed'])

        total_earnings = 0.0
        total_to_remit = 0.0
        total_cod_amount = 0.0
        total_online_amount = 0.0
        cod_count = 0
        online_count = 0

        for delivery in delivered_deliveries:
            order = delivery.order
            is_cod = self._is_cod_order(order)
            total_earnings += float(delivery.delivery_fee or 0)
            if is_cod:
                total_to_remit += float(order.total_amount) + float(delivery.delivery_fee or 0)
                total_cod_amount += float(order.total_amount)
                cod_count += 1
            else:
                total_to_remit += float(delivery.delivery_fee or 0)
                total_online_amount += float(order.total_amount)
                online_count += 1

        # Calculate week earnings and today deliveries
        now = timezone.now()
        week_start = now - timedelta(days=now.weekday())
        week_start = week_start.replace(hour=0, minute=0, second=0, microsecond=0)
        today_start = now.replace(hour=0, minute=0, second=0, microsecond=0)

        week_earnings = deliveries.filter(
            status__in=['delivered', 'completed'],
            delivered_at__gte=week_start
        ).aggregate(
            total=Sum('delivery_fee')
        )['total'] or 0
        week_earnings = float(week_earnings)

        today_deliveries = deliveries.filter(
            status__in=['delivered', 'completed'],
            delivered_at__gte=today_start
        ).count()

        aggregated = deliveries.aggregate(
            total_deliveries=Count('id'),
            delivered_count=Count('id', filter=Q(status__in=['delivered', 'completed'])),
            completed_count=Count('id', filter=Q(status__in=['delivered', 'completed'])),
            cancelled_count=Count('id', filter=Q(status='cancelled')),
            declined_count=Count('id', filter=Q(status='declined')),
            pending_count=Count('id', filter=Q(status='pending')),
            accepted_count=Count('id', filter=Q(status='accepted')),
            picked_up_count=Count('id', filter=Q(status='picked_up')),
            in_progress_count=Count('id', filter=Q(status='in_progress')),
            avg_delivery_time=Avg(
                F('actual_minutes'),
                filter=Q(status__in=['delivered', 'completed'], actual_minutes__isnull=False)
            ),
            # avg_rating removed from aggregate — queried from Review model below
            on_time_count=Count(
                'id',
                filter=Q(
                    status__in=['delivered', 'completed'],
                    estimated_minutes__isnull=False,
                    actual_minutes__isnull=False,
                    actual_minutes__lte=F('estimated_minutes')
                )
            ),
            total_distance=Coalesce(
                Sum('distance_km', filter=Q(status__in=['delivered', 'completed'])),
                Decimal('0.00'),
                output_field=DecimalField()
            )
        )

        delivered_count = aggregated['delivered_count'] or 0
        on_time_percentage = 0
        if delivered_count > 0:
            on_time_percentage = round((aggregated['on_time_count'] / delivered_count) * 100, 1)

        date_range = deliveries.filter(status__in=['delivered', 'completed']).aggregate(
            first_delivery=Min('delivered_at'),
            last_delivery=Max('delivered_at')
        )

        unremitted_data = delivered_deliveries.aggregate(unremitted_count=Count('id'))

        # Calculate deductions from disputes
        try:
            from .models import WalletTransaction, UserWallet
            rider_wallet = UserWallet.objects.get(user=rider.user)
            deductions = WalletTransaction.objects.filter(
                wallet=rider_wallet,
                transaction_type='debit',
                source_type='dispute'
            ).aggregate(total=Sum('amount'))['total'] or 0.0
            deductions = float(deductions)
        except Exception:
            deductions = 0.0

        return {
            'total_deliveries': aggregated['total_deliveries'],
            'delivered_count': aggregated['delivered_count'],
            'completed_count': aggregated.get('completed_count', 0),
            'cancelled_count': aggregated['cancelled_count'],
            'declined_count': aggregated.get('declined_count', 0),
            'pending_count': aggregated['pending_count'],
            'accepted_count': aggregated['accepted_count'],
            'picked_up_count': aggregated['picked_up_count'],
            'in_progress_count': aggregated['in_progress_count'],
            'total_earnings': total_earnings,
            'week_earnings': week_earnings,
            'today_deliveries': today_deliveries,
            'total_to_remit': total_to_remit,
            'cod_orders': {
                'count': cod_count,
                'total_order_amount': total_cod_amount,
                'total_with_fees': total_cod_amount
            },
            'online_orders': {
                'count': online_count,
                'total_order_amount': total_online_amount,
                'total_with_fees': total_online_amount
            },
            'deductions': deductions,
            'unremitted_count': unremitted_data['unremitted_count'],
            'avg_delivery_time': round(aggregated['avg_delivery_time'] or 0, 1),
            'avg_rating': round(
                Review.objects.filter(
                    rider=rider,
                    delivery_rating__isnull=False
                ).aggregate(avg=Avg('delivery_rating'))['avg'] or 0, 1
            ),
            'on_time_percentage': on_time_percentage,
            'total_distance_km': float(aggregated['total_distance']),
            'first_delivery': date_range['first_delivery'].isoformat() if date_range['first_delivery'] else None,
            'last_delivery': date_range['last_delivery'].isoformat() if date_range['last_delivery'] else None,
            'has_data': aggregated['total_deliveries'] > 0,
            'rider_since': rider.approval_date.isoformat() if rider.approval_date else None,
            'rider_verified': rider.verified,
            'rider_status': rider.availability_status,
            'sandbox_mode': getattr(settings, 'ENABLE_SANDBOX', False)
        }

    def _calculate_metrics(self, deliveries, rider, start_date=None, end_date=None):
        """Calculate metrics for a filtered queryset"""
        if not deliveries.exists():
            return self._get_empty_metrics()

        # Backfill any delivered/completed deliveries with missing/zero delivery_fee
        delivered_without_fee = deliveries.filter(
            status__in=['delivered', 'completed']
        ).filter(
            Q(delivery_fee__isnull=True) | Q(delivery_fee=0)
        )
        if delivered_without_fee.exists():
            delivered_without_fee.update(delivery_fee=Decimal('40.00'))

        delivered_deliveries = deliveries.filter(status__in=['delivered', 'completed'])

        total_earnings = 0.0
        total_to_remit = 0.0

        for delivery in delivered_deliveries:
            order = delivery.order
            total_earnings += float(delivery.delivery_fee or 0)
            if self._is_cod_order(order):
                total_to_remit += float(order.total_amount) + float(delivery.delivery_fee or 0)
            else:
                total_to_remit += float(delivery.delivery_fee or 0)

        aggregated = deliveries.aggregate(
            total_deliveries=Count('id'),
            delivered_count=Count('id', filter=Q(status__in=['delivered', 'completed'])),
            completed_count=Count('id', filter=Q(status__in=['delivered', 'completed'])),
            cancelled_count=Count('id', filter=Q(status='cancelled')),
            declined_count=Count('id', filter=Q(status='declined')),
            avg_delivery_time=Avg(
                F('actual_minutes'),
                filter=Q(status__in=['delivered', 'completed'], actual_minutes__isnull=False)
            ),
            # avg_rating removed from aggregate — queried from Review model below
            on_time_count=Count(
                'id',
                filter=Q(
                    status__in=['delivered', 'completed'],
                    estimated_minutes__isnull=False,
                    actual_minutes__isnull=False,
                    actual_minutes__lte=F('estimated_minutes')
                )
            )
        )

        delivered_count = aggregated['delivered_count'] or 0
        on_time_percentage = 0
        if delivered_count > 0:
            on_time_percentage = round((aggregated['on_time_count'] / delivered_count) * 100, 1)

        today_start = timezone.now().replace(hour=0, minute=0, second=0, microsecond=0)
        today_deliveries = deliveries.filter(status__in=['delivered', 'completed'], delivered_at__gte=today_start).count()

        week_start = timezone.now() - timedelta(days=timezone.now().weekday())
        week_deliveries = deliveries.filter(status__in=['delivered', 'completed'], delivered_at__gte=week_start)

        week_earnings = 0.0
        week_to_remit = 0.0
        for delivery in week_deliveries:
            order = delivery.order
            week_earnings += float(delivery.delivery_fee or 0)
            if self._is_cod_order(order):
                week_to_remit += float(order.total_amount) + float(delivery.delivery_fee or 0)
            else:
                week_to_remit += float(delivery.delivery_fee or 0)

        return {
            'total_deliveries': aggregated['total_deliveries'],
            'delivered_count': aggregated['delivered_count'],
            'completed_count': aggregated.get('completed_count', 0),
            'cancelled_count': aggregated['cancelled_count'],
            'declined_count': aggregated.get('declined_count', 0),
            'total_earnings': total_earnings,
            'total_to_remit': total_to_remit,
            'avg_delivery_time': round(aggregated['avg_delivery_time'] or 0, 1),
            'avg_rating': round(
                Review.objects.filter(
                    rider=rider,
                    delivery_rating__isnull=False
                ).aggregate(avg=Avg('delivery_rating'))['avg'] or 0, 1
            ),
            'on_time_percentage': on_time_percentage,
            'today_deliveries': today_deliveries,
            'week_earnings': week_earnings,
            'week_to_remit': week_to_remit,
            'has_data': aggregated['total_deliveries'] > 0,
            'date_range': {'start_date': start_date, 'end_date': end_date},
            'sandbox_mode': getattr(settings, 'ENABLE_SANDBOX', False)
        }

    def _get_empty_metrics(self):
        return {
            'total_deliveries': 0,
            'delivered_count': 0,
            'cancelled_count': 0,
            'pending_count': 0,
            'accepted_count': 0,
            'picked_up_count': 0,
            'in_progress_count': 0,
            'total_earnings': 0.0,
            'total_to_remit': 0.0,
            'cod_orders': {'count': 0, 'total_order_amount': 0.0, 'total_with_fees': 0.0},
            'online_orders': {'count': 0, 'total_order_amount': 0.0, 'total_with_fees': 0.0},
            'unremitted_count': 0,
            'avg_delivery_time': 0,
            'avg_rating': 0,
            'on_time_percentage': 0,
            'total_distance_km': 0.0,
            'completed_count': 0,
            'declined_count': 0,
            'week_earnings': 0.0,
            'today_deliveries': 0,
            'first_delivery': None,
            'last_delivery': None,
            'has_data': False,
            'rider_since': None,
            'rider_verified': False,
            'rider_status': None,
            'sandbox_mode': getattr(settings, 'ENABLE_SANDBOX', False)
        }

    # ================================================================
    # UNREMITTED AMOUNTS
    # ================================================================

    @action(detail=False, methods=['get'])
    def unremitted_amounts(self, request):
        """
        Get all unremitted amounts for the rider.
        Excludes deliveries already covered by a completed remittance.
        Query params: start_date, end_date
        """
        try:
            user = self._get_user_from_header(request)

            if not hasattr(user, 'rider'):
                return Response({'success': False, 'error': 'User is not a rider'}, status=status.HTTP_403_FORBIDDEN)

            start_date = request.query_params.get('start_date')
            end_date = request.query_params.get('end_date')

            deliveries = self._get_unremitted_deliveries_queryset(user)

            if start_date and end_date:
                deliveries = self._apply_date_filter(deliveries, start_date, end_date)

            total_unremitted = Decimal('0.00')
            total_cod_amount = Decimal('0.00')
            total_delivery_fees = Decimal('0.00')
            cod_count = 0
            online_count = 0
            unremitted_deliveries = []

            for delivery in deliveries:
                order = delivery.order
                customer = order.user
                is_cod = self._is_cod_order(order)

                if is_cod:
                    amount_to_remit = order.total_amount
                    total_cod_amount += order.total_amount
                    cod_count += 1
                else:
                    amount_to_remit = Decimal('0.00')
                    online_count += 1

                total_unremitted += amount_to_remit
                total_delivery_fees += (delivery.delivery_fee or Decimal('0.00'))

                unremitted_deliveries.append({
                    'delivery_id': str(delivery.id),
                    'order_id': str(order.order),
                    'order_number': str(order.order)[:8].upper(),
                    'customer_name': f"{customer.first_name} {customer.last_name}".strip() or customer.username,
                    'delivery_date': delivery.delivered_at.isoformat() if delivery.delivered_at else None,
                    'order_amount': float(order.total_amount),
                    'delivery_fee': float(delivery.delivery_fee or 0),
                    'total_to_remit': float(amount_to_remit),
                    'payment_method': order.payment_method,
                    'is_cod': is_cod,
                    'has_been_remitted': False,
                    'remittance_due_date': (delivery.delivered_at + timedelta(days=7)).isoformat() if delivery.delivered_at else None
                })

            return Response({
                'success': True,
                'summary': {
                    'total_unremitted_amount': float(total_unremitted),
                    'total_delivery_fees': float(total_delivery_fees),
                    'total_cod_order_amount': float(total_cod_amount),
                    'cod_orders_count': cod_count,
                    'online_orders_count': online_count,
                    'total_orders': cod_count + online_count,
                    'total_deliveries': len(unremitted_deliveries),
                    'currency': 'PHP',
                    'note': 'For COD orders, only the order amount needs to be remitted (riders keep the delivery fee in cash). Online orders do not require remittance.'
                },
                'unremitted_deliveries': unremitted_deliveries,
                'date_range': {'start_date': start_date, 'end_date': end_date},
                'sandbox_mode': getattr(settings, 'ENABLE_SANDBOX', False),
                'test_card': {
                    'message': 'For sandbox testing, use:',
                    'card_number': '5123450000000008',
                    'expiry': '12/25',
                    'cvv': '123',
                    'otp': '123456'
                } if getattr(settings, 'ENABLE_SANDBOX', False) else None
            })

        except ValueError as e:
            return Response({'success': False, 'error': str(e)}, status=status.HTTP_400_BAD_REQUEST)
        except Exception as e:
            return Response({'success': False, 'error': f'An unexpected error occurred: {str(e)}'}, status=status.HTTP_500_INTERNAL_SERVER_ERROR)

    # ================================================================
    # INITIATE REMITTANCE (Maya)
    # ================================================================

    @action(detail=False, methods=['POST'], url_path='initiate_remittance')
    def initiate_remittance(self, request):
        """
        Initiate rider remittance via Maya PWM.
        Creates a PENDING RiderRemittance record, then redirects to Maya.
        Body: { "delivery_ids": ["uuid1", "uuid2"], "user_id": "uuid" }
        """
        enable_sandbox = getattr(settings, 'ENABLE_SANDBOX', False)
        if not enable_sandbox:
            return Response({'success': False, 'error': 'Sandbox mode is not enabled'}, status=status.HTTP_403_FORBIDDEN)

        try:
            import base64
            import requests as http_requests
            from datetime import datetime as dt

            # Resolve user
            try:
                user = self._get_user_from_header(request)
                user_id = str(user.id)
            except ValueError:
                user_id = request.data.get('user_id')
                if not user_id:
                    return Response({'success': False, 'error': 'user_id is required'}, status=status.HTTP_400_BAD_REQUEST)
                try:
                    user = User.objects.get(id=user_id)
                except User.DoesNotExist:
                    return Response({'success': False, 'error': 'User not found'}, status=status.HTTP_404_NOT_FOUND)

            if not hasattr(user, 'rider'):
                return Response({'success': False, 'error': 'User is not a rider'}, status=status.HTTP_403_FORBIDDEN)

            delivery_ids = request.data.get('delivery_ids', [])
            if not delivery_ids:
                return Response({'success': False, 'error': 'delivery_ids are required'}, status=status.HTTP_400_BAD_REQUEST)

            # Only delivered + not yet in a completed remittance
            deliveries = Delivery.objects.filter(
                id__in=delivery_ids,
                rider=user.rider,
                status='delivered'
            ).exclude(
                remittance_items__remittance__status='completed'
            ).select_related('order')

            if not deliveries.exists():
                return Response({
                    'success': False,
                    'error': 'No valid unremitted deliveries found. These may have already been remitted.'
                }, status=status.HTTP_404_NOT_FOUND)

            # Calculate total
            total_amount = Decimal('0.00')
            items_preview = []
            for delivery in deliveries:
                order = delivery.order
                is_cod = self._is_cod_order(order)
                amount = order.total_amount if is_cod else Decimal('0.00')
                total_amount += amount
                items_preview.append({
                    'delivery_id': str(delivery.id),
                    'order_number': str(order.order)[:8].upper(),
                    'amount': float(amount),
                    'is_cod': is_cod,
                })

            reference = f"REM-{user_id[:8].upper()}-{dt.now().strftime('%H%M%S')}"

            # Build Maya payload
            maya_config = settings.MAYA_SANDBOX
            base_url = maya_config['BASE_URL']
            public_key = maya_config['PUBLIC_KEY']
            frontend_url = settings.FRONTEND_URL

            credentials = base64.b64encode(f"{public_key}:".encode()).decode()

            payload = {
                "totalAmount": {"value": round(float(total_amount), 2), "currency": "PHP"},
                "requestReferenceNumber": reference,
                "items": [{
                    "name": f"Rider Remittance ({len(items_preview)} delivery{'s' if len(items_preview) != 1 else ''})",
                    "quantity": len(items_preview),
                    "code": f"REM-{user_id[:8].upper()}",
                    "description": "Rider remittance payment",
                    "amount": {"value": round(float(total_amount / len(items_preview)), 2), "currency": "PHP"},
                    "totalAmount": {"value": round(float(total_amount), 2), "currency": "PHP"}
                }],
                "redirectUrl": {
                    "success": f"{frontend_url}/rider/remit-amount?status=success&reference={reference}",
                    "failure": f"{frontend_url}/rider/remit-amount?status=failed&reference={reference}",
                    "cancel":  f"{frontend_url}/rider/remit-amount?status=cancelled&reference={reference}"
                }
            }

            maya_response = http_requests.post(
                f"{base_url}/payby/v2/paymaya/payments",
                json=payload,
                headers={
                    "Authorization": f"Basic {credentials}",
                    "Content-Type": "application/json",
                    "Accept": "application/json"
                },
                timeout=30
            )

            if maya_response.status_code not in [200, 201]:
                logger.error(f"Maya API error {maya_response.status_code}: {maya_response.text}")
                return Response({
                    'success': False,
                    'error': f"Maya API error: {maya_response.text}"
                }, status=status.HTTP_502_BAD_GATEWAY)

            maya_data = maya_response.json()
            redirect_url = maya_data.get('redirectUrl')
            payment_id = maya_data.get('paymentId') or maya_data.get('id')

            if not redirect_url:
                return Response({'success': False, 'error': 'No redirect URL from Maya'}, status=status.HTTP_502_BAD_GATEWAY)

            # Create PENDING remittance + items
            remittance = RiderRemittance.objects.create(
                rider=user.rider,
                reference_number=reference,
                total_amount=total_amount,
                payment_method='Maya',
                maya_payment_id=payment_id,
                status='pending'
            )
            for delivery in deliveries:
                order = delivery.order
                is_cod = self._is_cod_order(order)
                amount = (
                    order.total_amount + (delivery.delivery_fee or Decimal('0.00'))
                    if is_cod else
                    (delivery.delivery_fee or Decimal('0.00'))
                )
                RiderRemittanceItem.objects.create(
                    remittance=remittance,
                    delivery=delivery,
                    order_amount=order.total_amount,
                    delivery_fee=delivery.delivery_fee or Decimal('0.00'),
                    amount_remitted=amount,
                    is_cod=is_cod,
                    payment_method=order.payment_method,
                )

            logger.info(f"Created pending remittance {reference} for rider {user.rider}")

            return Response({
                'success': True,
                'message': 'Remittance initiated. Redirecting to Maya payment.',
                'reference_number': reference,
                'total_amount': float(total_amount),
                'deliveries_count': len(items_preview),
                'items': items_preview,
                'redirect_url': redirect_url,
                'payment_id': payment_id,
                'sandbox_mode': True,
            })

        except Exception as e:
            logger.error(f"Error initiating remittance: {str(e)}")
            import traceback
            traceback.print_exc()
            return Response({
                'success': False,
                'error': 'Failed to initiate remittance',
                'details': str(e)
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)

    @action(detail=False, methods=['POST'], url_path='submit_manual_remittance')
    def submit_manual_remittance(self, request):
        """
        Submit a manual remittance request (Hub Drop-off, GCash Transfer, Bank Transfer).
        Creates a PENDING RiderRemittance record for admin review.
        Body: { "delivery_ids": ["uuid1", "uuid2"], "method": "hub_dropoff", "note": "ref no" }
        """
        try:
            from datetime import datetime as dt
            user = self._get_user_from_header(request)
            
            if not hasattr(user, 'rider'):
                return Response({'success': False, 'error': 'User is not a rider'}, status=status.HTTP_403_FORBIDDEN)

            delivery_ids = request.data.getlist('delivery_ids[]') if hasattr(request.data, 'getlist') else request.data.get('delivery_ids', [])
            if not delivery_ids:
                # Fallback if sent as JSON string
                import json
                try:
                    delivery_ids = json.loads(request.data.get('delivery_ids', '[]'))
                except:
                    delivery_ids = []
                    
            method_input = request.data.get('method', 'hub_dropoff')
            rider_amount = request.data.get('amount')
            proof_image = request.FILES.get('proof_image')
            
            # Map frontend method IDs to model choices
            method_mapping = {
                'hub_dropoff': 'Cash',
                'cash_transfer': 'GCash',
                'bank_deposit': 'Bank Transfer'
            }
            payment_method_val = method_mapping.get(method_input)
            
            if not payment_method_val:
                # Check if it's a UUID for UserPaymentDetail
                try:
                    payment_detail = UserPaymentDetail.objects.get(payment_id=method_input, user=user)
                    # Map 'bank' -> 'Bank Transfer', 'gcash' -> 'GCash', etc.
                    if payment_detail.payment_method.lower() == 'gcash':
                        payment_method_val = 'GCash'
                    elif payment_detail.payment_method.lower() == 'bank':
                        payment_method_val = 'Bank Transfer'
                    else:
                        payment_method_val = 'Maya'  # Fallback
                except Exception:
                    payment_method_val = 'Cash'

            if not delivery_ids:
                return Response({'success': False, 'error': 'No deliveries specified for remittance'}, status=status.HTTP_400_BAD_REQUEST)

            if not rider_amount:
                return Response({'success': False, 'error': 'Amount is required'}, status=status.HTTP_400_BAD_REQUEST)

            # Only delivered + not yet in a completed or pending remittance
            deliveries = Delivery.objects.filter(
                id__in=delivery_ids,
                rider=user.rider,
                status__in=['delivered', 'completed']
            ).exclude(
                remittance_items__remittance__status__in=['completed', 'pending']
            ).select_related('order')

            if not deliveries.exists():
                return Response({
                    'success': False,
                    'error': 'No valid unremitted deliveries found. They may already be remitted or pending review.'
                }, status=status.HTTP_404_NOT_FOUND)

            # Calculate true total from deliveries (for internal tracking/items, if needed, though we use the rider's stated amount for the overall record)
            total_deliveries_amount = Decimal('0.00')
            for delivery in deliveries:
                order = delivery.order
                is_cod = self._is_cod_order(order)
                amount = order.total_amount if is_cod else Decimal('0.00')
                total_deliveries_amount += amount

            reference = f"REM-{str(user.id)[:8].upper()}-{dt.now().strftime('%H%M%S')}"

            # Upload proof image if exists
            proof_url = ""
            if proof_image:
                from django.core.files.storage import default_storage
                from api.utils.storage_utils import convert_s3_to_public_url
                file_ext = proof_image.name.split('.')[-1]
                path = default_storage.save(f'remittance_proofs/{reference}.{file_ext}', proof_image)
                raw_url = default_storage.url(path)
                proof_url = convert_s3_to_public_url(raw_url)

            # Create Remittance record using the amount the rider actually specified
            # We use maya_payment_id to store the proof_url since we can't run migrations right now.
            remittance = RiderRemittance.objects.create(
                rider=user.rider,
                reference_number=reference,
                total_amount=Decimal(str(rider_amount)),
                payment_method=payment_method_val,
                maya_payment_id=proof_url,
                status='pending'
            )
            
            # Create Items
            for delivery in deliveries:
                order = delivery.order
                is_cod = self._is_cod_order(order)
                amount = order.total_amount if is_cod else Decimal('0.00')
                RiderRemittanceItem.objects.create(
                    remittance=remittance,
                    delivery=delivery,
                    order_amount=order.total_amount,
                    delivery_fee=delivery.delivery_fee or Decimal('0.00'),
                    amount_remitted=amount,
                    is_cod=is_cod,
                    payment_method=order.payment_method,
                )

            logger.info(f"Created manual pending remittance {reference} for user {user.id}")

            return Response({
                'success': True,
                'message': 'Remittance submitted successfully.',
                'reference_number': reference,
                'total_amount': float(rider_amount)
            })

        except Exception as e:
            logger.error(f"Error submitting manual remittance: {str(e)}")
            return Response({
                'success': False,
                'error': 'Failed to submit remittance',
                'details': str(e)
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)

    @action(detail=False, methods=['GET'], url_path='remittances')
    def get_remittances(self, request):
        """
        Get all remittances for a rider, formatted like WalletTransactions.
        """
        try:
            user = self._get_user_from_header(request)
            if not hasattr(user, 'rider'):
                return Response({'success': False, 'error': 'User is not a rider'}, status=status.HTTP_403_FORBIDDEN)
                
            remittances = RiderRemittance.objects.filter(rider=user.rider).order_by('-created_at')
            data = []
            for r in remittances:
                data.append({
                    'transaction_id': str(r.id),
                    'amount': float(r.total_amount),
                    'transaction_type': 'debit',
                    'source_type': 'cod_remittance',
                    'status': r.status,
                    'created_at': r.created_at.isoformat(),
                    'proof_url': r.maya_payment_id, # maya_payment_id stores the proof image URL
                    'reference_number': r.reference_number,
                    'payment_method': r.payment_method
                })
            return Response({'success': True, 'remittances': data})
        except Exception as e:
            return Response({'success': False, 'error': str(e)}, status=status.HTTP_500_INTERNAL_SERVER_ERROR)


    @action(detail=False, methods=['get'], url_path='remittance-success')
    def remittance_success(self, request):
        """
        Maya browser redirect after successful payment.
        Marks the RiderRemittance as completed, then redirects frontend.
        """
        reference = request.GET.get('reference')
        frontend_url = getattr(settings, 'FRONTEND_URL', 'http://localhost:5173')

        if not reference:
            from django.shortcuts import redirect
            return redirect(f"{frontend_url}/rider/remit-amount?status=failed&error=missing_reference")

        try:
            remittance = RiderRemittance.objects.get(reference_number=reference)

            if remittance.status == 'pending':
                remittance.status = 'completed'
                remittance.processed_at = timezone.now()
                remittance.save(update_fields=['status', 'processed_at'])
                logger.info(f"Remittance {reference} marked as completed via success callback")
            elif remittance.status == 'completed':
                logger.info(f"Remittance {reference} already completed — duplicate callback ignored")

        except RiderRemittance.DoesNotExist:
            logger.error(f"Remittance {reference} not found in success callback")
            from django.shortcuts import redirect
            return redirect(f"{frontend_url}/rider/remit-amount?status=failed&error=not_found&reference={reference}")
        except Exception as e:
            logger.error(f"Error completing remittance {reference}: {str(e)}")
            from django.shortcuts import redirect
            return redirect(f"{frontend_url}/rider/remit-amount?status=failed&error=server_error&reference={reference}")

        from django.shortcuts import redirect
        return redirect(f"{frontend_url}/rider/remit-amount?status=success&reference={reference}")


    @action(detail=False, methods=['get'], url_path='remittance-failure')
    def remittance_failure(self, request):
        """Maya browser redirect after failed payment."""
        reference = request.GET.get('reference')
        frontend_url = getattr(settings, 'FRONTEND_URL', 'http://localhost:5173')

        if reference:
            try:
                RiderRemittance.objects.filter(
                    reference_number=reference,
                    status='pending'
                ).update(status='failed')
                logger.info(f"Remittance {reference} marked as failed")
            except Exception as e:
                logger.error(f"Error marking remittance {reference} as failed: {str(e)}")

        from django.shortcuts import redirect
        return redirect(f"{frontend_url}/rider/remit-amount?status=failed&reference={reference or ''}")


    @action(detail=False, methods=['get'], url_path='remittance-cancel')
    def remittance_cancel(self, request):
        """Maya browser redirect after cancelled payment."""
        reference = request.GET.get('reference')
        frontend_url = getattr(settings, 'FRONTEND_URL', 'http://localhost:5173')

        if reference:
            try:
                RiderRemittance.objects.filter(
                    reference_number=reference,
                    status='pending'
                ).update(status='cancelled')
                logger.info(f"Remittance {reference} marked as cancelled")
            except Exception as e:
                logger.error(f"Error marking remittance {reference} as cancelled: {str(e)}")

        from django.shortcuts import redirect
        return redirect(f"{frontend_url}/rider/remit-amount?status=cancelled&reference={reference or ''}")


    @action(detail=False, methods=['post'], url_path='process_remittance')
    def process_remittance(self, request):
        """
        Sandbox shortcut: directly creates a completed remittance without Maya.
        Body: { "delivery_ids": ["uuid1"], "user_id": "uuid" }
        """
        enable_sandbox = getattr(settings, 'ENABLE_SANDBOX', False)
        if not enable_sandbox:
            return Response({'success': False, 'error': 'Sandbox mode is not enabled'}, status=status.HTTP_403_FORBIDDEN)

        try:
            user_id = request.data.get('user_id')
            delivery_ids = request.data.get('delivery_ids', [])

            if not user_id or not delivery_ids:
                return Response({'success': False, 'error': 'user_id and delivery_ids are required'}, status=status.HTTP_400_BAD_REQUEST)

            try:
                user = User.objects.get(id=user_id)
            except User.DoesNotExist:
                return Response({'success': False, 'error': 'User not found'}, status=status.HTTP_404_NOT_FOUND)

            if not hasattr(user, 'rider'):
                return Response({'success': False, 'error': 'User is not a rider'}, status=status.HTTP_403_FORBIDDEN)

            deliveries = Delivery.objects.filter(
                id__in=delivery_ids,
                rider=user.rider,
                status='delivered'
            ).exclude(
                remittance_items__remittance__status='completed'
            ).select_related('order')

            if not deliveries.exists():
                return Response({
                    'success': False,
                    'error': 'No valid unremitted deliveries found'
                }, status=status.HTTP_404_NOT_FOUND)

            total_amount = Decimal('0.00')
            remittance_details = []

            for delivery in deliveries:
                order = delivery.order
                is_cod = self._is_cod_order(order)
                amount = (
                    order.total_amount + (delivery.delivery_fee or Decimal('0.00'))
                    if is_cod else
                    (delivery.delivery_fee or Decimal('0.00'))
                )
                total_amount += amount
                remittance_details.append({
                    'delivery_id': str(delivery.id),
                    'order_number': str(order.order)[:8].upper(),
                    'amount': float(amount),
                    'is_cod': is_cod,
                    'payment_method': order.payment_method,
                })

            reference = f"REM{str(uuid.uuid4())[:8].upper()}"

            # Create completed remittance directly
            remittance = RiderRemittance.objects.create(
                rider=user.rider,
                reference_number=reference,
                total_amount=total_amount,
                payment_method='Cash',
                status='completed',
                processed_at=timezone.now()
            )
            for delivery in deliveries:
                order = delivery.order
                is_cod = self._is_cod_order(order)
                amount = (
                    order.total_amount + (delivery.delivery_fee or Decimal('0.00'))
                    if is_cod else
                    (delivery.delivery_fee or Decimal('0.00'))
                )
                RiderRemittanceItem.objects.create(
                    remittance=remittance,
                    delivery=delivery,
                    order_amount=order.total_amount,
                    delivery_fee=delivery.delivery_fee or Decimal('0.00'),
                    amount_remitted=amount,
                    is_cod=is_cod,
                    payment_method=order.payment_method,
                )

            logger.info(f"Sandbox: completed remittance {reference} for rider {user.rider}")

            return Response({
                'success': True,
                'message': 'Remittance processed successfully',
                'reference_number': reference,
                'total_amount': float(total_amount),
                'deliveries_count': len(remittance_details),
                'deliveries': remittance_details,
                'sandbox_mode': True,
            })

        except Exception as e:
            logger.error(f"Error processing remittance: {str(e)}")
            return Response({
                'success': False,
                'error': 'Failed to process remittance',
                'details': str(e)
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
        
    @action(detail=False, methods=['get'], url_path='remittance-history')
    def remittance_history(self, request):
        """
        Get rider's remittance history from RiderRemittance records.
        Query params: start_date, end_date, status
        """
        try:
            user = self._get_user_from_header(request)

            if not hasattr(user, 'rider'):
                return Response({'success': False, 'error': 'User is not a rider'}, status=status.HTTP_403_FORBIDDEN)

            start_date = request.query_params.get('start_date')
            end_date = request.query_params.get('end_date')
            status_filter = request.query_params.get('status', 'all')

            remittances = RiderRemittance.objects.filter(
                rider=user.rider
            ).prefetch_related('items__delivery__order').order_by('-created_at')

            if status_filter != 'all':
                remittances = remittances.filter(status=status_filter)

            if start_date and end_date:
                remittances = remittances.filter(
                    created_at__date__gte=start_date,
                    created_at__date__lte=end_date
                )

            history_data = []
            for remittance in remittances:
                items_data = []
                for item in remittance.items.all():
                    delivery = item.delivery
                    items_data.append({
                        'delivery_id': str(delivery.id) if delivery else None,
                        'order_id': str(delivery.order.order) if delivery else None,
                        'order_number': str(delivery.order.order)[:8].upper() if delivery else None,
                        'order_amount': float(item.order_amount),
                        'delivery_fee': float(item.delivery_fee),
                        'amount_remitted': float(item.amount_remitted),
                        'is_cod': item.is_cod,
                        'payment_method': item.payment_method,
                    })

                history_data.append({
                    'id': str(remittance.id),
                    'reference_number': remittance.reference_number,
                    'total_amount': float(remittance.total_amount),
                    'status': remittance.status,
                    'payment_method': remittance.payment_method,
                    'maya_payment_id': remittance.maya_payment_id,
                    'deliveries_count': remittance.deliveries_count,
                    'processed_at': remittance.processed_at.isoformat() if remittance.processed_at else None,
                    'created_at': remittance.created_at.isoformat(),
                    'items': items_data,
                })

            # Summary
            total_remitted = sum(r['total_amount'] for r in history_data if r['status'] == 'completed')

            return Response({
                'success': True,
                'remittance_history': history_data,
                'count': len(history_data),
                'summary': {
                    'total_remitted': total_remitted,
                    'completed_count': sum(1 for r in history_data if r['status'] == 'completed'),
                    'pending_count': sum(1 for r in history_data if r['status'] == 'pending'),
                    'failed_count': sum(1 for r in history_data if r['status'] == 'failed'),
                },
                'date_range': {'start_date': start_date, 'end_date': end_date},
                'current_filter': status_filter,
            })

        except Exception as e:
            return Response({'success': False, 'error': str(e)}, status=status.HTTP_500_INTERNAL_SERVER_ERROR)

    # ================================================================
    # FORMAT HELPERS
    # ================================================================

    def _format_delivery_data(self, deliveries):
        """Format delivery data for response"""

        
        deliveries_data = []
        for delivery in deliveries:
            order = delivery.order
            
            # Get product image for this order
            product_image_url = None
            try:
                # Get checkout items for this order
                checkout_items = Checkout.objects.filter(order=order)
                for item in checkout_items:
                    if item.cart_item and item.cart_item.variant:
                        variant = item.cart_item.variant
                        product = variant.product if variant.product else None
                        if product:
                            first_media = product.productmedia_set.first()
                            if first_media and first_media.file_data:
                                product_image_url = get_media_url(first_media.file_data)
                                break  # Stop after finding first image
            except Exception as e:
                print(f"Error getting product image for order {order.order}: {e}")
            
            # Get delivery fee
            delivery_fee = delivery.delivery_fee
            
            # Calculate time elapsed
            time_elapsed = timezone.now() - delivery.created_at
            hours = int(time_elapsed.total_seconds() // 3600)
            minutes = int((time_elapsed.total_seconds() % 3600) // 60)
            
            # Determine if late (more than 2 hours for pending)
            is_late = hours > 2 and delivery.status == 'pending'
            
            # Get shipping address
            shipping_address = order.shipping_address
            delivery_location = shipping_address.get_full_address() if shipping_address else "Address not available"
            recipient_name = shipping_address.recipient_name if shipping_address else ""
            recipient_phone = shipping_address.recipient_phone if shipping_address else ""
            
            deliveries_data.append({
                "id": str(delivery.id),
                "order_id": str(order.order),
                "order_number": str(order.order)[:8],
                "customer_name": f"{order.user.first_name} {order.user.last_name}" if order.user else "Unknown",
                "customer_contact": order.user.contact_number if order.user else "",
                "customer_email": order.user.email if order.user else "",
                "recipient_name": recipient_name,
                "recipient_phone": recipient_phone,
                "delivery_location": delivery_location,
                "status": delivery.status,
                "order_amount": float(order.total_amount),
                "payment_method": order.payment_method,
                "delivery_fee": float(delivery_fee) if delivery_fee else 0,
                "product_image": product_image_url,  # Add product image
                "order_created_at": order.created_at.isoformat(),
                "picked_at": delivery.picked_at.isoformat() if delivery.picked_at else None,
                "delivered_at": delivery.delivered_at.isoformat() if delivery.delivered_at else None,
                "created_at": delivery.created_at.isoformat(),
                "time_elapsed": f"{hours}h {minutes}m",
                "is_late": is_late,
                "proofs_count": Proof.objects.filter(delivery=delivery).count(),
            })
        
        return deliveries_data
    def _get_items_summary(self, order):
        """Get a brief summary of order items"""
        items = order.checkout_set.all()[:3]
        if not items.exists():
            return "No items"

        item_names = []
        for item in items:
            if item.cart_item and item.cart_item.product:
                item_names.append(item.cart_item.product.name)
            else:
                item_names.append("Unknown Product")

        summary = ", ".join(item_names)
        if order.checkout_set.count() > 3:
            summary += f" and {order.checkout_set.count() - 3} more"
        return summary

    # ================================================================
    # EXPORT
    # ================================================================

    @action(detail=False, methods=['get'])
    def export_history(self, request):
        """Export order history as CSV or JSON"""
        try:
            user = self._get_user_from_header(request)

            if not hasattr(user, 'rider'):
                return Response({'success': False, 'error': 'User is not a rider'}, status=status.HTTP_403_FORBIDDEN)

            format_type = request.query_params.get('format', 'json')
            start_date = request.query_params.get('start_date')
            end_date = request.query_params.get('end_date')

            deliveries = self.get_queryset(user)
            if start_date and end_date:
                deliveries = self._apply_date_filter(deliveries, start_date, end_date)

            if format_type == 'csv':
                response = HttpResponse(content_type='text/csv')
                response['Content-Disposition'] = 'attachment; filename="rider_history.csv"'
                writer = csv.writer(response)
                writer.writerow([
                    'Order ID', 'Customer', 'Delivery Address', 'Status',
                    'Payment Method', 'Order Amount', 'Delivery Fee', 'Total Amount',
                    'Amount to Remit', 'Rider Earnings', 'Is Remitted', 'Rating',
                    'Delivery Time', 'Order Date', 'Delivered Date'
                ])
                for delivery in deliveries:
                    order = delivery.order
                    customer = order.user
                    shipping_address = order.shipping_address
                    is_cod = self._is_cod_order(order)
                    amount_to_remit = float(order.total_amount + (delivery.delivery_fee or 0)) if is_cod else float(delivery.delivery_fee or 0)
                    is_remitted = delivery.remittance_items.filter(remittance__status='completed').exists()

                    writer.writerow([
                        str(order.order)[:8],
                        f"{customer.first_name} {customer.last_name}",
                        shipping_address.get_full_address() if shipping_address else "N/A",
                        delivery.get_status_display(),
                        order.payment_method,
                        str(order.total_amount),
                        str(delivery.delivery_fee or 0),
                        str(order.total_amount + (delivery.delivery_fee or 0)),
                        str(amount_to_remit),
                        str(delivery.delivery_fee or 0),
                        'Yes' if is_remitted else 'No',
                        str(delivery.delivery_rating) if delivery.delivery_rating else "N/A",
                        f"{delivery.actual_minutes}m" if delivery.actual_minutes else "N/A",
                        order.created_at.strftime('%Y-%m-%d'),
                        delivery.delivered_at.strftime('%Y-%m-%d') if delivery.delivered_at else "N/A"
                    ])
                return response
            else:
                deliveries_data = self._format_delivery_data(deliveries)
                return Response({
                    'success': True,
                    'format': 'json',
                    'count': len(deliveries_data),
                    'data': deliveries_data,
                    'sandbox_mode': getattr(settings, 'ENABLE_SANDBOX', False)
                })

        except Exception as e:
            return Response({'success': False, 'error': str(e)}, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
                   
class RiderScheduleViewSet(viewsets.ViewSet):
    """
    Rider Schedule API endpoints for managing rider availability and schedules
    """
    
    def _get_user_from_header(self, request):
        """Extract and validate user from X-User-Id header"""
        user_id = request.headers.get('X-User-Id')
        
        if not user_id:
            raise ValueError('X-User-Id header is required')
        
        try:
            user_uuid = uuid.UUID(user_id)
            user = User.objects.get(id=user_uuid)
            return user
        except (ValueError, User.DoesNotExist):
            raise ValueError(f'Invalid or non-existent user ID: {user_id}')
    
    def _get_rider_from_user(self, user):
        """Get rider instance from user with validation"""
        if not hasattr(user, 'rider'):
            raise ValueError('User is not a rider')
        return user.rider
    
    @action(detail=False, methods=['get'])
    def get_schedule_data(self, request):
        """
        Get comprehensive schedule data for the rider UI
        Includes: availability status, custom schedule, metrics, and scheduled deliveries
        """
        try:
            # Get user from X-User-Id header
            user = self._get_user_from_header(request)
            rider = self._get_rider_from_user(user)
            
            # Get rider's schedule from RiderSchedule model
            rider_schedules = RiderSchedule.objects.filter(
                rider=rider
            ).order_by('day_of_week')
            
            # Format schedule for UI
            formatted_schedule = self._format_schedule_data(rider_schedules, rider)
            
            # Get scheduled deliveries for metrics and calendar
            scheduled_deliveries = self._get_scheduled_deliveries(rider)
            
            # Calculate metrics
            metrics = self._calculate_schedule_metrics(rider, scheduled_deliveries)
            
            # Format scheduled deliveries for UI
            formatted_deliveries = self._format_scheduled_deliveries(scheduled_deliveries)
            
            # Get custom schedule from rider (if exists)
            custom_schedule = rider.custom_schedule if hasattr(rider, 'custom_schedule') else {}
            
            return Response({
                'success': True,
                'rider': {
                    'id': str(rider.rider),
                    'availability_status': getattr(rider, 'availability_status', 'offline'),
                    'is_accepting_deliveries': getattr(rider, 'is_accepting_deliveries', True),
                    'last_status_update': getattr(rider, 'last_status_update', timezone.now()),
                    'custom_schedule': custom_schedule
                },
                'schedule': formatted_schedule,
                'deliveries': formatted_deliveries,
                'metrics': metrics
            })
            
        except ValueError as e:
            return Response({
                'success': False,
                'error': str(e)
            }, status=status.HTTP_400_BAD_REQUEST)
        except Exception as e:
            return Response({
                'success': False,
                'error': f'An unexpected error occurred: {str(e)}'
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
    
    def _format_schedule_data(self, rider_schedules, rider):
        """Format schedule data from RiderSchedule model"""
        days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday']
        formatted_schedule = []
        
        # Create a dictionary of existing schedules
        schedule_dict = {s.day_of_week: s for s in rider_schedules}
        
        for i, day_name in enumerate(days):
            if i in schedule_dict:
                schedule = schedule_dict[i]
                formatted_schedule.append({
                    'day_of_week': i,
                    'day_name': day_name,
                    'start_time': schedule.start_time.strftime('%H:%M'),
                    'end_time': schedule.end_time.strftime('%H:%M'),
                    'is_available': schedule.is_available,
                    'has_custom_schedule': True,
                    'id': str(schedule.id)  # Include ID for editing
                })
            else:
                # Default values for days without schedule
                formatted_schedule.append({
                    'day_of_week': i,
                    'day_name': day_name,
                    'start_time': '09:00',
                    'end_time': '17:00',
                    'is_available': i < 5,  # Mon-Fri available by default
                    'has_custom_schedule': False
                })
        
        return formatted_schedule
    
    def _get_scheduled_deliveries(self, rider):
        """Get optimized queryset for scheduled deliveries"""
        # Get deliveries for the next 7 days with all necessary relations
        seven_days_from_now = timezone.now() + timedelta(days=7)
        
        return Delivery.objects.filter(
            rider=rider,
            status__in=['scheduled', 'pending', 'picked_up', 'in_progress'],
            scheduled_pickup_time__lte=seven_days_from_now
        ).select_related(
            'order',
            'order__user',
            'order__shipping_address'
        ).prefetch_related(
            'order__orderitem_set__product__shop'
        ).order_by('scheduled_pickup_time')
    
    def _calculate_schedule_metrics(self, rider, deliveries):
        """Calculate comprehensive schedule metrics"""
        if not deliveries.exists():
            return self._get_empty_metrics()
        
        # Calculate metrics from deliveries
        aggregated = deliveries.aggregate(
            total_deliveries=Count('id'),
            upcoming_deliveries=Count('id', filter=Q(status__in=['scheduled', 'pending'])),
            in_progress_deliveries=Count('id', filter=Q(status__in=['picked_up', 'in_progress'])),
            completed_deliveries=Count('id', filter=Q(status='delivered')),
            avg_delivery_time=Avg('estimated_minutes'),
            total_distance_km=Sum('distance_km'),
            # avg_rating removed — queried from Review model below
        )
        
        # Calculate today's deliveries
        today_start = timezone.now().replace(hour=0, minute=0, second=0, microsecond=0)
        today_deliveries = deliveries.filter(
            scheduled_pickup_time__gte=today_start,
            scheduled_pickup_time__lt=today_start + timedelta(days=1)
        ).count()
        
        # Calculate peak day
        peak_day = self._get_peak_day(deliveries)
        
        # Calculate availability percentage from RiderSchedule
        total_schedules = RiderSchedule.objects.filter(rider=rider).count()
        available_schedules = RiderSchedule.objects.filter(
            rider=rider, 
            is_available=True
        ).count()
        
        availability_percentage = round((available_schedules / max(total_schedules, 1)) * 100) if total_schedules > 0 else 71
        
        # Calculate average deliveries per day (next 7 days)
        deliveries_by_day = self._get_deliveries_by_day(deliveries)
        avg_deliveries_per_day = sum(deliveries_by_day.values()) / max(len(deliveries_by_day), 1)
        
        return {
            'total_deliveries': aggregated['total_deliveries'] or 0,
            'upcoming_deliveries': aggregated['upcoming_deliveries'] or 0,
            'in_progress_deliveries': aggregated['in_progress_deliveries'] or 0,
            'completed_deliveries': aggregated['completed_deliveries'] or 0,
            'avg_delivery_time': round(aggregated['avg_delivery_time'] or 0, 1),
            'total_distance_km': float(aggregated['total_distance_km'] or 0),
            'average_rating': round(
                Review.objects.filter(
                    rider=rider,
                    delivery_rating__isnull=False
                ).aggregate(avg=Avg('delivery_rating'))['avg'] or 0, 1
            ),
            'today_deliveries': today_deliveries,
            'peak_day': peak_day,
            'availability_percentage': availability_percentage,
            'avg_deliveries_per_day': round(avg_deliveries_per_day, 1),
            'has_data': aggregated['total_deliveries'] > 0
        }
    
    def _get_peak_day(self, deliveries):
        """Determine which day has the most deliveries"""
        if not deliveries.exists():
            return 'N/A'
        
        # Count deliveries by day of week
        deliveries_by_day = {}
        for delivery in deliveries:
            if delivery.scheduled_pickup_time:
                day_name = delivery.scheduled_pickup_time.strftime('%A')
                deliveries_by_day[day_name] = deliveries_by_day.get(day_name, 0) + 1
        
        if deliveries_by_day:
            return max(deliveries_by_day.items(), key=lambda x: x[1])[0]
        
        return 'N/A'
    
    def _get_deliveries_by_day(self, deliveries):
        """Get deliveries count by day for the next 7 days"""
        deliveries_by_day = {}
        today = timezone.now().date()
        
        for i in range(7):
            day_date = today + timedelta(days=i)
            day_name = day_date.strftime('%A')
            deliveries_by_day[day_name] = 0
        
        # Count deliveries for each day
        for delivery in deliveries:
            if delivery.scheduled_pickup_time:
                day_name = delivery.scheduled_pickup_time.strftime('%A')
                if day_name in deliveries_by_day:
                    deliveries_by_day[day_name] += 1
        
        return deliveries_by_day
    
    def _format_scheduled_deliveries(self, deliveries):
        """Format scheduled deliveries for UI"""
        formatted_deliveries = []
        
        for delivery in deliveries:
            order = delivery.order
            customer = order.user
            shipping_address = order.shipping_address
            
            # Get shop name from first order item
            shop_name = None
            shop_contact = None
            if order.orderitem_set.exists():
                first_item = order.orderitem_set.first()
                if first_item.product and first_item.product.shop:
                    shop_name = first_item.product.shop.name
                    shop_contact = first_item.product.shop.contact_number
            
            formatted_deliveries.append({
                'id': str(delivery.id),
                'order': str(order.id),
                'order_number': str(order.id)[:8].upper(),
                'status': delivery.status,
                'scheduled_pickup_time': delivery.scheduled_pickup_time.isoformat() if delivery.scheduled_pickup_time else None,
                'scheduled_delivery_time': delivery.scheduled_delivery_time.isoformat() if delivery.scheduled_delivery_time else None,
                'is_scheduled': delivery.is_scheduled,
                'estimated_minutes': delivery.estimated_minutes,
                'actual_minutes': delivery.actual_minutes,
                'distance_km': float(delivery.distance_km) if delivery.distance_km else None,
                'delivery_rating': delivery.delivery_rating,
                'notes': delivery.notes,
                
                # Order details
                'order_details': {
                    'order': str(order.id),
                    'user': {
                        'username': customer.username,
                        'email': customer.email,
                        'contact_number': getattr(customer, 'contact_number', '')
                    },
                    'shipping_address': {
                        'recipient_name': shipping_address.recipient_name if shipping_address else None,
                        'street': shipping_address.street if shipping_address else None,
                        'barangay': shipping_address.barangay if shipping_address else None,
                        'city': shipping_address.city if shipping_address else None,
                        'province': shipping_address.province if shipping_address else None,
                        'zip_code': shipping_address.zip_code if shipping_address else None,
                        'recipient_phone': shipping_address.recipient_phone if shipping_address else None
                    } if shipping_address else None,
                    'total_amount': str(order.total_amount),
                    'payment_method': order.payment_method,
                    'delivery_method': order.delivery_method
                },
                
                # Customer info
                'customer_name': f"{customer.first_name} {customer.last_name}".strip() or customer.username,
                'customer_contact': getattr(customer, 'contact_number', ''),
                'customer_email': customer.email,
                
                # Shop info
                'shop_name': shop_name,
                'shop_contact': shop_contact,
                
                # Timestamps
                'created_at': delivery.created_at.isoformat() if delivery.created_at else None,
                'updated_at': delivery.updated_at.isoformat() if delivery.updated_at else None,
                'picked_at': delivery.picked_at.isoformat() if delivery.picked_at else None,
                'delivered_at': delivery.delivered_at.isoformat() if delivery.delivered_at else None,
            })
        
        return formatted_deliveries
    
    def _get_empty_metrics(self):
        """Return empty metrics structure"""
        return {
            'total_deliveries': 0,
            'upcoming_deliveries': 0,
            'in_progress_deliveries': 0,
            'completed_deliveries': 0,
            'avg_delivery_time': 0,
            'total_distance_km': 0,
            'average_rating': 0,
            'today_deliveries': 0,
            'peak_day': 'N/A',
            'availability_percentage': 71,
            'avg_deliveries_per_day': 0,
            'has_data': False
        }
    
    @action(detail=False, methods=['post'])
    def update_availability(self, request):
        """Update rider's availability status"""
        try:
            user = self._get_user_from_header(request)
            rider = self._get_rider_from_user(user)
            
            # Validate required fields
            availability_status = request.data.get('availability_status')
            is_accepting_deliveries = request.data.get('is_accepting_deliveries')
            
            if not availability_status:
                return Response({
                    'success': False,
                    'error': 'availability_status is required'
                }, status=status.HTTP_400_BAD_REQUEST)
            
            # Validate availability_status
            valid_statuses = ['offline', 'available', 'busy', 'break', 'unavailable']
            if availability_status not in valid_statuses:
                return Response({
                    'success': False,
                    'error': f'Invalid availability_status. Must be one of: {", ".join(valid_statuses)}'
                }, status=status.HTTP_400_BAD_REQUEST)
            
            # Update rider's availability (if these fields exist on Rider model)
            if hasattr(rider, 'availability_status'):
                rider.availability_status = availability_status
            if hasattr(rider, 'is_accepting_deliveries'):
                rider.is_accepting_deliveries = bool(is_accepting_deliveries)
            if hasattr(rider, 'last_status_update'):
                rider.last_status_update = timezone.now()
            rider.save()
            
            return Response({
                'success': True,
                'message': 'Availability updated successfully',
                'rider': {
                    'availability_status': getattr(rider, 'availability_status', availability_status),
                    'is_accepting_deliveries': getattr(rider, 'is_accepting_deliveries', bool(is_accepting_deliveries)),
                    'last_status_update': getattr(rider, 'last_status_update', timezone.now())
                }
            })
            
        except ValueError as e:
            return Response({
                'success': False,
                'error': str(e)
            }, status=status.HTTP_400_BAD_REQUEST)
        except Exception as e:
            return Response({
                'success': False,
                'error': f'An unexpected error occurred: {str(e)}'
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
    
    @action(detail=False, methods=['post'])
    def update_schedule(self, request):
        """Update rider's schedule using RiderSchedule model"""
        try:
            user = self._get_user_from_header(request)
            rider = self._get_rider_from_user(user)
            
            schedule_data = request.data.get('schedule', [])
            
            if not isinstance(schedule_data, list):
                return Response({
                    'success': False,
                    'error': 'schedule must be a list'
                }, status=status.HTTP_400_BAD_REQUEST)
            
            # Process each day's schedule
            for day_schedule in schedule_data:
                day_of_week = day_schedule.get('day_of_week')
                start_time = day_schedule.get('start_time')
                end_time = day_schedule.get('end_time')
                is_available = day_schedule.get('is_available', True)
                
                if day_of_week is None or not start_time or not end_time:
                    continue
                
                # Validate time format
                time_pattern = re.compile(r'^([0-1]?[0-9]|2[0-3]):[0-5][0-9]$')
                if not time_pattern.match(start_time) or not time_pattern.match(end_time):
                    return Response({
                        'success': False,
                        'error': f'Invalid time format for day {day_of_week}. Use HH:MM format.'
                    }, status=status.HTTP_400_BAD_REQUEST)
                
                # Convert string times to TimeField
                from datetime import time
                start_hour, start_minute = map(int, start_time.split(':'))
                end_hour, end_minute = map(int, end_time.split(':'))
                
                # Update or create schedule
                schedule, created = RiderSchedule.objects.update_or_create(
                    rider=rider,
                    day_of_week=day_of_week,
                    defaults={
                        'start_time': time(start_hour, start_minute),
                        'end_time': time(end_hour, end_minute),
                        'is_available': is_available
                    }
                )
            
            # Return updated schedule
            updated_schedules = RiderSchedule.objects.filter(rider=rider).order_by('day_of_week')
            formatted_schedule = self._format_schedule_data(updated_schedules, rider)
            
            return Response({
                'success': True,
                'message': 'Schedule updated successfully',
                'schedule': formatted_schedule
            })
            
        except ValueError as e:
            return Response({
                'success': False,
                'error': str(e)
            }, status=status.HTTP_400_BAD_REQUEST)
        except Exception as e:
            return Response({
                'success': False,
                'error': f'An unexpected error occurred: {str(e)}'
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
    
    @action(detail=False, methods=['get'])
    def get_weekly_view(self, request):
        """Get data for weekly calendar view"""
        try:
            user = self._get_user_from_header(request)
            rider = self._get_rider_from_user(user)
            
            # Get week parameter
            week_offset = int(request.query_params.get('week_offset', 0))
            
            # Calculate start of week (Monday)
            today = timezone.now().date()
            start_of_current_week = today - timedelta(days=today.weekday())  # Monday of current week
            start_of_target_week = start_of_current_week + timedelta(weeks=week_offset)
            
            # Get deliveries for the target week
            start_datetime = timezone.make_aware(
                timezone.datetime.combine(start_of_target_week, timezone.datetime.min.time())
            )
            end_datetime = start_datetime + timedelta(days=7)
            
            weekly_deliveries = Delivery.objects.filter(
                rider=rider,
                scheduled_pickup_time__gte=start_datetime,
                scheduled_pickup_time__lt=end_datetime
            ).select_related(
                'order',
                'order__user'
            ).order_by('scheduled_pickup_time')
            
            # Get rider's schedule
            rider_schedules = RiderSchedule.objects.filter(rider=rider)
            schedule_dict = {s.day_of_week: s for s in rider_schedules}
            
            # Format data for weekly view
            weekly_data = []
            for i in range(7):
                day_date = start_of_target_week + timedelta(days=i)
                day_name = day_date.strftime('%A')
                
                # Get day's schedule
                day_schedule = schedule_dict.get(i)
                is_available = day_schedule.is_available if day_schedule else (i < 5)
                start_time = day_schedule.start_time.strftime('%H:%M') if day_schedule else '09:00'
                end_time = day_schedule.end_time.strftime('%H:%M') if day_schedule else '17:00'
                
                # Get day's deliveries
                day_deliveries = []
                day_delivery_count = 0
                
                for delivery in weekly_deliveries:
                    if delivery.scheduled_pickup_time.date() == day_date:
                        day_delivery_count += 1
                        if len(day_deliveries) < 2:  # Only include first 2 for preview
                            day_deliveries.append({
                                'id': str(delivery.id),
                                'order_number': str(delivery.order.id)[:8].upper(),
                                'scheduled_time': delivery.scheduled_pickup_time.time().strftime('%H:%M'),
                                'status': delivery.status,
                                'customer_name': delivery.order.user.username
                            })
                
                weekly_data.append({
                    'date': day_date.isoformat(),
                    'day_of_week': i,
                    'day_name': day_name,
                    'is_today': day_date == today,
                    'is_available': is_available,
                    'start_time': start_time,
                    'end_time': end_time,
                    'deliveries_count': day_delivery_count,
                    'deliveries_preview': day_deliveries
                })
            
            return Response({
                'success': True,
                'week_start': start_of_target_week.isoformat(),
                'week_end': (start_of_target_week + timedelta(days=6)).isoformat(),
                'week_offset': week_offset,
                'weekly_data': weekly_data,
                'total_deliveries': len(weekly_deliveries)
            })
            
        except ValueError as e:
            return Response({
                'success': False,
                'error': str(e)
            }, status=status.HTTP_400_BAD_REQUEST)
        except Exception as e:
            return Response({
                'success': False,
                'error': f'An unexpected error occurred: {str(e)}'
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
    
    @action(detail=False, methods=['delete'])
    def delete_schedule(self, request):
        """Delete a specific schedule entry"""
        try:
            user = self._get_user_from_header(request)
            rider = self._get_rider_from_user(user)
            
            day_of_week = request.query_params.get('day_of_week')
            
            if day_of_week is None:
                return Response({
                    'success': False,
                    'error': 'day_of_week is required'
                }, status=status.HTTP_400_BAD_REQUEST)
            
            try:
                day_of_week = int(day_of_week)
            except ValueError:
                return Response({
                    'success': False,
                    'error': 'Invalid day_of_week'
                }, status=status.HTTP_400_BAD_REQUEST)
            
            # Delete the schedule
            deleted = RiderSchedule.objects.filter(
                rider=rider,
                day_of_week=day_of_week
            ).delete()
            
            return Response({
                'success': True,
                'message': 'Schedule deleted successfully',
                'deleted': deleted[0] > 0
            })
            
        except ValueError as e:
            return Response({
                'success': False,
                'error': str(e)
            }, status=status.HTTP_400_BAD_REQUEST)
        except Exception as e:
            return Response({
                'success': False,
                'error': f'An unexpected error occurred: {str(e)}'
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)

class ReviewView(APIView):
    """
    Comprehensive view for all review operations:
    - GET: List reviews with filters or get single review
    - POST: Create new review with multiple rating criteria
    - PUT: Update review
    - PATCH: Partial update review
    - DELETE: Delete review
    """
    
    def get_customer(self, request):
        """Extract customer from request data or X-User-Id header"""
        # Try to get from request data first (for POST/PUT/PATCH)
        user_id = request.data.get('customer_id')
        
        # If not in data, try from query params (for GET)
        if not user_id:
            user_id = request.query_params.get('customer_id')
        
        # If not in data or query, try from headers
        if not user_id:
            user_id = request.headers.get('X-User-Id')
        
        if user_id:
            try:
                # First get the User
                user = User.objects.get(id=user_id)
                # Then get or create the Customer profile
                customer, created = Customer.objects.get_or_create(customer=user)
                if created:
                    print(f"Created new customer profile for user {user.username}")
                return customer
            except User.DoesNotExist as e:
                print(f"User not found: {e}")
                return None
            except Exception as e:
                print(f"Error getting customer: {e}")
                return None
        return None

    def get(self, request, review_id=None):
        """
        Handle GET requests:
        - If review_id provided: Get specific review
        - If no review_id: List reviews with filters
        """
        try:
            # Get single review if review_id provided
            if review_id:
                return self._get_single_review(request, review_id)
            
            # Otherwise list reviews with filters
            return self._list_reviews(request)
            
        except Exception as e:
            logger.error(f"Error in GET request: {str(e)}")
            return Response({
                'status': 'error',
                'message': 'Failed to process request',
                'error': str(e)
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
    
    def _get_single_review(self, request, review_id):
        """Get a single review by ID"""
        try:
            review = Review.objects.select_related(
                'customer',
                'product',
                'rider',
                'shop'
            ).prefetch_related('medias').get(id=review_id)
            
            # Get customer info - FIXED: removed get_full_name()
            customer_info = None
            if review.customer and review.customer.customer:
                # Combine first_name and last_name manually
                first = review.customer.customer.first_name or ''
                last = review.customer.customer.last_name or ''
                full_name = f"{first} {last}".strip() or review.customer.customer.username
                customer_info = {
                    'id': str(review.customer.customer.id),
                    'name': full_name,
                }
            
            # Get rider info - FIXED: removed get_full_name()
            rider_info = None
            if review.rider and review.rider.rider:
                first = review.rider.rider.first_name or ''
                last = review.rider.rider.last_name or ''
                full_name = f"{first} {last}".strip() or review.rider.rider.username
                rider_info = {
                    'id': str(review.rider.rider_id),
                    'rider_id': str(review.rider.rider_id),
                    'name': full_name,
                }
            
            # Get product info
            product_info = None
            if review.product:
                product_info = {
                    'id': str(review.product.id),
                    'name': review.product.name,
                    'price': str(review.product.price) if hasattr(review.product, 'price') else None,
                }
            
            # Get shop info
            shop_info = None
            if review.shop:
                shop_info = {
                    'id': str(review.shop.id),
                    'name': review.shop.name,
                }
            
            review_data = {
                'id': str(review.id),
                'average_rating': review.average_rating,
                'condition_rating': review.condition_rating,
                'accuracy_rating': review.accuracy_rating,
                'value_rating': review.value_rating,
                'delivery_rating': review.delivery_rating,
                'comment': review.comment,
                'created_at': review.created_at.isoformat(),
                'updated_at': review.updated_at.isoformat(),
                'customer': customer_info,
                'product': product_info,
                'rider': rider_info,
                'shop': shop_info,
                'media': ReviewMediaSerializer(review.medias.all(), many=True).data
            }
            
            return Response({
                'status': 'success',
                'message': 'Review retrieved successfully',
                'data': review_data
            }, status=status.HTTP_200_OK)
            
        except Review.DoesNotExist:
            return Response({
                'status': 'error',
                'message': f'Review with id {review_id} not found'
            }, status=status.HTTP_404_NOT_FOUND)


    def _list_reviews(self, request):
        """List reviews with filters"""
        # Start with all reviews and select related fields
        reviews = Review.objects.select_related(
            'customer',
            'product',
            'rider',
            'shop'
        ).prefetch_related('medias').all()
        
        # Apply filters
        # Filter by product
        product_id = request.query_params.get('product_id') or request.query_params.get('product')
        if product_id:
            reviews = reviews.filter(product_id=product_id)
        
        # Filter by rider
        rider_id = request.query_params.get('rider_id') or request.query_params.get('rider')
        if rider_id:
            reviews = reviews.filter(rider_id=rider_id)
        
        # Filter by shop
        shop_id = request.query_params.get('shop_id') or request.query_params.get('shop')
        if shop_id:
            reviews = reviews.filter(shop_id=shop_id)
        
        # Filter by customer
        customer_id = request.query_params.get('customer_id') or request.query_params.get('customer')
        if customer_id:
            reviews = reviews.filter(customer_id=customer_id)
        
        # Filter by average rating
        min_rating = request.query_params.get('min_rating')
        if min_rating:
            reviews = reviews.filter(average_rating__gte=float(min_rating))
        
        max_rating = request.query_params.get('max_rating')
        if max_rating:
            reviews = reviews.filter(average_rating__lte=float(max_rating))
        
        # Filter by specific criteria ratings
        condition = request.query_params.get('condition_rating')
        if condition:
            reviews = reviews.filter(condition_rating=condition)
        
        accuracy = request.query_params.get('accuracy_rating')
        if accuracy:
            reviews = reviews.filter(accuracy_rating=accuracy)
        
        value = request.query_params.get('value_rating')
        if value:
            reviews = reviews.filter(value_rating=value)
        
        delivery = request.query_params.get('delivery_rating')
        if delivery:
            reviews = reviews.filter(delivery_rating=delivery)
        
        # Filter by date range
        days = request.query_params.get('days')
        if days:
            date_from = timezone.now() - timedelta(days=int(days))
            reviews = reviews.filter(created_at__gte=date_from)
        
        date_from = request.query_params.get('date_from')
        if date_from:
            reviews = reviews.filter(created_at__gte=date_from)
        
        date_to = request.query_params.get('date_to')
        if date_to:
            reviews = reviews.filter(created_at__lte=date_to)
        
        # Search in comments
        search = request.query_params.get('search')
        if search:
            reviews = reviews.filter(comment__icontains=search)
        
        # Include statistics if requested
        include_stats = request.query_params.get('include_stats', '').lower() == 'true'
        stats = None
        
        if include_stats:
            # Calculate statistics based on filtered queryset
            stats = reviews.aggregate(
                average_rating=Avg('average_rating'),
                total_reviews=Count('id'),
                avg_condition=Avg('condition_rating'),
                avg_accuracy=Avg('accuracy_rating'),
                avg_value=Avg('value_rating'),
                avg_delivery=Avg('delivery_rating')
            )
            
            # Calculate rating distribution
            rating_distribution = {}
            for i in range(1, 6):
                count = reviews.filter(average_rating__gte=i-0.5, average_rating__lt=i+0.5).count()
                rating_distribution[str(i)] = count
            
            stats['rating_distribution'] = rating_distribution
        
        # Ordering
        order_by = request.query_params.get('order_by', '-created_at')
        allowed_orders = ['created_at', '-created_at', 'average_rating', '-average_rating']
        if order_by in allowed_orders:
            reviews = reviews.order_by(order_by)
        
        # Pagination
        page = int(request.query_params.get('page', 1))
        page_size = int(request.query_params.get('page_size', 10))
        start = (page - 1) * page_size
        end = start + page_size
        
        total_count = reviews.count()
        paginated_reviews = reviews[start:end]
        
        # Build response data
        reviews_data = []
        for review in paginated_reviews:
            # Get customer info - FIXED: manually combine first_name and last_name
            customer_info = None
            if review.customer and review.customer.customer:
                first = review.customer.customer.first_name or ''
                last = review.customer.customer.last_name or ''
                full_name = f"{first} {last}".strip() or review.customer.customer.username
                customer_info = {
                    'id': str(review.customer.customer.id),
                    'name': full_name,
                }
            
            # Get rider info - FIXED: use rider_id instead of id and manually combine name
            rider_info = None
            if review.rider and review.rider.rider:
                first = review.rider.rider.first_name or ''
                last = review.rider.rider.last_name or ''
                full_name = f"{first} {last}".strip() or review.rider.rider.username
                rider_info = {
                    'id': str(review.rider.rider_id),  # Changed from review.rider.id
                    'rider_id': str(review.rider.rider_id),
                    'name': full_name,
                }
            
            # Get product info
            product_info = None
            if review.product:
                product_info = {
                    'id': str(review.product.id),
                    'name': review.product.name,
                }
            
            # Get shop info
            shop_info = None
            if review.shop:
                shop_info = {
                    'id': str(review.shop.id),
                    'name': review.shop.name,
                }
            
            review_data = {
                'id': str(review.id),
                'average_rating': review.average_rating,
                'condition_rating': review.condition_rating,
                'accuracy_rating': review.accuracy_rating,
                'value_rating': review.value_rating,
                'delivery_rating': review.delivery_rating,
                'comment': review.comment,
                'created_at': review.created_at.isoformat(),
                'customer': customer_info,
                'product': product_info,
                'rider': rider_info,
                'shop': shop_info,
                'media': ReviewMediaSerializer(review.medias.all(), many=True).data 
            }
            
            reviews_data.append(review_data)
        
        response_data = {
            'status': 'success',
            'message': 'Reviews retrieved successfully',
            'data': {
                'pagination': {
                    'total_count': total_count,
                    'page': page,
                    'page_size': page_size,
                    'total_pages': (total_count + page_size - 1) // page_size if total_count > 0 else 0,
                },
                'reviews': reviews_data
            }
        }
        
        # Add statistics if requested
        if include_stats and stats:
            response_data['data']['statistics'] = stats
        
        return Response(response_data, status=status.HTTP_200_OK)

    def post(self, request):
        """
        Handle POST requests to create a new review with multiple rating criteria
        Allows both product_id and rider_id in the same review
        """
        try:
            # Get customer from request data or header
            customer = self.get_customer(request)
            if not customer:
                return Response({
                    'status': 'error',
                    'message': 'Customer not found. Please ensure you have a customer profile.'
                }, status=status.HTTP_400_BAD_REQUEST)
            
            # Get product_id and rider_id from request data
            product_id = request.data.get('product_id')
            variant_id = request.data.get('variant_id')
            rider_id = request.data.get('rider_id')
            
            # Check if at least one is provided
            if not product_id and not rider_id:
                return Response({
                    'status': 'error',
                    'message': 'Either product_id or rider_id must be provided'
                }, status=status.HTTP_400_BAD_REQUEST)
            
            # ========== FIX: Check for existing reviews BEFORE validation ==========
            # Check for existing product review
            if product_id:
                existing_product_review = Review.objects.filter(
                    customer=customer,
                    product_id=product_id
                ).first()
                
                if existing_product_review:
                    return Response({
                        'status': 'error',
                        'message': 'You have already reviewed this product',
                        'data': {
                            'existing_review_id': str(existing_product_review.id)
                        }
                    }, status=status.HTTP_400_BAD_REQUEST)
            
            # Check for existing rider review ONLY if this is a standalone rider review (no product)
            # If product_id is provided, allow multiple product reviews with same rider
            if rider_id and not product_id:
                existing_rider_review = Review.objects.filter(
                    customer=customer,
                    rider_id=rider_id
                ).first()
                
                if existing_rider_review:
                    return Response({
                        'status': 'error',
                        'message': 'You have already reviewed this rider',
                        'data': {
                            'existing_review_id': str(existing_rider_review.id)
                        }
                    }, status=status.HTTP_400_BAD_REQUEST)
            
            # Prepare data for serializer
            data = {}
            
            # Set customer
            data['customer'] = customer.customer.id
            
            # Get ratings from request
            data['condition_rating'] = request.data.get('condition_rating')
            data['accuracy_rating'] = request.data.get('accuracy_rating')
            data['value_rating'] = request.data.get('value_rating')
            data['delivery_rating'] = request.data.get('delivery_rating')
            data['comment'] = request.data.get('comment', '')
            
            # Handle product if provided
            if product_id:
                # Get product
                try:
                    product = Product.objects.get(id=product_id)
                    data['product'] = product.id
                    data['shop'] = product.shop.id if product.shop else None
                except Product.DoesNotExist:
                    return Response({
                        'status': 'error',
                        'message': f'Product with id {product_id} not found'
                    }, status=status.HTTP_404_NOT_FOUND)
                
                # Handle variant if provided
                if variant_id:
                    try:
                        variant = Variants.objects.get(id=variant_id)
                        data['variant'] = variant.id
                    except Variants.DoesNotExist:
                        pass  # Variant is optional, don't fail if not found
            
            # Handle rider if provided
            if rider_id:
                # Get rider
                try:
                    rider = Rider.objects.get(rider_id=rider_id)
                    data['rider'] = rider.rider.id
                except Rider.DoesNotExist:
                    return Response({
                        'status': 'error',
                        'message': f'Rider with id {rider_id} not found'
                    }, status=status.HTTP_404_NOT_FOUND)
            
            # Debug: Print what we're sending to serializer
            print("=== DATA FOR SERIALIZER ===")
            print(data)
            
            # Use serializer to create the review
            serializer = ReviewSerializer(data=data, context={'request': request})
            
            if serializer.is_valid():
                review = serializer.save()
                
                # Handle media files if provided
                media_files = request.FILES.getlist('media')
                if media_files:
                    for media_file in media_files:
                        # Determine file type
                        file_name = media_file.name
                        if file_name.lower().endswith(('.jpg', '.jpeg', '.png', '.gif', '.webp', '.bmp')):
                            file_type = 'image'
                        elif file_name.lower().endswith(('.mp4', '.mov', '.avi', '.mkv', '.webm', '.flv')):
                            file_type = 'video'
                        else:
                            file_type = 'file'
                        
                        ReviewMedia.objects.create(
                            review=review,
                            file_data=media_file,
                            file_type=file_type
                        )
                
                # Get serialized data with media
                response_data = ReviewSerializer(review).data
                response_data['media'] = ReviewMediaSerializer(review.medias.all(), many=True).data
                
                # Determine message based on what was reviewed
                if product_id and rider_id:
                    message = 'Product and rider review created successfully'
                elif product_id:
                    message = 'Product review created successfully'
                else:
                    message = 'Rider review created successfully'
                
                return Response({
                    'status': 'success',
                    'message': message,
                    'data': response_data
                }, status=status.HTTP_201_CREATED)
            else:
                print("=== SERIALIZER ERRORS ===")
                print(serializer.errors)
                return Response({
                    'status': 'error',
                    'message': 'Validation failed',
                    'errors': serializer.errors
                }, status=status.HTTP_400_BAD_REQUEST)
                
        except Exception as e:
            logger.error(f"Error creating review: {str(e)}")
            import traceback
            traceback.print_exc()
            return Response({
                'status': 'error',
                'message': 'Failed to create review',
                'error': str(e)
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)

    def put(self, request, review_id):
        """Handle PUT requests for full update"""
        return self._update_review(request, review_id, partial=False)
    
    def patch(self, request, review_id):
        """Handle PATCH requests for partial update"""
        return self._update_review(request, review_id, partial=True)
    
    def _update_review(self, request, review_id, partial=False):
        """
        Internal method to handle review updates
        """
        try:
            # Get customer from request data or header
            customer = self.get_customer(request)
            if not customer:
                return Response({
                    'status': 'error',
                    'message': 'Customer ID is required (provide in request body as customer_id or X-User-Id header)'
                }, status=status.HTTP_400_BAD_REQUEST)
            
            # Get review
            try:
                review = Review.objects.get(id=review_id)
            except Review.DoesNotExist:
                return Response({
                    'status': 'error',
                    'message': f'Review with id {review_id} not found'
                }, status=status.HTTP_404_NOT_FOUND)
            
            # Check if customer owns this review
            if str(review.customer.customer_id) != str(customer.customer_id):
                return Response({
                    'status': 'error',
                    'message': 'You do not have permission to update this review'
                }, status=status.HTTP_403_FORBIDDEN)
            
            data = request.data
            updated_fields = []
            
            # Update ratings if provided
            rating_fields = ['condition_rating', 'accuracy_rating', 'value_rating', 'delivery_rating']
            for field in rating_fields:
                if field in data:
                    try:
                        value = int(data[field]) if data[field] is not None else None
                        if value is not None and (value < 1 or value > 5):
                            return Response({
                                'status': 'error',
                                'message': f'{field} must be between 1 and 5'
                            }, status=status.HTTP_400_BAD_REQUEST)
                        setattr(review, field, value)
                        updated_fields.append(field)
                    except (TypeError, ValueError):
                        return Response({
                            'status': 'error',
                            'message': f'Invalid {field} value'
                        }, status=status.HTTP_400_BAD_REQUEST)
            
            # Update comment if provided
            if 'comment' in data:
                review.comment = data['comment']
                updated_fields.append('comment')
            
            # For full update, validate required fields
            if not partial:
                if review.product and not any([
                    review.condition_rating,
                    review.accuracy_rating,
                    review.value_rating
                ]):
                    return Response({
                        'status': 'error',
                        'message': 'At least one product rating is required'
                    }, status=status.HTTP_400_BAD_REQUEST)
            
            # Save changes (average_rating will be calculated in serializer)
            review.save()

            # Handle deleted media IDs
            deleted_media_ids = data.get('deleted_media_ids')
            if deleted_media_ids:
                try:
                    import json
                    if isinstance(deleted_media_ids, str):
                        deleted_ids = json.loads(deleted_media_ids)
                    else:
                        deleted_ids = deleted_media_ids
                    
                    # Only delete media that belongs to this review
                    ReviewMedia.objects.filter(
                        id__in=deleted_ids,
                        review=review
                    ).delete()
                except (json.JSONDecodeError, TypeError) as e:
                    logger.error(f"Error parsing deleted_media_ids: {str(e)}")

            # Add any newly uploaded review media on update
            media_files = request.FILES.getlist('media')
            if media_files:
                for media_file in media_files:
                    file_name = media_file.name
                    if file_name.lower().endswith(('.jpg', '.jpeg', '.png', '.gif', '.webp', '.bmp')):
                        file_type = 'image'
                    elif file_name.lower().endswith(('.mp4', '.mov', '.avi', '.mkv', '.webm', '.flv')):
                        file_type = 'video'
                    else:
                        file_type = 'file'

                    ReviewMedia.objects.create(
                        review=review,
                        file_data=media_file,
                        file_type=file_type
                    )
            
            return Response({
                'status': 'success',
                'message': 'Review updated successfully',
                'data': {
                    'id': str(review.id),
                    'updated_fields': updated_fields,
                    'average_rating': review.average_rating,
                    'condition_rating': review.condition_rating,
                    'accuracy_rating': review.accuracy_rating,
                    'value_rating': review.value_rating,
                    'delivery_rating': review.delivery_rating,
                    'comment': review.comment,
                    'updated_at': review.updated_at.isoformat(),
                    'media': ReviewMediaSerializer(review.medias.all(), many=True).data
                }
            }, status=status.HTTP_200_OK)
            
        except Exception as e:
            logger.error(f"Error updating review: {str(e)}")
            return Response({
                'status': 'error',
                'message': 'Failed to update review',
                'error': str(e)
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
    
    def delete(self, request, review_id):
        """
        Handle DELETE requests to remove a review
        """
        try:
            # Get customer from request data or header
            customer = self.get_customer(request)
            if not customer:
                return Response({
                    'status': 'error',
                    'message': 'Customer ID is required (provide in request body as customer_id or X-User-Id header)'
                }, status=status.HTTP_400_BAD_REQUEST)
            
            # Get review
            try:
                review = Review.objects.get(id=review_id)
            except Review.DoesNotExist:
                return Response({
                    'status': 'error',
                    'message': f'Review with id {review_id} not found'
                }, status=status.HTTP_404_NOT_FOUND)
            
            # Check if customer owns this review
            if str(review.customer.customer_id) != str(customer.customer_id):
                return Response({
                    'status': 'error',
                    'message': 'You do not have permission to delete this review'
                }, status=status.HTTP_403_FORBIDDEN)
            
            # Store review info for response
            review_info = {
                'id': str(review.id),
                'average_rating': review.average_rating,
                'type': 'product' if review.product else 'rider'
            }
            
            # Delete review
            review.delete()
            
            return Response({
                'status': 'success',
                'message': 'Review deleted successfully',
                'data': review_info
            }, status=status.HTTP_200_OK)
            
        except Exception as e:
            logger.error(f"Error deleting review: {str(e)}")
            return Response({
                'status': 'error',
                'message': 'Failed to delete review',
                'error': str(e)
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)       


class ProfileView(APIView):
    """Get user profile and shop information in one API call"""

    def get_shop_for_customer(self, customer: Customer, current_user: User):
        """
        Fetch the first shop owned by the customer and return a serialized dict.
        Includes follower count, follow status, active status, and location.
        """
        shop = Shop.objects.filter(customer=customer).first()
        if not shop:
            return None

        follower_count = ShopFollow.objects.filter(shop=shop).count()
        current_user_follows = ShopFollow.objects.filter(
            shop=shop,
            customer=customer
        ).exists()

        # Compute orders and unique customers using Checkout -> CartItem -> Product -> Shop relationship
        try:
            orders_qs = Checkout.objects.filter(
                cart_item__product__shop=shop,
                order__status__in=['confirmed', 'processing', 'shipped', 'delivered']
            ).select_related('order')
            orders_count = orders_qs.values('order').distinct().count()

            # Count unique customers who had delivered orders involving this shop
            delivered_order_ids = Checkout.objects.filter(
                cart_item__product__shop=shop,
                order__status='delivered'
            ).values('order').distinct()
            customer_count = Order.objects.filter(order__in=delivered_order_ids).values('user').distinct().count()
        except Exception as e:
            logger.exception('Error computing shop order/customer counts: %s', e)
            orders_count = 0
            customer_count = 0

        return {
            'id': str(shop.id),
            'name': shop.name,
            'description': shop.description,
            'shop_picture': shop.shop_picture.url if shop.shop_picture else None,
            'contact_number': shop.contact_number,
            'verified': shop.verified,
            'status': shop.status,
            'total_sales': str(shop.total_sales),
            'created_at': shop.created_at.isoformat(),
            'is_suspended': shop.is_suspended,
            'suspended_until': shop.suspended_until.isoformat() if shop.suspended_until else None,
            'follower_count': follower_count,
            'is_following': current_user_follows,
            'is_active': shop.status == "Active" and not shop.is_suspended,
            'location': f"{shop.barangay}, {shop.city}, {shop.province}" if shop.barangay and shop.city and shop.province else "",
            # Additional shop stats for dashboard
            'orders_count': orders_count,
            # Product model uses `is_removed` and `status` fields; filter accordingly for active products
            'products_count': shop.products.filter(is_removed=False, status__iexact='active').count(),
            'customer_count': customer_count,
            'total_orders': Checkout.objects.filter(cart_item__product__shop=shop).values('order').distinct().count(),
        }

    def get(self, request):
        user_id = request.headers.get('X-User-Id')
        if not user_id:
            return Response(
                {"error": "X-User-Id header is required"},
                status=status.HTTP_400_BAD_REQUEST
            )

        try:
            # Get user
            user = User.objects.get(id=user_id)
            user_data = UserSerializer(user).data
            # Add user headers (user-specific info)
            user_data['full_name'] = " ".join(filter(None, [
                user.first_name, 
                user.middle_name, 
                user.last_name
            ]))
            # Safely handle profile picture (user may not have this attribute)
            profile_pic = getattr(user, 'profile_picture', None)
            user_data['has_profile_picture'] = bool(profile_pic)
            user_data['profile_picture_url'] = get_media_url(profile_pic) if profile_pic else None

            user_data['is_complete_profile'] = all([
                user.first_name,
                user.last_name,
                user.email,
                user.contact_number
            ])
            user_data['registration_complete'] = user.registration_stage >= 3 if user.registration_stage else False

            # Check if user is a customer
            try:
                customer = Customer.objects.get(customer=user)
                customer_data = CustomerSerializer(customer).data
                # Use the related User's created_at if available
                try:
                    customer_since_dt = customer.customer.created_at if hasattr(customer, 'customer') and customer.customer else None
                except Exception:
                    customer_since_dt = None

                customer_data.update({
                    'is_customer': True,
                    'can_add_product': customer.can_add_product(),
                    'products_remaining': customer.product_limit - customer.current_product_count,
                    'has_max_products': customer.current_product_count >= customer.product_limit,
                    # Customer headers
                    'customer_since': customer_since_dt.strftime('%B %d, %Y') if customer_since_dt else None,
                    'product_limit_info': f"{customer.current_product_count}/{customer.product_limit} products",
                    'can_manage_shop': True,  # All customers can potentially have a shop
                })
            except Customer.DoesNotExist:
                customer_data = {
                    'customer': None,
                    'product_limit': 0,
                    'current_product_count': 0,
                    'is_customer': False,
                    'can_add_product': False,
                    'products_remaining': 0,
                    'has_max_products': False,
                    'customer_since': None,
                    'product_limit_info': "0/0 products",
                    'can_manage_shop': False,
                }

            # Get shop if customer
            shop_data = None
            if customer_data.get('is_customer'):
                try:
                    shop_data = self.get_shop_for_customer(customer, user)
                    if shop_data:
                        # ... (existing shop data processing) ...
                        pass
                except Exception as e:
                    logger.error(f"Error fetching shop data: {str(e)}")
                    shop_data = None
            else:
                # Add headers for non-customers
                shop_data = {
                    'shop_headers': {
                        'has_shop': False,
                        'is_shop_owner': False,
                        'can_manage_shop': False,
                        'message': 'Create a customer account to start a shop',
                    }
                }

            # Get payment methods for the user
            payment_methods = []
            try:
                payment_methods_qs = UserPaymentDetail.objects.filter(user=user).order_by('-is_default', '-created_at')
                for pm in payment_methods_qs:
                    payment_methods.append({
                        'payment_id': str(pm.payment_id),
                        'payment_method': pm.payment_method,
                        'bank_name': pm.bank_name,
                        'account_name': pm.account_name,
                        'account_number': self.mask_account_number(pm.account_number),
                        'is_default': pm.is_default,
                        'created_at': pm.created_at.isoformat() if pm.created_at else None,
                    })
            except Exception as e:
                logger.error(f"Error fetching payment methods: {str(e)}")
                payment_methods = []

            # Create response data with headers
            response_data = {
                "success": True,
                "profile": {
                    "user": user_data,
                    "customer": customer_data,
                    "shop": shop_data,
                    "payment_methods": payment_methods  # Add payment methods here
                },
                # Global response headers
                "headers": {
                    "timestamp": timezone.now().isoformat(),
                    "api_version": "1.0",
                    "requires_shop": True if shop_data else False,
                    "user_type": "seller" if shop_data else ("customer" if customer_data.get('is_customer') else "guest"),
                    "has_active_session": True,
                    "can_switch_mode": customer_data.get('is_customer', False),
                    # Navigation headers
                    "available_routes": {
                        "seller_dashboard": bool(shop_data),
                        "customer_dashboard": customer_data.get('is_customer', False),
                        "create_shop": customer_data.get('is_customer', False) and not shop_data,
                        "manage_products": bool(shop_data),
                        "view_orders": bool(shop_data),
                    }
                }
            }

            return Response(response_data)

        except User.DoesNotExist:
            return Response(
                {
                    "success": False, 
                    "error": "User not found",
                    "headers": {
                        "requires_authentication": True,
                        "redirect_to": "/login"
                    }
                },
                status=status.HTTP_404_NOT_FOUND
            )
        except Exception as e:
            logger.error(f"Error fetching profile: {str(e)}")
            return Response(
                {
                    "success": False, 
                    "error": "Internal server error",
                    "headers": {
                        "retry_available": True,
                        "error_code": "PROFILE_FETCH_ERROR"
                    }
                },
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )

    def post(self, request):
        """Handle POST requests for payment methods and profile picture"""
        user_id = request.headers.get('X-User-Id')
        if not user_id:
            return Response(
                {"error": "X-User-Id header is required"},
                status=status.HTTP_400_BAD_REQUEST
            )

        try:
            user = User.objects.get(id=user_id)
            action = request.data.get('action')

            if action == 'add_payment_method':
                return self.add_payment_method(request, user)
            elif action == 'delete_payment_method':
                return self.delete_payment_method(request, user)
            elif action == 'set_default_payment':
                return self.set_default_payment(request, user)
            elif action == 'update_profile_picture':
                return self.update_profile_picture(request, user)
            elif action == 'remove_profile_picture':
                return self.remove_profile_picture(request, user)
            else:
                return Response(
                    {"error": "Invalid action"},
                    status=status.HTTP_400_BAD_REQUEST
                )

        except User.DoesNotExist:
            return Response(
                {"error": "User not found"},
                status=status.HTTP_404_NOT_FOUND
            )
        except Exception as e:
            logger.error(f"Error in profile POST: {str(e)}")
            return Response(
                {"error": "Internal server error"},
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )

    def put(self, request):
        """Handle PUT requests for updating user profile information"""
        user_id = request.headers.get('X-User-Id')
        if not user_id:
            return Response(
                {"error": "X-User-Id header is required"},
                status=status.HTTP_400_BAD_REQUEST
            )

        try:
            user = User.objects.get(id=user_id)
            serializer = UserSerializer(user, data=request.data, partial=True)
            
            if serializer.is_valid():
                serializer.save()
                
                # Return updated user data
                user_data = serializer.data
                profile_pic = getattr(user, 'profile_picture', None)
                user_data['has_profile_picture'] = bool(profile_pic)
                user_data['profile_picture_url'] = get_media_url(profile_pic) if profile_pic else None
                user_data['full_name'] = " ".join(filter(None, [
                    user.first_name, 
                    user.middle_name, 
                    user.last_name
                ]))
                
                return Response({
                    "success": True,
                    "message": "Profile updated successfully",
                    "user": user_data
                })
            else:
                return Response({
                    "success": False,
                    "error": "Invalid data",
                    "errors": serializer.errors
                }, status=status.HTTP_400_BAD_REQUEST)

        except User.DoesNotExist:
            return Response(
                {"error": "User not found"},
                status=status.HTTP_404_NOT_FOUND
            )
        except Exception as e:
            logger.error(f"Error updating profile: {str(e)}")
            return Response(
                {"error": "Internal server error"},
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )

    def update_profile_picture(self, request, user):
        """Update user profile picture"""
        try:
            # Check if file is in request.FILES (multipart form data)
            if 'profile_picture' in request.FILES:
                profile_picture = request.FILES['profile_picture']
                
                # Validate file type
                allowed_types = ['image/jpeg', 'image/jpg', 'image/png', 'image/gif']
                if profile_picture.content_type not in allowed_types:
                    return Response(
                        {"error": "Invalid file type. Only JPEG, PNG, and GIF are allowed."},
                        status=status.HTTP_400_BAD_REQUEST
                    )
                
                # Validate file size (max 5MB)
                max_size = 5 * 1024 * 1024  # 5MB
                if profile_picture.size > max_size:
                    return Response(
                        {"error": "File too large. Maximum size is 5MB."},
                        status=status.HTTP_400_BAD_REQUEST
                    )
                
                # Delete old profile picture if it exists
                if user.profile_picture:
                    user.profile_picture.delete(save=False)
                
                # Save new profile picture
                user.profile_picture = profile_picture
                user.save()
                
                # Return success response with updated URLs
                return Response({
                    "success": True,
                    "message": "Profile picture updated successfully",
                    "profile_picture_url": get_media_url(user.profile_picture),
                    "has_profile_picture": True
                })
            else:
                return Response(
                    {"error": "No profile picture provided"},
                    status=status.HTTP_400_BAD_REQUEST
                )

        except Exception as e:
            logger.error(f"Error updating profile picture: {str(e)}")
            return Response(
                {"error": "Failed to update profile picture"},
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )

    def remove_profile_picture(self, request, user):
        """Remove user profile picture"""
        try:
            if user.profile_picture:
                # Delete the file
                user.profile_picture.delete(save=False)
                user.profile_picture = None
                user.save()
                
                return Response({
                    "success": True,
                    "message": "Profile picture removed successfully",
                    "profile_picture_url": None,
                    "has_profile_picture": False
                })
            else:
                return Response({
                    "success": True,
                    "message": "No profile picture to remove",
                    "has_profile_picture": False
                })

        except Exception as e:
            logger.error(f"Error removing profile picture: {str(e)}")
            return Response(
                {"error": "Failed to remove profile picture"},
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )

    def add_payment_method(self, request, user):
        """Add a new payment method for the user"""
        try:
            data = request.data

            # Validate required fields
            required_fields = ['payment_method', 'account_name', 'account_number']
            for field in required_fields:
                if not data.get(field):
                    return Response(
                        {"error": f"{field} is required"},
                        status=status.HTTP_400_BAD_REQUEST
                    )

            # If this is the first payment method, make it default
            is_first = not UserPaymentDetail.objects.filter(user=user).exists()

            # If setting as default, unset any existing default
            if data.get('is_default', False) or is_first:
                UserPaymentDetail.objects.filter(user=user, is_default=True).update(is_default=False)

            # Create payment method
            payment_method = UserPaymentDetail.objects.create(
                user=user,
                payment_method=data.get('payment_method'),
                bank_name=data.get('bank_name', ''),
                account_name=data.get('account_name'),
                account_number=data.get('account_number'),
                is_default=data.get('is_default', False) or is_first
            )

            # Return success response with the new payment method
            return Response({
                "success": True,
                "message": "Payment method added successfully",
                "payment_method": {
                    'payment_id': str(payment_method.payment_id),
                    'payment_method': payment_method.payment_method,
                    'bank_name': payment_method.bank_name,
                    'account_name': payment_method.account_name,
                    'account_number': self.mask_account_number(payment_method.account_number),
                    'is_default': payment_method.is_default,
                    'created_at': payment_method.created_at.isoformat(),
                }
            }, status=status.HTTP_201_CREATED)

        except Exception as e:
            logger.error(f"Error adding payment method: {str(e)}")
            return Response(
                {"error": "Failed to add payment method"},
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )

    def delete_payment_method(self, request, user):
        """Delete a payment method"""
        try:
            payment_id = request.data.get('payment_id')
            if not payment_id:
                return Response(
                    {"error": "payment_id is required"},
                    status=status.HTTP_400_BAD_REQUEST
                )

            try:
                payment_method = UserPaymentDetail.objects.get(
                    payment_id=payment_id, 
                    user=user
                )
            except UserPaymentDetail.DoesNotExist:
                return Response(
                    {"error": "Payment method not found"},
                    status=status.HTTP_404_NOT_FOUND
                )

            was_default = payment_method.is_default
            payment_method.delete()

            # If deleted payment was default, set another as default
            if was_default:
                next_payment = UserPaymentDetail.objects.filter(user=user).first()
                if next_payment:
                    next_payment.is_default = True
                    next_payment.save()

            return Response({
                "success": True,
                "message": "Payment method deleted successfully"
            })

        except Exception as e:
            logger.error(f"Error deleting payment method: {str(e)}")
            return Response(
                {"error": "Failed to delete payment method"},
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )

    def set_default_payment(self, request, user):
        """Set a payment method as default"""
        try:
            payment_id = request.data.get('payment_id')
            if not payment_id:
                return Response(
                    {"error": "payment_id is required"},
                    status=status.HTTP_400_BAD_REQUEST
                )

            try:
                payment_method = UserPaymentDetail.objects.get(
                    payment_id=payment_id, 
                    user=user
                )
            except UserPaymentDetail.DoesNotExist:
                return Response(
                    {"error": "Payment method not found"},
                    status=status.HTTP_404_NOT_FOUND
                )

            # Unset any existing default
            UserPaymentDetail.objects.filter(user=user, is_default=True).update(is_default=False)

            # Set new default
            payment_method.is_default = True
            payment_method.save()

            return Response({
                "success": True,
                "message": "Default payment method updated"
            })

        except Exception as e:
            logger.error(f"Error setting default payment: {str(e)}")
            return Response(
                {"error": "Failed to set default payment method"},
                status=status.HTTP_500_INTERNAL_SERVER_ERROR
            )

    def mask_account_number(self, account_number):
        """Mask account number for security"""
        if not account_number:
            return None
        if len(account_number) <= 4:
            return '*' * len(account_number)
        return '*' * (len(account_number) - 4) + account_number[-4:]


class SellerBoosts(viewsets.ViewSet):
    """ViewSet for seller boost operations"""
    
    def _get_product_total_stock(self, product):
        """Helper method to get total stock from variants"""
        return product.variants.filter(
            is_active=True
        ).aggregate(total=Sum('quantity'))['total'] or 0
    
    def _get_product_min_price(self, product):
        """Helper method to get minimum price from variants"""
        min_price = product.variants.filter(
            is_active=True,
            price__isnull=False
        ).order_by('price').values_list('price', flat=True).first()
        return float(min_price) if min_price else 0
    
    def _get_product_max_price(self, product):
        """Helper method to get maximum price from variants"""
        max_price = product.variants.filter(
            is_active=True,
            price__isnull=False
        ).order_by('-price').values_list('price', flat=True).first()
        return float(max_price) if max_price else 0
    
    def _get_product_primary_image(self, product):
        """Helper method to get primary product image and convert to public URL"""
        try:
            media = product.productmedia_set.first()
            if media and media.file_data:
                s3_url = media.file_data.url
                public_url = convert_s3_to_public_url(s3_url)
                
                request = self.request if hasattr(self, 'request') else None
                if request and public_url and not public_url.startswith('http'):
                    return request.build_absolute_uri(public_url)
                return public_url
        except Exception as e:
            print(f"Error getting product image: {e}")
        return None
    
    @action(detail=False, methods=['get'])
    def plans(self, request):
        """Get all active boost plans with features"""
        try:
            boost_plans = BoostPlan.objects.filter(
                status='active'
            ).order_by('price')
            
            plans_data = []
            for plan in boost_plans:
                plan_features = BoostPlanFeature.objects.filter(
                    boost_plan=plan
                ).select_related('feature')
                
                features_data = []
                plan_limit = 1
                
                for pf in plan_features:
                    features_data.append({
                        'id': str(pf.id),
                        'feature_id': str(pf.feature.id),
                        'feature_name': pf.feature.name,
                        'description': pf.feature.description,
                        'value': pf.value
                    })
                    
                    # Extract product limit from "Product Highlights" feature
                    if 'product' in pf.feature.name.lower() and pf.value:
                        match = re.search(r'\d+', pf.value)
                        if match:
                            plan_limit = int(match.group())
                
                plans_data.append({
                    'id': str(plan.id),
                    'name': plan.name,
                    'price': float(plan.price),
                    'duration': plan.duration,
                    'time_unit': plan.time_unit,
                    'status': plan.status,
                    'features': features_data,
                    'product_limit': plan_limit,
                    'created_at': plan.created_at.isoformat()
                })
            
            return Response({
                'success': True,
                'plans': plans_data,
                'message': 'Boost plans retrieved successfully'
            })
            
        except Exception as e:
            return Response({
                'success': False,
                'plans': [],
                'message': str(e)
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
    
