class WithdrawalRequestViewSet(viewsets.ModelViewSet):
    """
    ViewSet for WithdrawalRequest operations.
    """
    queryset = WithdrawalRequest.objects.all()
    serializer_class = WithdrawalRequestSerializer
    
    def get_queryset(self):
        """Filter queryset based on user from header"""
        user_id = self.request.headers.get('X-User-Id')
        if not user_id:
            return WithdrawalRequest.objects.none()
        
        try:
            user = User.objects.get(id=user_id)
            # Admin can see all, users see only their own
            if user.is_admin:
                return WithdrawalRequest.objects.all()
            return WithdrawalRequest.objects.filter(user=user)
        except User.DoesNotExist:
            return WithdrawalRequest.objects.none()
    
    def get_serializer_class(self):
        """Use different serializers for different actions"""
        if self.action in ['update', 'partial_update', 'approve', 'reject', 'process', 'complete']:
            return WithdrawalRequestUpdateSerializer
        return WithdrawalRequestSerializer
    
    def get_user_from_header(self, request):
        """Helper to get user from header"""
        user_id = request.headers.get('X-User-Id')
        if not user_id:
            return None, Response(
                {'success': False, 'error': 'X-User-Id header is required'}, 
                status=status.HTTP_400_BAD_REQUEST
            )
        
        try:
            user = User.objects.get(id=user_id)
            return user, None
        except User.DoesNotExist:
            return None, Response(
                {'success': False, 'error': 'User not found'}, 
                status=status.HTTP_404_NOT_FOUND
            )
    
    def create(self, request, *args, **kwargs):
        """
        Create a new withdrawal request
        """
        try:
            # Get user from header
            user, error_response = self.get_user_from_header(request)
            if error_response:
                return error_response
            
            # Log for debugging
            print(f"Creating withdrawal request for user: {user.id}")
            
            # Get amount from request
            amount_str = request.data.get('amount')
            
            if not amount_str:
                return Response({
                    'success': False,
                    'error': 'Amount is required'
                }, status=status.HTTP_400_BAD_REQUEST)
            
            # Convert to Decimal
            try:
                amount = Decimal(str(amount_str))
                if amount <= 0:
                    return Response({
                        'success': False,
                        'error': 'Amount must be greater than zero'
                    }, status=status.HTTP_400_BAD_REQUEST)
            except (TypeError, ValueError, Decimal.InvalidOperation):
                return Response({
                    'success': False,
                    'error': 'Invalid amount format'
                }, status=status.HTTP_400_BAD_REQUEST)
            
            # Get or create wallet
            try:
                wallet = UserWallet.objects.get(user=user)
                print(f"Wallet found: {wallet.wallet_id}, available: {wallet.available_balance}")
            except UserWallet.DoesNotExist:
                # Create wallet if it doesn't exist
                wallet = UserWallet.objects.create(user=user)
                print(f"Wallet created: {wallet.wallet_id}")
            
            # Check if user has sufficient available balance
            if wallet.available_balance < amount:
                return Response({
                    'success': False,
                    'error': f'Insufficient available balance. Available: {wallet.available_balance}'
                }, status=status.HTTP_400_BAD_REQUEST)
            
            # Check for existing pending requests
            pending_exists = WithdrawalRequest.objects.filter(
                user=user,
                status__in=['pending', 'processing']
            ).exists()
            
            if pending_exists:
                return Response({
                    'success': False,
                    'error': 'You already have a pending withdrawal request'
                }, status=status.HTTP_400_BAD_REQUEST)
            
            # Create withdrawal request
            with transaction.atomic():
                withdrawal = WithdrawalRequest.objects.create(
                    user=user,
                    wallet=wallet,
                    amount=amount,
                    status='pending'
                )
                
                # Deduct from available, move to pending
                wallet.available_balance -= amount
                wallet.pending_balance += amount
                wallet.save()
                
                logger.info(f"Withdrawal request created: {withdrawal.withdrawal_id} for user {user.id}")
                
                # Create a transaction record for this withdrawal
                WalletTransaction.objects.create(
                    wallet=wallet,
                    user=user,
                    amount=amount,
                    transaction_type='debit',
                    source_type='withdrawal',
                    status='pending'
                )
            
            serializer = self.get_serializer(withdrawal)
            return Response({
                'success': True,
                'message': 'Withdrawal request submitted successfully',
                'withdrawal': serializer.data
            }, status=status.HTTP_201_CREATED)
            
        except Exception as e:
            # Log the full error for debugging
            import traceback
            print(f"Error creating withdrawal request: {str(e)}")
            print(traceback.format_exc())
            logger.error(f"Error creating withdrawal request: {str(e)}", exc_info=True)
            
            return Response({
                'success': False,
                'error': f'Server error: {str(e)}'
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
    
    @action(detail=False, methods=['get'])
    def my_requests(self, request):
        """
        Get withdrawal requests for the current user
        """
        try:
            user, error_response = self.get_user_from_header(request)
            if error_response:
                return error_response
            
            # Filter by status if provided
            status_filter = request.GET.get('status')
            
            queryset = WithdrawalRequest.objects.filter(user=user)
            
            if status_filter:
                queryset = queryset.filter(status=status_filter)
            
            # Order by requested date (newest first)
            queryset = queryset.order_by('-requested_at')
            
            # Pagination
            page = int(request.GET.get('page', 1))
            page_size = int(request.GET.get('page_size', 10))
            start = (page - 1) * page_size
            end = start + page_size
            
            withdrawals = queryset[start:end]
            total = queryset.count()
            
            serializer = self.get_serializer(withdrawals, many=True)
            
            # Calculate statistics for user
            total_withdrawn = queryset.filter(
                status='completed'
            ).aggregate(total=Sum('amount'))['total'] or 0
            
            pending_amount = queryset.filter(
                status__in=['pending', 'processing', 'approved']
            ).aggregate(total=Sum('amount'))['total'] or 0
            
            return Response({
                'success': True,
                'withdrawal_requests': serializer.data,
                'statistics': {
                    'total_requests': total,
                    'total_withdrawn': float(total_withdrawn),
                    'pending_amount': float(pending_amount),
                    'page': page,
                    'page_size': page_size,
                    'pages': (total + page_size - 1) // page_size
                }
            })
            
        except Exception as e:
            print(f"Error in my_requests: {str(e)}")
            import traceback
            traceback.print_exc()
            return Response({
                'success': False,
                'error': str(e)
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)
    
    @action(detail=True, methods=['post'])
    def cancel(self, request, pk=None):
        """
        Cancel a pending withdrawal request
        """
        try:
            user, error_response = self.get_user_from_header(request)
            if error_response:
                return error_response
            
            withdrawal = self.get_object()
            
            # Ensure user owns this withdrawal
            if withdrawal.user.id != user.id:
                return Response({
                    'success': False,
                    'error': 'You can only cancel your own withdrawal requests'
                }, status=status.HTTP_403_FORBIDDEN)
            
            # Can only cancel pending requests
            if withdrawal.status != 'pending':
                return Response({
                    'success': False,
                    'error': f'Cannot cancel withdrawal with status: {withdrawal.status}'
                }, status=status.HTTP_400_BAD_REQUEST)
            
            withdrawal.status = 'cancelled'
            withdrawal.save()
            
            logger.info(f"Withdrawal cancelled: {withdrawal.withdrawal_id} by user {user.id}")
            
            serializer = self.get_serializer(withdrawal)
            return Response({
                'success': True,
                'message': 'Withdrawal request cancelled',
                'withdrawal': serializer.data
            })
            
        except Exception as e:
            print(f"Error cancelling withdrawal: {str(e)}")
            return Response({
                'success': False,
                'error': str(e)
            }, status=status.HTTP_500_INTERNAL_SERVER_ERROR)



class WithdrawalRequestSerializer(serializers.ModelSerializer):
    user = serializers.SerializerMethodField()
    wallet = serializers.SerializerMethodField()
    approved_by = serializers.SerializerMethodField()

    class Meta:
        model = WithdrawalRequest
        fields = [
            "withdrawal_id",
            "user",
            "wallet",
            "amount",
            "status",
            "requested_at",
            "approved_by",
            "approved_at",
            "completed_at",
            "admin_proof",
        ]

    def get_user(self, obj):
        if obj.user:
            return {
                "id": obj.user.id,
                "username": getattr(obj.user, "username", None),
                "email": getattr(obj.user, "email", None),
            }
        return None

    def get_wallet(self, obj):
        if obj.wallet:
            return {
                "id": str(obj.wallet.wallet_id),  # Use wallet_id instead of id
                "balance": float(obj.wallet.available_balance) if obj.wallet.available_balance else 0,  # Use available_balance instead of balance
            }
        return None


    def get_approved_by(self, obj):
        if obj.approved_by:
            return {
                "id": obj.approved_by.id,
                "username": getattr(obj.approved_by, "username", None),
            }
        return None

    def to_representation(self, instance):
        data = super().to_representation(instance)
        data["id"] = str(instance.withdrawal_id)  # Add id for frontend
        # Convert amount to string to match frontend interface
        data["amount"] = str(instance.amount)
        return data

class AdminWithdrawalViewSet(viewsets.ViewSet):
    
    def _convert_to_public_url(self, file_url):
        """Helper method to convert S3 URL to public URL"""
        if not file_url:
            return None
        try:
            return convert_s3_to_public_url(file_url)
        except Exception:
            return file_url
    
    def list(self, request):
        try:
            withdrawals = WithdrawalRequest.objects.select_related(
                "user",
                "wallet",
                "approved_by"
            ).all().order_by("-requested_at")

            # filters
            status_filter = request.GET.get("status")
            search = request.GET.get("search")

            if status_filter:
                withdrawals = withdrawals.filter(status=status_filter)

            if search:
                withdrawals = withdrawals.filter(
                    Q(user__username__icontains=search) |
                    Q(user__email__icontains=search)
                )

            # Calculate statistics
            total_count = withdrawals.count()
            
            # Calculate metrics for the frontend
            metrics = {
                'total_pending': withdrawals.filter(status='pending').count(),
                'total_processing': withdrawals.filter(status='processing').count(),
                'total_approved': withdrawals.filter(status='approved').count(),
                'total_completed': withdrawals.filter(status='completed').count(),
                'total_rejected': withdrawals.filter(status='rejected').count(),
                'total_amount_pending': float(withdrawals.filter(status='pending').aggregate(total=Sum('amount'))['total'] or 0),
                'total_amount_processing': float(withdrawals.filter(status='processing').aggregate(total=Sum('amount'))['total'] or 0),
                'total_amount_approved': float(withdrawals.filter(status='approved').aggregate(total=Sum('amount'))['total'] or 0),
                'total_amount_completed': float(withdrawals.filter(status='completed').aggregate(total=Sum('amount'))['total'] or 0),
                'total_amount_rejected': float(withdrawals.filter(status='rejected').aggregate(total=Sum('amount'))['total'] or 0),
            }

            serializer = WithdrawalRequestSerializer(withdrawals, many=True)
            
            # Convert admin_proof URLs in the response
            serialized_data = serializer.data
            for item in serialized_data:
                if item.get('admin_proof'):
                    item['admin_proof'] = self._convert_to_public_url(item['admin_proof'])

            return Response({
                "success": True,
                "data": serialized_data,
                "stats": metrics,
                "total_count": total_count
            })

        except Exception as e:
            import traceback
            print(f"Error in list: {str(e)}")
            print(traceback.format_exc())
            return Response({
                "success": False,
                "error": str(e)
            }, status=500)

    def retrieve(self, request, pk=None):
        """
        Get a single withdrawal by ID (using withdrawal_id as primary key)
        """
        try:
            # Use withdrawal_id instead of id since that's the primary key
            withdrawal = WithdrawalRequest.objects.select_related(
                "user",
                "wallet",
                "approved_by"
            ).get(withdrawal_id=pk)

            # Get user wallet balance - UserWallet uses wallet_id, not id
            wallet_balance = withdrawal.wallet.available_balance if withdrawal.wallet else 0
            pending_balance = withdrawal.wallet.pending_balance if withdrawal.wallet else 0

            # Get user address
            user_address = None
            if withdrawal.user.street or withdrawal.user.barangay or withdrawal.user.city:
                address_parts = []
                if withdrawal.user.street:
                    address_parts.append(withdrawal.user.street)
                if withdrawal.user.barangay:
                    address_parts.append(withdrawal.user.barangay)
                if withdrawal.user.city:
                    address_parts.append(withdrawal.user.city)
                if withdrawal.user.province:
                    address_parts.append(withdrawal.user.province)
                user_address = ", ".join(address_parts)

            # Convert admin_proof URL to public URL
            admin_proof_url = None
            if withdrawal.admin_proof:
                admin_proof_url = self._convert_to_public_url(withdrawal.admin_proof.url)

            # Build withdrawal data
            withdrawal_data = {
                "id": str(withdrawal.withdrawal_id),
                "withdrawal_id": withdrawal.withdrawal_id,
                "amount": float(withdrawal.amount),
                "status": withdrawal.status,
                "requested_at": withdrawal.requested_at.isoformat(),
                "approved_at": withdrawal.approved_at.isoformat() if withdrawal.approved_at else None,
                "completed_at": withdrawal.completed_at.isoformat() if withdrawal.completed_at else None,
                "admin_proof": admin_proof_url,
                
                # User info
                "user": {
                    "id": withdrawal.user.id,
                    "username": withdrawal.user.username,
                    "email": withdrawal.user.email,
                    "first_name": withdrawal.user.first_name,
                    "last_name": withdrawal.user.last_name,
                    "phone": withdrawal.user.contact_number,
                    "address": user_address
                },
                
                # Wallet info - Use wallet_id instead of id
                "wallet": {
                    "id": str(withdrawal.wallet.wallet_id) if withdrawal.wallet else None,
                    "wallet_id": withdrawal.wallet.wallet_id if withdrawal.wallet else None,
                    "balance": float(wallet_balance),
                    "available_balance": float(wallet_balance),
                    "pending_balance": float(pending_balance)
                },
                
                # Approved by info
                "approved_by": {
                    "id": withdrawal.approved_by.id,
                    "username": withdrawal.approved_by.username,
                    "email": withdrawal.approved_by.email
                } if withdrawal.approved_by else None
            }

            return Response({
                "success": True,
                "withdrawal": withdrawal_data,
                "data": withdrawal_data  # For compatibility with frontend
            })

        except WithdrawalRequest.DoesNotExist:
            return Response({
                "success": False,
                "error": "Withdrawal not found"
            }, status=404)
        except Exception as e:
            import traceback
            print(f"Error in retrieve: {str(e)}")
            print(traceback.format_exc())
            return Response({
                "success": False,
                "error": str(e)
            }, status=500)

    @action(detail=True, methods=['post'])
    def approve(self, request, pk=None):
        """
        Approve a withdrawal request
        """
        try:
            withdrawal = WithdrawalRequest.objects.get(withdrawal_id=pk)
            
            if withdrawal.status != 'pending':
                return Response({
                    "success": False,
                    "error": f"Cannot approve withdrawal with status '{withdrawal.status}'"
                }, status=400)
            
            # Get admin user ID from header
            admin_user_id = request.headers.get('X-User-Id')
            admin_user = None
            if admin_user_id:
                try:
                    admin_user = User.objects.get(id=admin_user_id)
                except User.DoesNotExist:
                    pass
            
            withdrawal.status = 'approved'
            withdrawal.approved_at = timezone.now()
            withdrawal.approved_by = admin_user
            withdrawal.save()
            
            return Response({
                "success": True,
                "message": "Withdrawal approved successfully",
                "withdrawal": {
                    "id": str(withdrawal.withdrawal_id),
                    "status": withdrawal.status,
                    "approved_at": withdrawal.approved_at.isoformat()
                }
            })
            
        except WithdrawalRequest.DoesNotExist:
            return Response({
                "success": False,
                "error": "Withdrawal not found"
            }, status=404)
        except Exception as e:
            return Response({
                "success": False,
                "error": str(e)
            }, status=500)

    @action(detail=True, methods=['post'])
    def reject(self, request, pk=None):
        """
        Reject a withdrawal request
        """
        try:
            withdrawal = WithdrawalRequest.objects.get(withdrawal_id=pk)
            
            if withdrawal.status != 'pending':
                return Response({
                    "success": False,
                    "error": f"Cannot reject withdrawal with status '{withdrawal.status}'"
                }, status=400)
            
            reason = request.data.get('reason')
            if not reason:
                return Response({
                    "success": False,
                    "error": "Rejection reason is required"
                }, status=400)
            
            with transaction.atomic():
                withdrawal.status = 'rejected'
                withdrawal.save()
                
                # Refund available balance and deduct from pending balance
                if withdrawal.wallet:
                    withdrawal.wallet.available_balance += withdrawal.amount
                    withdrawal.wallet.pending_balance -= withdrawal.amount
                    withdrawal.wallet.save()
                
                # Update corresponding WalletTransaction
                wallet_tx = WalletTransaction.objects.filter(
                    user=withdrawal.user,
                    amount=withdrawal.amount,
                    transaction_type='debit',
                    source_type='withdrawal',
                    status='pending'
                ).first()
                
                if wallet_tx:
                    wallet_tx.status = 'rejected'
                    wallet_tx.save()
            
            return Response({
                "success": True,
                "message": "Withdrawal rejected successfully",
                "withdrawal": {
                    "id": str(withdrawal.withdrawal_id),
                    "status": withdrawal.status
                }
            })
            
        except WithdrawalRequest.DoesNotExist:
            return Response({
                "success": False,
                "error": "Withdrawal not found"
            }, status=404)
        except Exception as e:
            return Response({
                "success": False,
                "error": str(e)
            }, status=500)

    @action(detail=True, methods=['post'])
    def process(self, request, pk=None):
        """
        Mark withdrawal as processing
        """
        try:
            withdrawal = WithdrawalRequest.objects.get(withdrawal_id=pk)
            
            if withdrawal.status != 'approved':
                return Response({
                    "success": False,
                    "error": f"Cannot process withdrawal with status '{withdrawal.status}'. Status must be 'approved'."
                }, status=400)
            
            withdrawal.status = 'processing'
            withdrawal.save()
            
            return Response({
                "success": True,
                "message": "Withdrawal marked as processing",
                "withdrawal": {
                    "id": str(withdrawal.withdrawal_id),
                    "status": withdrawal.status
                }
            })
            
        except WithdrawalRequest.DoesNotExist:
            return Response({
                "success": False,
                "error": "Withdrawal not found"
            }, status=404)
        except Exception as e:
            return Response({
                "success": False,
                "error": str(e)
            }, status=500)

    @action(detail=True, methods=['post'])
    def complete(self, request, pk=None):
        """
        Complete a withdrawal with proof of payment
        """
        try:
            withdrawal = WithdrawalRequest.objects.get(withdrawal_id=pk)
            
            if withdrawal.status != 'processing':
                return Response({
                    "success": False,
                    "error": f"Cannot complete withdrawal with status '{withdrawal.status}'. Status must be 'processing'."
                }, status=400)
            
            admin_proof = request.FILES.get('admin_proof')
            if not admin_proof:
                return Response({
                    "success": False,
                    "error": "Proof of payment is required"
                }, status=400)
            
            with transaction.atomic():
                withdrawal.status = 'completed'
                withdrawal.completed_at = timezone.now()
                withdrawal.admin_proof = admin_proof
                withdrawal.save()
                
                # Deduct from pending balance (was added during request)
                if withdrawal.wallet:
                    withdrawal.wallet.pending_balance -= withdrawal.amount
                    withdrawal.wallet.save()
                    
                # Update corresponding WalletTransaction to completed
                # Look for processing or pending transaction
                wallet_tx = WalletTransaction.objects.filter(
                    user=withdrawal.user,
                    amount=withdrawal.amount,
                    transaction_type='debit',
                    source_type='withdrawal',
                    status__in=['pending', 'processing']
                ).first()
                
                if wallet_tx:
                    wallet_tx.status = 'completed'
                    wallet_tx.save()
            
            # Convert the saved admin_proof URL to public URL
            admin_proof_url = None
            if withdrawal.admin_proof:
                admin_proof_url = self._convert_to_public_url(withdrawal.admin_proof.url)
            
            return Response({
                "success": True,
                "message": "Withdrawal completed successfully",
                "withdrawal": {
                    "id": str(withdrawal.withdrawal_id),
                    "status": withdrawal.status,
                    "completed_at": withdrawal.completed_at.isoformat(),
                    "admin_proof": admin_proof_url
                }
            })
            
        except WithdrawalRequest.DoesNotExist:
            return Response({
                "success": False,
                "error": "Withdrawal not found"
            }, status=404)
        except Exception as e:
            return Response({
                "success": False,
                "error": str(e)
            }, status=500)

